const dexDescMap = {
  "G네 드래곤": "다리가 많은 다족룡의 한 부류. 땅속에서 주로 거주한다. 스타일에 민감한 드래곤답게 자신의 화려함을 자랑으로 여긴다. [ 획득가능: 나무 던전 ]",
  "i곤": "I곤은 메탈 마그넷과 같은 메카닉 드래곤 종류에 속한다. 멋진 생김새로 많은 드래곤 테이머들의 인기를 얻지만 물기에 매우 약하기 때문에 보다 세심한 관리가 필요하다.",
  "가디언": "어느 왕국의 왕실의 상징으로 사람을 잘 따르며 보호 본능이 뛰어나다. 오른손에 생기는 문양은 힘을 더욱 강력하게 만든다.",
  "가루다": "수많은 역사에 기록된 전설의 화마. 무지막지한 전투력과 상상을 초월하는 난폭함을 지닌 드래곤.거대한 덩치와 칼날과 같이 솟아난 여러 개의 뿔을 지닌 것이 특징이며 적이 강하면 강할수록 온몸에 불꽃이 타올라 자신의 힘을 증가시킨다.",
  "가스트": "기묘하고 매혹적인 색의 드래곤. 화가 나면 이것저것 들이받는 난폭한 성격. 튼튼한 두 다리로 여기저기 휘젓고 다니길 좋아한다.",
  "가이안": "고귀한 영혼이 머무는 땅 프뉴마. 가이안은 수많은 음유시인의 노래에 존재한 환상의 세계 프뉴마의 파수꾼이다. 이 신비의 땅의 파수꾼은 거대한 덩치와 막강한 힘을 지니고 있다. 하지만 그저 환상의 존재라고 여길 뿐 실제로 이 파수꾼을 본 자는 그 누구도 존재하지 않는다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "각진 에닉스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 에닉스는 여섯 수호자 중 땅을 상징한다. 숲과 대지를 다루는 능력으로 레오나를 노리는 악에 맞서 싸웠다고 전해진다. [ 획득가능: 에스텔라 ]",
  "간다르바": "몹쓸 장난꾸러기로 악명이 자자한 드래곤. 간혹 카데스의 첩자가 아닌가 하는 의심이 들 정도로 심한 장난을 친다. 하지만 태초의 전쟁때 있었던 활약으로 그 의심은 순식간에 사그라들었다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "강강": "사자탈 드래곤. 차차웅을 따라 악한 기운을 끝까지 쫓아가 없애는 충성스러운 드래곤. 마댓자루같이 복슬복슬한 외형과는 다르게 움직임은 굉장히 빠르고 부드러워 마치 춤을 추는 것 같다. 실제로도 목과 꼬리의 방울 소리를 따라 춤추는 걸 좋아하는 흥겨운 성격이다.",
  "강림 강화곤": "다른 드래곤들에게 힘을 실어 주는 드래곤. 초월 단계와 동일한 힘으로 다른 드래곤의 강림 진화를 도와준다.",
  "개틀링곤": "고대의 현자가 만들어낸 마공학 병기. 기계와 드래곤의 융합을 통해 강력한 방어력을 보유하게 되었으며 장착한 무장으로 사정거리 내의 목표물을 초토화시킬 수 있다.",
  "갤러스": "사람이 발길이 닿지 않는 조용한 호수에 서식하는 드래곤. 성격이 선하고 아름다워 타인에게 피해를 주는 것을 끔찍이 싫어한다. 마음을 열고 친해지면 자주 장난을 치기도 한다.",
  "갤럭시": "먼 은하에서부터 찾아온 우주 드래곤. 은하를 뜻하는 별의 장식이 이마에 장식되어 있으며 곡선으로 수놓아진 아름다운 몸매를 자랑한다. 호기심이 많고 귀염성이 있어 최근 많은 드래곤 테이머들에게 인기가 많다.",
  "갤럭시아 드래곤": "아름다운 날개를 가진 드래곤. 밤하늘을 날아가면 마치 은하수를 보는 것만 같다. 화가 나면 뿔과 이마 부분이 붉게 타오른다",
  "거들테일 드래곤": "바위 지대에 무리 지어 생활하는 도마뱀 드래곤이다. 도마뱀 왕국 멸망 이후, 새로운 도마뱀 왕국을 탄생시키기 위해 움직이는 드래곤이다. 과거, 도마뱀 왕국 드래곤 중 뛰어난 방어막으로 활약하며 수많은 전쟁을 승리로 이끌었다.",
  "거스트 드래곤": "거친 돌풍을 몰고 다니는 드래곤. 돌풍이 이는 곳에 모습을 나타내는건지, 나타나면서 거친 돌풍을 몰아일으키는 건지는 확실하지 않다. 샤프테일 드래곤을 '굉장히' 싫어한다.",
  "게스드래곤": "수정 날개를 지닌 신비의 드래곤. 신의 광물이라 불리는 디바인 스톤과 생김새가 유사하지만, 그 능력은 다르다. 가끔 털갈이를 할 때 귀한 수정을 얻을 수 있다. [ 획득가능: 미스터리 뽑기 ]",
  "견고한 에닉스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 에닉스는 여섯 수호자 중 땅을 상징한다. 숲과 대지를 다루는 능력으로 레오나를 노리는 악에 맞서 싸웠다고 전해진다. [ 획득가능: 에스텔라 ]",
  "고귀한 갤러헤드": "단단한 피부를 지닌 갤러헤드는 강력한 투구를 이용해 상대를 제압한다. 여러 개의 팔과 다리로 어디에든 붙어있거나 여러 가지 일들을 동시에 해낼 수 있다.",
  "고귀한 넬로 드래곤": "심해에 사는 보랏빛 드래곤. 사슴의 뿔과 여우의 꼬리를 가지고 있어 한때 육지에 살았을거란 추측이 있다. 심해에는 대화할 상대가 없다보니 자연스럽게 과묵한 성격이 되었다. [ 이벤트 랭킹1위 일일보상 ]",
  "고귀한 다크베인": "유타칸 침공의 선봉장으로 검은 날개와 붉은 눈을 가진 무시무시한 드래곤. 성격은 매우 잔인하고 포악하며 아르하에서도 그 악명이 자자했다. [9주년 이벤트 랭킹1위 일일보상 ]",
  "고귀한 다크혼": "부의 영광을 기원하는 골든혼과 다르게 다크혼은 악명으로 소문이 자자한 존재이다. 섬뜩한 안광을 바라본 자는 반드시 불행한 일을 겪는다는 괴담.어쩌면 이러한 괴담이 생긴 원인은 워낙 무시무시한 생김새를 지닌 다크혼의 외모 탓이 아닐까?",
  "고귀한 디아누": "차원문을 열 수 있는 문지기 드래곤. 빛과 어둠의 전쟁 당시 포르타, 페로스와 함께 차원문을 열고 닫으며 수많은 드래곤들을 지켜냈다. 디아누는 차원의 사슬로 닫힌 차원문은 강력한 힘이어도 열 수 없으며, 오직 차원의 열쇠로만 열 수 있다.",
  "고귀한 레버넌트": "생김새 만큼이나 사악하고 악독한 드래곤. 헬카이저의 명령이면 무엇이든지 따른다. 카데스와 헬카이저에게 저항하는 이들을 무자비하게 살육했다.",
  "고귀한 루네라 드래곤": "보름달의 어둠에서 태어난 드래곤. 여신에게 선택받지 못했다는 이유로 아르테미스 드래곤을 극도로 미워한다. 하지만 그 빼어난 아름다움은 아르테미스 드래곤에게 뒤지지 않는다.",
  "고귀한 말덱": "둘로 나뉜 순환의 서 중, 흡수의 서를 갖고 있는 악동 드래곤. 호기심이 많아 눈에 보이는 생명들을 책 안에 가두려고 한다. 덕분에 누나인 스트라가 골치를 앓는 편.",
  "고귀한 블러디터스크": "온 몸이 피로 물든 것처럼 붉은 드래곤. 날카로운 송곳니에 물린 적은 온 몸의 피를 흡수당한다고 한다. [이벤트 랭킹1위 일일보상]",
  "고귀한 설리반": "용의 보옥에서 태어나, 아름다운 깃털로 적을 현혹하는 드래곤. 자신 외의 모든 것이 아름답지 않다 생각하며 항상 눈을 감고 다닌다. 소문에 의하면, '현명함의 사도’를 만날 때만 눈을 뜬다고 한다.",
  "고귀한 스트라": "둘로 나뉜 순환의 서 중, 방출의 서를 갖고 있는 드래곤. 동생이 가둔 생명들을 불쌍히 여겨 풀어주려한다. 문제는, 자기 마음대로 내보내는 것이 동생보다 더한 악동이라는 평이 있다.",
  "고귀한 아누라다": "마카라에 충성을 바치는 이 사악한 드래곤들은 여러 행성을 파괴하며 엘베스타 성계전역에 악명을 떨쳤다.",
  "고귀한 아델라": "디트가 새로운 마공학 회로를 도입해 만든 병기. 안타깝게도 메모리가 부족해 언어 회로는 집어넣지 못했다고 한다. 비록 말은 못하지만 정의감만큼은 누구에게도 뒤지지 않는다. [ 2021 크리스마스 이벤트 랭킹1위 통합보상 ]",
  "고귀한 앙그라": "먼 과거에 존재하던 고대 드래곤들의 왕. 카데스와 맞서싸운 용감무쌍한 왕이었으나 그 오만한 성격으로 인해 신의 미움을 사 봉인당하고 만다. 빛과 어둠의 전쟁으로 봉인이 약해져 최근 눈을 뜨게 된다.",
  "고귀한 엔더 드래곤": "카데스의 여섯 날개 중 하나로 파멸의 힘을 부여받은 신의 화신. 지금까지 그 누구도 정체를 모르고 있던 드래곤으로 이유는 아주 간단하다. 그와 마주한 모든 이들의 운명은 파멸밖에 없었을 뿐이다. [2021 빛의 축제 이벤트 랭킹1위 일일보상 ]",
  "고귀한 이블던": "진지하고 진중한 성격의 드래곤. 헬카이저의 교활한 계략에 신중함을 더하는 참모 역할을 맡고 있다. 말수도 없고 표정도 읽기 어렵지만, 그 속내에 감추고 있는 잔인함은 헬카이저 못지 않게 끔찍하다.",
  "고귀한 이지스": "신의 방패라 불리는 드래곤, 단단한 피부의 갑주는 성스러운 빛을 발산하며 사악한 공격을 방어하며 그 공격은 그대로 날개에 흡수되어 에너지가 된다. [2021 한가위 이벤트 랭킹1위 일일보상 ]",
  "고귀한 익시아": "여명을 부르는 고요한 바람에 머무는 환상의 드래곤. 온몸을 수놓은 보랏빛의 무늬는 익시아의 감정에 따라 연해지거나 진해진다.",
  "고귀한 카이저번": "죽은 이의 영혼을 관장하던 유타칸의 고대 드래곤. 하지만 카데스에 의해 타락하여 원래 모습을 잃어버린 지금은 그저 산 자의 영혼을 갈구하는 괴물일 뿐이다.",
  "고귀한 페로스": "차원문을 열 수 있는 문지기 드래곤. 빛과 어둠의 전쟁 당시 포르타, 디아누와 함께 차원문을 열고 닫으며 수많은 드래곤들을 지켜냈다. 페로스는 차원문의 열쇠로 페로스의 차원의 열쇠는 차원을 넘어 마음먹은 곳으로 이동할 수 있다.",
  "고귀한 펜리르": "날카로운 발톱과 이마의 뿔로 자기 마음에 들지 않는 것들을 부숴버리는 포악한 드래곤. 처음에는 착하고 부드러운 성격이었지만 무엇인가를 계기로 모든 것을 적대하게 되었고 누군가와의 전투에서 강탈한 망치를 자유자재로 다루게 되면서 한층 더 강력해졌다.",
  "고귀한 허리케인": "돌풍을 먹고 사는 드래곤. 머문 자리에 돌풍으로 인한 피해가 생겨 악귀로 여겨지지만, 실제로는 돌풍을 먹어 없애는 착한 드래곤이다.",
  "고귀한 헤네스": "그림자 여신을 받드는 사도 중 현명함을 추구하는 드래곤. 행운과 지혜를 모두 갖춘 자만이 그녀를 만날 수 있다. 지성과 기민함이 함께하는 그대에게 빛이 있으라.",
  "고귀한 헬카이저": "카데스의 명령으로 아르하를 지배중인 드래곤. 뛰어난 지능을 바탕으로 교활하고 잔인한 전략을 구사한다. 그와 동시에 아르하의 모든 수호룡을 쓰러뜨릴 정도의 강력한 힘을 가진 무시무시한 존재. [이벤트 랭킹1위 보상 ]",
  "고대 주니어": "고대신룡과 엔젤사이에서 태어난 아들이다. 고대신룡처럼 정의롭지만 나이가 어려서 철이 없고 암컷드래곤들을 매우 좋아 한다.",
  "고대신룡": "용의 신전에 사는 용. 신의 힘을 가지고 있는 용이라고 전해진다. 주로 하늘과 닿아있는 곳, 밝은 곳에서 주로 볼 수 있다. 사람들에게는 신의 대행자라고 주로 알려져있다. [ 획득가능: 하늘의 신전 ]",
  "고요한 라이오스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 라이오스는 여섯 수호자 중 바람을 상징한다. 폭풍과 같은 능력으로 최선을 다해 여신 레오나를 지킨 수호 드래곤이다. [ 획득가능: 에스텔라 ]",
  "고트": "뿔과 눈의 동공이 염소와 닮은 드래곤이다. 어두운 털색과 염소의 이미지 때문에 악마의 드래곤으로 오해받기도 하는데 정작 성격은 온순하고 힘을 남용하지 않는 정의로운 드래곤이다. 나무에 뿔을 다듬는 고트의 모습을 보면 행운이 따라온다고 전해진다.",
  "골드 드래곤": "피부와 뼈가 모두 금으로 된 드래곤. 빛의 광산 깊은 곳에서 서식한다. 수 많은 탐험가들이 찾으려 하지만 아직까지 전설로만 전해온다. [ 획득가능: 하늘의 신전 ]",
  "골든혼": "같은 종족중에서도 수십년에 한번씩 태어나는 황금으로 된 뿔과 날개를 가진 드래곤이다. 그 뿔과 날개는 종족 중에서도 우월함을 상징하며 강한 힘의 원천이 되기도 한다.",
  "골디": "아주 깊은 지하에서 생활하는 금 드래곤이다. 골디의 손이 닿을 때마다 벨벳 자루에서는 끝없는 골드가 생성된다.",
  "골락": "온 몸이 바위로 이루어진 암석 드래곤. 드래곤으로서의 특징은 많이 잃었지만 바위 드래곤과의 유사성이 많아 연구가 진행되고 있다. 다만 성질이 너무 사나워 접근이 쉽지가 않다. [ 획득가능: 아르하의 입구 ]",
  "광명의 바리안": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 바리안은 여섯 수호자 중 빛을 상징한다. 광명의 빛으로 최선을 다해 여신 레오나를 지킨 수호드래곤이며, 여섯 수호자의 우두머리이다. [ 획득가능: 에스텔라 ]",
  "구미호": "사람의 간을 먹는다는 무시무시한 괴물이 드래곤의 간을 먹어 드래곤으로 다시 태어났다고 한다. 드래곤이 되어서도 간에 대한 집착은 변하지 않으니 주의할 것.",
  "궁니르": "심판의 꼬리로 모든 악을 심판하는 드래곤. 빛의 자손들을 지키고 수호하기 위해 태어났다. 하지만 약간 건방진 성격탓에 다른 드래곤의 속을 썩이기도 한다. 적에게는 어떠한 빈틈도 보여주지 않는 철벽같은 공격을 하는 드래곤이다.",
  "그늘진 발로드": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 발로드는 여섯 수호자 중 어둠을 상징한다. 강력한 어둠의 힘을 조종했으며, 누구보다 레오나를 위했던 드래곤이었다고 전해진다. [ 획득가능: 에스텔라 ]",
  "그라노스": "태초의 마귀 크로낙을 하얀 매와 함께 물리친 신성 드래곤이다. 고대 마귀 크로낙이 사악한 힘으로 세상을 어지럽게 하던 시절, 그라노스는 밝은 빛을 몰고 와 나타나선 매와 함께 신성한 공격을 가했다. 그라노스는 어둠의세력을 물러가게한 신성한 드래곤으로 여겨진다.",
  "그라치아": "태초에 존재했던 신비의 성, 파라디수스를 지키던 최후의 수호 드래곤. 물의 힘을 조종하며 수압의 차이를 이용해 적을 물리치는 전법을 구사한다. [ 획득가능: 미스터리 뽑기 ]",
  "그랑 세이버": "아그나드보다 더욱 발전된 마공학으로 제작한 드래곤 병기. 비록 만들어진 영혼이지만 생명의 소중함과 평화의 가치를 아는 정의의 사도이다. 아그나드와 함께 모든 악을 물리치기로 맹세한다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "그레이탄": "안개가 짙은 날에만 나타나는 신비한 존재. 거대한 크기와 무서운 얼굴에도 불구하고 생명을 보호하고 위해주는 선한 드래곤이다. 물론 가끔 근처 마을로 내려와 먹을 것을 훔치는 장난을 치기도 한다.",
  "그리파르": "악한 마음을 소멸시키는 불꽃을 만들어낸다. 혼돈의 틈새를 떠돌다가 신비로운 불꽃을 만났다. 불꽃이 다크닉스로 인한 어두운 미래를 보여준 이후, 세계를 지켜야겠다는 마음을 가지며 혼돈의 틈새의 수문장이 되었다.",
  "그리핀": "허공을 가르는 맹수라 불리는 드래곤. 천둥과 같은 울음소리와 대지를 불태우는 강렬한 불꽃이 특징적이다.",
  "그림자 발로드": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 발로드는 여섯 수호자 중 어둠을 상징한다. 강력한 어둠의 힘을 조종했으며, 누구보다 레오나를 위했던 드래곤이었다고 전해진다. [ 획득가능: 에스텔라 ]",
  "글라오네": "고대의 현자가 만들어낸 궁극의 병기 드래곤이다. 세 드래곤의 힘이 합쳐져 비로소 궁극의 힘을 발휘한다. 드디어 세 드래곤이 완벽하게 하나가 된 순간이 찾아온다. 행성으로부터 진격하는 위험을 수호하는 힘을 손에 쥐었다. 행성과 우주를 수호하는 전설적인 존재로 거듭나, 공중을 가르고, 번개와 화염으로 적을 불태우며, 대지를 뒤흔든다.",
  "글래시어": "태초에 물의 수호자 빙하고룡을 따른 빙결형 드래곤.빙하고룡이 다크닉스를 막기 위해 자리를 비운 사이 사악한 마물들에 맞서 무고한 생명들을 지키기 위해 최선을 다했으며 무시무시한 빙결의 힘을 지니고 있다.",
  "금오드래곤": "삼족오라는 까마귀와 비슷해서 지어진 이름이다. 날개가 3개, 눈이 3개이다. 세 번째 눈은 어릴 때 감겨 있는데 성장하면서 세 번째 눈을 뜨면 엄청난 말썽꾸러기가 된다.",
  "기간티스": "공간의 신 구드라의 수호 드래곤. 과거 악신 카데스를 따르는 다섯 개의 재앙을 불러오는 디콘과 싸웠으며 구드라의 우측을 수호했다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "기린": "사신 드래곤과 함께 사방에 질서를 가져온다. 사방신 드래곤들과 밀접하게 연결되어 있다. 동, 서, 남, 북의 균형을 맞추는 역할을 맡고 있다. 균형이 흐트러질 때면, 구름을 타고 온몸에서 빛을 내뿜으며 나타난다.",
  "까마귀 드래곤": "무리들을 보호하기 위해 몸과 마음을 바친다. 검은 깃털론느 적을 혼란스럽게 만들며, 한 번의 강력한 날갯짓으로는 강한 바람을 일으켜 적을 밀어내거나 무리를 숨긴다. 무리를 안전한 곳으로 이끌기 위해 빠르고 날렵하게 비행한다. 무리를 위협하는 적에게는 강력한 눈빛과 날카로운 울음소리로 경고를 보낸다. 무리들이 정성을 다해 만들어준 장신구를 소중히 간직하며, 늘 몸에 지니고 있다. 몸에 아무리 상처나 흉터가 남아도 결코 싸움에서 등을 돌리는 법이 없다.",
  "까치 드래곤": "무리 지어 맛있는 음식이나 반짝이는 물건을 훔쳐 달아난다. 한 해가 시작되면 하늘을 가득 채울 정도로 마을을향해 무리 지어 오는 습성이 있다. 그렇게 마을 주민들을 겁에 질리게 한 뒤, 마을에 착지하여거대한 입으로 마을의 작물과 과일을 순식간에 빼앗곤 날개로 빠르게 도망친다. 까치 드래곤들이 지나간 마을엔 항상 검은 날개가 남는다 알려진다. 또한 빛나는 병뚜ㄱ껑이나 깡통에 잘 이끌리기도 한다. 그것들을 조심스레 부리로 두드린 뒤 왕관으로 만들고, 과일과 작물을 가져다가 자신의 무리를 지켜주는 강한 존재에게 선물한다.",
  "깨비곤": "먼 동방이라는 대륙의 퇴마술사가 식신으로 길러낸 드래곤. 사악한 요괴와 마물을 퇴치하고자 만든 퇴마의 드래곤인 만큼 눈에서 나오는 요술빔은 사악하고 해로운 잡귀와 마물들에 대해 강한 공격 능력을 지녔다고 전해진다.",
  "꽁꽁이": "음으로 된 작은 몸과 흰 꼬리를 가진 드래곤이다. 얼음밭에서 가장 흔하게 볼 수 있는 존재다. 걸을 때마다 얼음이 부딪히는 소리가 나며, 그 소리를 본떠 '꽁꽁이'라는 이름이 붙었다. 자신보다 강한 존재를 무리 지어 따르는 습성이 있어, 얼음밭의 왕을 대장으로 여기며 따른다. 함께 독특한 얼음소리를 내거나, 흰 꼬리의 우아한 물건을 만들 다니는 등, 무지런히 움직여 왕의 성장을 연구하고 있다.",
  "나기": "비행에 특화된 온화한 성격의 드래곤. 날렵한 날개와 지느러미가 빠르고 정확한 비행을 가능하게 한다.",
  "나이트 드래곤": "중세시대로부터 전해 내려온 갑옷을 입고 있으며, 기사의 영혼을 담고있는 전설의 드래곤이다. 정의롭고 용감하며 패배를 모르는 드래곤이다.",
  "나이트메어": "그의 행동엔 선의도, 악의도 없다. 그저 장난일뿐 그러니 너그러이 이해해 주도록하자.",
  "나트론": "생명체가 살 수 없는 '나트론 호수'에만 서식하는 드래곤. 강한 산성 호수라 천적이 없지만 알이 부식되는 일이 많아 개체가 많지는 않다고 한다.",
  "너티빌런": "사람들을 골려주길 좋아하는 악동 드래곤. 평소에 장난을 통해 사람들을 골려 주거나 함정을 통해 사냥감을 사냥한다. 무서운 생김새와 달리 매우 밝고 긍정적인 성격으로 최근 많은 드래곤 테이머들에게 인기를 얻고 있다.",
  "네무스": "오래된 숲에서 정령들의 의지가 깃들어 태어난 드래곤이다. 오래되고 거대한 숲에서만 발견되며 숲을 해치려는 자들로부터 보호한다. 강력한 정화의 힘을 가지고있다.",
  "네뷸라": "태양의 뒤에서 다른 별자리를 이끄는 드래곤. 다른 별자리의 드래곤들이 길을 헤매지 않도록 이끌며 조율한다. 우주의 색에 묻혀 잘 보이지는 않지만 점술집의 유리구슬을 통해서 네뷸라의 모습을 살펴볼 수 있다. [ 획득가능: 초보자 패키지 ]",
  "네비아": "몸에 달린 보석에서 치유의 안개를 만들어내는 드래곤, 주로 숲을 안개로 덮어 보호하고 돌봐주기 때문에 네비아가 사는 숲은 안개의 숲이라고 불린다.​​ 다친 동물들이나 나무들을 보살펴주는 걸 좋아하는 온화한 성격. 공격할 때는 다른 색의 안개를 만들어내는데, 상대방에게 자만심을 심어주어 스스로 자멸하게 만든다.",
  "네시": "네스호에 사는 괴수. 자주 모습을 보이진 않는다.주로 깊은 물속에 살지만 가끔 물위로 올라와 사람들을 놀래킨다.귀여운 모습이 사람들에게 인기가 많다. [ 획득가능: 난파선 ]",
  "네온 드래곤": "오색의 비수. 한번 보는 것만으로도시선을 빼앗긴다고 전해지는 오색의 드래곤. 호기심이 풍부하고 두려움이 적은 편이다. 하지만 그 아름다운 색에 현혹당해 나쁜 짓을 하려 든다면 무시무시한 장기인 오색의 비수로 자신을 해하려는 자들을 눈 깜짝할 사이에 물리친다.",
  "네크로멘서": "병들고 아픈 자들만이 밤하늘에서 볼 수 있는 드래곤. 그래서 별명은 [죽음을 관장하는 자]이다. 하지만 이는 소문으로, 사실은 병들고 아픈 자들에게 도움을 주기 위해 찾아온 것이다.",
  "네펜데스": "매우 아름다운 붉은빛을 띤 드래곤. 하지만 사실 맹독을 가지고 있다. 먹이와 적을 독으로 마비시킨 후 공격한다.",
  "넬로 드래곤": "심해에 사는 보랏빛 드래곤. 사슴의 뿔과 여우의 꼬리를 가지고 있어 한때 육지에 살았을거란 추측이 있다. 심해에는 대화할 상대가 없다보니 자연스럽게 과묵한 성격이 되었다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "녹스": "시간의 여신 기누의 수호 드래곤.녹스는 시간의 이루는 두 축 중 밤을 상징하며 시간의 여신 기누의 명에 따라 초월적인 힘을 지닌 칠흑의 포효를 사용하여, 사악한 카데스의 마물들을 물리쳤다고 전해진다.",
  "녹스O": "시간의 여신 기누의 수호 드래곤.녹스는 시간의 이루는 두 축 중 밤을 상징하며 시간의 여신 기누의 명에 따라 초월적인 힘을 지닌 칠흑의 포효를 사용하여, 사악한 카데스의 마물들을 물리쳤다고 전해진다.",
  "논": "공허의 힘을 부여받은 어둠 드래곤이다. 카데스의 여섯 날개 중 네 번째 날개에 파괴신으로부터 공허의 힘을 부여받았다. 빛과 어둠의 전쟁 이전, 불안한 기운이 퍼진 세상 속에서 예고 없이 모습을 드러냈으며, 그 모습이 목격된 수많은 차원 속, 공허의 움직임을 상징하는 존재라고 한다. 행성을 집어삼킬 정도로 강력한 논의 힘이 날뛰던 때만 빛과 어둠의 끝판왕에게 뒤틀리는데, 이 때문에 논을 처치하고자 빛 드래곤과 어둠 드래곤이 서로 힘을 합치는 경우도 있다.",
  "뇌신": "큰 구름을 몰고 다니며 날씨와 벌개를 자유자재로 부리는 드래곤. 평소에는 날씨를 조종하여 사람들을 윤택하게 해주지만 악에 빠진 자들에게는 거대한 번개로 천벌을 내린다.",
  "니케": "승리를 축복해주는 드래곤. 양심과 질서를 수호하는 드래곤이기도 하다. 제아무리 수많은 승리를 기록한 테이머라 할지라도 비겁한 수단을 이용한 자는 이 드래곤을 만날 수 없다.",
  "니케다": "승리의 여신의 어둠같은 차분함을 상징하는 드래곤. 콜로세움에서 강인함과 용감함을 증명한 자만이 만날 수 있다. [ 획득가능: 콜로세움 솔로 ]",
  "니케라이": "승리의 여신의 불같은 마음을 상징하는 드래곤. 콜로세움에서 강인함과 용감함을 증명한 자만이 만날 수 있다. [ 획득가능: 콜로세움 솔로 ]",
  "니케벤토": "승리의 여신의 바람 같은 민첩함을 상징하는 드래곤. 콜로세움에서 강인함과 용감함을 증명한 자만이 만날 수 있다. [ 획득가능: 콜로세움 솔로 ]",
  "니케이": "승리의 여신의 맑은 정신을 상징하는 드래곤. 콜로세움에서 강인함과 용감함을 증명한 자만이 만날 수 있다. [ 획득가능: 콜로세움 솔로 ]",
  "니케테라": "승리의 여신의 땅같은 굳건함을 상징하는 드래곤. 콜로세움에서 강인함과 용감함을 증명한 자만이 만날 수 있다. [ 획득가능: 콜로세움 솔로 ]",
  "니케플로": "승리의 여신의 물같은 유연함을 상징하는 드래곤. 콜로세움에서 강인함과 용감함을 증명한 자만이 만날 수 있다. [ 획득가능: 콜로세움 솔로 ]",
  "니티": "누군가의 정성스러운 뜨개질이 강한 염원을 담아 드래곤으로 만들어졌다. 잘 찢어질 듯 약해 보이지만, 뜨개질한 피부는 스파이크 못지않게 방어력이 높다고 한다.",
  "니플하임": "차가운 빙결의 틈새에서 서식하는 드래곤. 많은 신화에서 기록된 신비의 존재. 하지만 그 어떤 기록에도 구체적인 모습은 드러나지 않았다. 미지의 힘을 이용한 강력하고 매서운 공격은 그 어떤 적도 용서치 않는다.",
  "닌므니아": "복면을 두르고 남들이 모르는 선행을 하고 들키지 않는 것을 즐기는 특이한 취미를 가진 드래곤 ‘들키지않는것은 매우 중요하다. 소곤소곤’",
  "닌자드래곤": "비밀 집단에서 암묵적으로 교육하여길러진 드래곤이다. 기습과 은신에 능하며 상대의 약점을 간파하여 공략하는 치밀함도 지녔다.주로 적의 후방을 급습한다. [ 획득가능: 미스터리 뽑기 ]",
  "다로스": "빛과 어둠의 시대, 사악한 어둠에 맞선 크고 강대한 힘을 지닌 수호 드래곤.기억의 신이 내린 명령을 이행하고자 세상에 나타났으며, 압도적인 힘과 거대한 덩치를 이용해 적을 제압한다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "다르누스": "달이 뜨지 않는 밤에 나타나 꿈을 가져간다는 드래곤. 깊고 어두운 밤, 자고 있는 드래곤과 테이머들에게서 먹이인 꿈을 가져간다. 꿈은 나비의 형태로 구슬에 저장되며, 가장 큰 것은 순수하고 깨끗한 꿈, 작은 것은 악몽, 가장 작은 것은 상처받은 기억들과 관련된 꿈을 저장한다고 한다.",
  "다므니아": "드래곤 놀리기가 삶의 목적인 드래곤. 오늘은 또 어떤 드래곤에게 장난을 칠 지 고심한다. 일전에 다크닉스에게 장난을 쳤다가 옴므니아에게 크게 혼난 적이 있다. [획득조건: 도감점수 달성 ]",
  "다크나이트": "어둠의 갑옷을 입은 수수께끼의 드래곤. 빛이 보이지 않는 깜깜한 밤에 나타나 악을 멸하는 어둠의 심판자로 활약한다. [ 획득가능: 아르하 레이드 ]",
  "다크닉스": "빛과 어둠의 시대, 신의 대행자로서어둠의 세상을 수호하던어둠의 수호자.",
  "다크베인": "유타칸 침공의 선봉장으로 검은 날개와 붉은 눈을 가진 무시무시한 드래곤. 성격은 매우 잔인하고 포악하며 아르하에서도 그 악명이 자자했다. [ 획득가능: 아르하의 입구 ]",
  "다크스퀘어": "평소에 강에서 놀며 시간을 보내는 것이 하루에 대부분으로 물을 엄청 좋아한다. 평소에는 온순하며 장난을 친다. 물에서만 활동하는 것을 보면 물속성으로 오해를 하는 경우가 많다. 온순하지만 잘못해서 화를 내게하면 크게 다칠수도 있다.",
  "다크폴": "암흑이 스며든 물에서 태어나는잔인하고 무시무시한 드래곤.암흑의 정기가 물에 스며들어 장기간의 세월을 거쳐 태어나는 암흑의 드래곤이다. 강력한 비기인 칠흑의 공세는 살아 있는 모든 것에 치명적인 상처를 입힌다. [ 획득가능: 미스터리 뽑기 ]",
  "다크프로스티": "고위도 추운지방에 분포, 추운지방에 서식해서 몸에 깃털이 둘러져 있다. 프로스티 드래곤과 달리 혼자 생활하는 습성이 있다.",
  "다크혼": "부의 영광을 기원하는 골든혼과 다르게 다크혼은 악명으로 소문이 자자한 존재이다. 섬뜩한 안광을 바라본 자는 반드시 불행한 일을 겪는다는 괴담.어쩌면 이러한 괴담이 생긴 원인은 워낙 무시무시한 생김새를 지닌 다크혼의 외모 탓이 아닐까?",
  "단탈리온": "끔찍한 불행을 불러오는 무서운 드래곤. 생김새와 더불어 몸 주변에 풍기는 검은 안개는 불행을 불러올 것 같은 착각마저 든다. 하지만 이 드래곤을 육성하는 드래곤 테이머들은 그 소문을 매우 기분 나빠한다. 겉모습으로 사람을 판단하면 안 되는 것처럼, 어쩌면 단탈리온은 오히려 행운을 불러오는 드래곤일지 모르기 때문이다.",
  "데네브": "머리에 달린 보석으로 자신의 감정을 드러내는 드래곤. 굉장히 발랄하고 친근한 성격을 가지고 있다. 우주에 대한 관심이 많아 이에 대한 지식이 많은 이들은 쉽게 친해질 수 있다고 한다.",
  "데르": "고대의 존재를 지키는 수호자 드래곤. 무서운 생김새와 이세계의 불을 연상시키는 초록색 불꽃은 선하기보다 악하다는 선입견을 심어주기 충분하다. 하지만 수호자 드래곤인 만큼 생명을 수호한다는 이념에 충실하니 섣부른 오해는 접어두는 것이 좋다.",
  "데모니오": "공간의 신 구드라의 수호 드래곤. 과거 악신 카데스를 따르는 다섯 개의 재앙을 불러오는 디콘과 싸웠으며 구드라의 좌측을 수호했다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "데몽과가고일": "몬스터 세계에서 온 데몽과 그의 드래곤. 종족은 다르지만 둘은 항상 붙어 다니며 드래곤은 언제나 데몽의 지시에 따른다.",
  "데바": "거대한 양팔을 이용하여 상대를 공격하는 태고 드래곤이다. 태고의 유산에 이끌리는 드래곤이다. 태고의 유산에 이끌리는 드래곤이다. 태고의 유산을 후손하려는 적들을 처단하고 유산을 지켜낸다 전해진다. 태고의 힘을 사용할 수 있는 정확한 이유는 밝혀지지 않았다.",
  "데빌곤": "악마형 마수 드래곤. 이미 죽은드래곤의 영혼들이 땅에 스며들어태어난 드래곤인 만큼 생존의 목적이다른 어떠한 드래곤들보다 명확하다.자랑 중의 하나인 데빌레이더스는목표로 삼은 적에게 날아가 반드시명중하는 무시무시한 기술로 한번포착한 먹잇감을 끝까지 따라붙어죽음에 이르게 한다.",
  "데스락": "다른 차원에서 군림하고 있던 드래곤 어떤 사건으로 봉인되었지만 디멘션 드래곤이 차원을 이동하면서 열렸던 차원의 문을 비집고 나타났다. 다른 차원에서 왔기 때문에 알려진 정보가 없다.",
  "데칼": "무시무시한 마력을 지닌 마력형 드래곤. 감당하지 못할 홍의 마력의 힘으로 이성을 잃는 일이 잦아지자, 스스로 이마에 봉인을 새겨 넣어 강한 마력을 억제시키고 있다.",
  "돌연변이 미이라곤": "지하 던전 깊은 곳에 서식하는 드래곤. 몬스터 친구 가릴 것 없이 싸우는 것을 좋아해 상처가 마를 날이 없다.",
  "돌연변이 베네지": "매우 희귀한 확률로 태어나는 돌연변이 드래곤. 남들과 다르다는 이유로 때로는 선망의 대상이 되기도, 때로는 두려움의 대상이 되기도 한다.",
  "돌연변이 본헤드": "매우 희귀한 확률로 태어나는 돌연변이 드래곤. 남들과 다르다는 이유로 때로는 선망의 대상이 되기도, 때로는 두려움의 대상이 되기도 한다.",
  "돌연변이 볼케이노": "라바드래곤과는 또 다른 형태의 용암 드래곤. 붉은 피부만큼 불에 익숙하며, 잘 다룰 줄 안다. 튼튼한 근육과 꼬리는 그에 상응하는 전투력을 보장한다.",
  "돌연변이 수룡": "물속에서 살아가는 드래곤. 호수나 바다에서 물고기를 먹으며 살아간다. 온순한 성격에 다른 동물들과도 잘 어울릴 줄 안다.",
  "돌연변이 순둥곤": "동글동글한 생김새가 웃긴 드래곤. 매사를 둥글둥글하게 취급하며 살아가기 때문에 전투하는 경우가 적다. 일부 특이한 용 애호가들 사이에서는 애완용으로 인기가 많다.",
  "돌연변이 스마트 드래곤": "태어나면서부터 IQ가 뛰어난 드래곤이다. 책을 항상 갖고 다니는 이 드래곤은 책을 읽지 못하면 화가 나서 공격을 해버릴 수 있다. 책을 주웠다면 돌려주자.",
  "돌연변이 스콜피온": "매우 희귀한 확률로 태어나는 돌연변이 드래곤. 남들과 다르다는 이유로 때로는 선망의 대상이 되기도, 때로는 두려움의 대상이 되기도 한다.",
  "돌연변이 식스레그혼": "다리가 6개인 매우 특이한 드래곤으로 온순한 성격으로 사람들에게 인기가 많다. 머리 위에 뿔이 특히 매력적이다. 나는 것보다 뛰는 것을 좋아한다.",
  "돌연변이 에일리언": "우주괴물처럼 생긴 용, 우주의 힘을 가지고 있는 용이라고 전해진다. 하늘과 가까이 있는 곳, 하늘보다 더 하늘인 곳에서 많이 출현한다.",
  "돌연변이 패트 드래곤": "새끼때는 겁이 많아서 숨어 지내지만 점점 어른이 되면서 몸이 커진다. 매우 온순하고 약해 보이지만 먹이를 뺏기면 포악해져서 무서워지는 드래곤",
  "돌풍의 라이오스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 라이오스는 여섯 수호자 중 바람을 상징한다. 폭풍과 같은 능력으로 최선을 다해 여신 레오나를 지킨 수호 드래곤이다. [ 획득가능: 에스텔라 ]",
  "듀펜": "폭발적인 힘을 지닌 괴력형 드래곤. 아무리 무거운 적도 두 손으로 번쩍 들어 던지는 근력을 자랑한다. 이 무시무시한 힘의 근원은 머리에 솟아난 신비의 광석 '루마' 특히 머리에 솟아난 뿔이 강렬한 붉은색으로 변하면 더욱더 큰 힘을 발휘할 수 있다.",
  "드라고노이드": "난쟁이의 기계 병기와 드래곤이 만나탄생했다고 알려진 드래곤. 감정이라는 단어를 잃어버렸지만, 자신에게 연민을 품어 줄 테이머를 항상 기다리는 안타까운 존재이다. [ 획득가능: 미스터리 뽑기 ]",
  "드래곤 슬레이어": "빛과 어둠에 배신당한 이름 모를 고대 드래곤. 더 이상 그 정체는 알 수 없다. 증오와 저주로 타락한 그는 '모든 드래곤을 죽이는 자', 드래곤 슬레이어일 뿐이다. [ 획득가능: 증명의 탑 ]",
  "드므니아": "세상에서 숲속 깊이 들어가 잠자기를 가장 좋아한다. 인적이 드문 곳을 좋아하다보니 뜻밖에 드래곤 친구들을 많이 만났다. 다만 자느라 함께 놀지는 못한 것 같다 [획득조건: 도감점수 달성 ]",
  "디멘션 드래곤": "차원의 틈을 떠돌아다니는 존재. 보는 이마다 그 모습이 각기 다르게 보인다고 한다. 유타칸의 테이머들에겐 그 모습이 드래곤이었을 뿐, 원래 정체는 아무도 알 수 없다. [ 획득가능: 아르하의 입구 ]",
  "디아누": "차원문을 열 수 있는 문지기 드래곤. 빛과 어둠의 전쟁 당시 포르타, 페로스와 함께 차원문을 열고 닫으며 수많은 드래곤들을 지켜냈다. 디아누는 차원의 사슬로 닫힌 차원문은 강력한 힘이어도 열 수 없으며, 오직 차원의 열쇠로만 열 수 있다.",
  "디요나": "축복의 힘을 지닌 비행형 드래곤. 하늘거리는 금색의 깃털은 축복을 준다고 전해졌다. 하지만 소문은 언제나 거짓이 많은 법. 이 깃털은 치유의 효과만 지녔을 뿐 축복이란 능력은 없다. [ 획득가능: 미스터리 뽑기 ]",
  "딜랑": "금의 가호를 받은 비행형 드래곤. 금색의 몸에 수놓은 신비의 붉은 선의 장식은 빠르게 비행하면 더욱 강렬한 빛을 발한다. 빛 속성 드래곤임에도 불구하고 딜랑의 비행 속도는 바람 속성 드래곤과 견주어도 결코 뒤지지 않는다.",
  "따스한 발칸": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 발칸은 여섯 수호자 중 불을 상징한다. 과거 여신을 노리는 다크닉스에 맞서 타오르는 화염의 힘으로 대적한 용감한 드래곤이다. [ 획득가능: 에스텔라 ]",
  "땅의 고대신룡": "용의 신전에 사는 용. 신의 힘을 가지고 있는 용이라고 전해진다. 주로 하늘과 닿아있는 곳, 밝은 곳에서 주로 볼 수 있다. 사람들에게는 신의 대행자라고 주로 알려져있다.",
  "땅의 뱃도치 드래곤": "등에는 강력한 가시가, 꼬리에는 무시무시한 철퇴가, 이 드래곤을 상대하려면 엄청 곤욕을 치뤄야 할 각오를 해야 한다.",
  "땅의 블레이드 드래곤": "온몸이 칼날인 드래곤. 바위를 두부 썰 듯 자른다. 칼날의 예리함은 친구와 적을 구분하지 않으니 조심하자.",
  "땅의 파이어 드래곤": "불을 먹고 산다고 전해지는 드래곤. 주로 뜨거운 지역에서 생활하며 불을 좋아한다. 호전적이며 불같은 성격을 지녔다.",
  "라루스": "태양 속 작은 폭발에서 태어난 빛의 드래곤. 힘의 원천인 태양과 빛의 신성함으로 모든 암흑과 혼돈을 정화한다. 알지도 못하는 먼 과거에 일어난 암흑 대전에서 모든 악을 정화하고 사라졌다.",
  "라므니아": "모든 태어나는 드래곤을 보며 축복하는것이 숙명이라 생각하는 드래곤 근엄하지만 귀여운것에 약하다.",
  "라바 드래곤": "용암속에서 태어난 드래곤수천도의 온도에서도 견딜 수 있는 피부를 가지고있다.주로 용암속에 알을 낳기 때문에 알을 보기란 힘들다. [ 획득가능: 불의 산 ]",
  "라센티": "용암에서 태어나는 드래곤으로 날카로운 다리 끝에는 모든 걸 불태울 만큼 뜨거운 용암이 흐른다. 몸체에서는 끝없이 용암을 떨어트리며 기어 다니는데 라센티가 지나간 자리는 녹은 흔적만이 남는다.",
  "라스": "어둠의 수호자, 다크닉스의 권능 아래 7가지 죄악을 심판하는 다크세븐의 일원이다. 7가지 죄악 중 분노를 주관하고 있다. 자신의 분노를 가슴에서 표출하면서 상대의 분노를 흡수하기도 한다. 조그마한 일에도 분노를 일으킬 수 있으니 눈에 띄지 않는게 좋다. [ 획득가능: 2021 크리스마스 이벤트 ]",
  "라우아": "깊은 바다에서 그 모습을 확인할 수 있는 심해활동 드래곤. 몸 곳곳에 돋아난 아름다운 뿔은 물의 흐름을 알아내어 보다 쉽게 헤엄칠 수 있게 도와준다. 사람에게 그 모습을 쉽게 드러내지 않아. 환상형 드래곤으로 오해받지만 단순히 낯을 가리는 것 뿐이라는 학설이 지배적이다.",
  "라울": "마치 새하얀 종이 위에 칠흑의 음표를 새긴 것 처럼, 흑과 백 그 외도 아닌 것 처럼 다른 이들에게 기쁨을 주기 위해서라던지, 자신의 슬픔을 표현하던지, 가 아닌 단순히 존재한다 라는 이유로 마법으로 음악을 창조하는 드래곤이다. 가끔 '노래 불러줘'라고 조용히 속삭일 때도 있다.",
  "라이곤": "호기심이 많고 매우 활발한 성격의 드래곤. 날개가 작아 자유롭게 하늘을 날아다니지는 못하지만 빠른 달리기와 저공 비행을 이용해 땅 위에서는 상대를 놓치는 적이 없다. 강력한 다리 힘으로 한번 휘두르면 공기를 가르는 파동이 생긴다. [ 획득가능: 하늘의 신전 ]",
  "라이오스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 라이오스는 여섯 수호자 중 바람을 상징한다. 폭풍과 같은 능력으로 최선을 다해 여신 레오나를 지킨 수호 드래곤이다. [ 획득가능: 에스텔라 ]",
  "라지카스": "과거 빛과 어둠의 전쟁 당시 고대신룡을 수호한 기사 드래곤. 뛰어난 기교와 앞을 내다보는 책략은 고대신룡을 노리는 모든 존재에게 끔찍한 악몽으로 기억되었다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "라키온": "함정 설치는 즐기는 보따리 드래곤이다. 자신이 설치한 함정을 부수는 것에 예민하고 함정 제거 키트를 싫어한다. 짓궂은 성격을 지녀, 자신이 만든 함정에 다른 드래곤이나 동물들, 테이머가 당하는 모습을 구경하는 걸 좋아한다.",
  "라파엘": "태초에 빛과 어둠이 대립하던 시기에 존재한 매우 강력한 고대 드래곤. 과거 빛과 어둠의 대전투에서 무고한 생명을 지키고자 싸웠으며, 또 다른 이름으로는 자애의 대변자로 알려졌다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "락샤사": "수많은 선박 침몰 원인으로 손꼽히는 심해 드래곤이다. 많은 드래곤의 재물을 탐한 터라 긴나라의 수장 브리트라에 의해 깊은 심해로 쫓겨나고 말았다. 심해에서도 금은보화를 노려 수많은 선박을 침몰시켰다.",
  "램곤": "꿈의 여신 샌즈의 수호 드래곤.과거 꿈의 여신이라고 불린 샌즈의 수호 드래곤으로 포근한 양털에 덮인귀여운 생김새를 지니고 있다. 불면증이 걸린 사람들이 램곤의털을 얻어 베게에 넣고 자면 불면증이사라진다는 묘한 소문도 떠돈다고알려졌다.",
  "러스트": "강력한 산성 구름을 무기로 사용하는 특이성 드래곤. 강한 힘을 지녔으나 성격이 난폭하다는 말을 퍼져 그다지 테이머에게 인기가 높지 않다. 뛰어난 육성실력을 지녔다면 도전해볼 만하다.",
  "레굴루스": "네뷸라의 인도 아래 외우주를 떠돌아다니는 드래곤들 중 하나. 성장하면 성장할수록, 강렬해지는 빛으로 자신의 존재감을 뽐내기에 유타칸의 밤하늘에서도 레굴루스가 어디를 향하고 있는지 쉽게 확인할 수 있다고 한다.",
  "레긴레이프": "비프로스트의 안개를 가르고 대륙의 경계를 침범하는 위협으로부터 세계수의 뿌리를 지키는 드래곤이다. 고산 지대의 험준한 바위 절벽과 끊어진 다리가 맞닿은 비프로스트에서 살고 있다. 브륀힐드의 기운 중 '단절'의 의지를 물려받아 탄생했으며, 검의 형상을 띤 날렵한 팔을 휘둘러 안개 속에서 숨은 위험을 베어낸다. 레건레이프의 힘이 고조되면 신체에 새겨진 룬 문자가 찬란하게 빛나는데, 이때 응집된 마력을 폭발시켜 지형의 흐름을 방해하는 불순한 요소들을 정교하게 도려낸다. 평소에는 짙은 무지갯빛 안개 속을 소리 없이 기동하며, 외부의 간섭이 세계수의 뿌리에 닿지 않도록 경계를 늦추지 않는다.",
  "레드불 드래곤": "거구에 걸맞게 뛰어난 힘을 지닌 괴력형 드래곤. 레드불은 때로는 무소처럼 때로는 냉철한 사냥꾼처럼 적을 집요하게 공략하기로 이름이 알려졌다. 거대한 체구를 이용한 강인한 공격이 특징이다. [ 획득가능: 미스터리 뽑기 ]",
  "레드와이번": "새끼일때는 순하지만 성체가 되고부터는 막무가내로 포악해지는 드래곤이다. 뜨거운 불 구덩이 주변에서 자주 볼 수 있는 와이번 중 하나이다.",
  "레무레스": "봉인을 풀고 되돌아온 망령 드래곤이다. 심장에 박혔던 말뚝을 지팡이로 만들었고, 지팡이 끝의 보석은 약한 영혼들을 흡수해 마력을 모은다.",
  "레버넌트": "생김새 만큼이나 사악하고 악독한 드래곤. 헬카이저의 명령이면 무엇이든지 따른다. 카데스와 헬카이저에게 저항하는 이들을 무자비하게 살육했다. [ 획득가능: 증명의 탑 ]",
  "레베리": "날개 끝을 맞대어 거울을 만들어낸다. 이 거울을 통해 여신 샌즈가 내면을 돌아보고 옳은 길을 찾도록 돕는다. 거울로 허상을 만들어낼 수 있으며, 내면에 침투하는 존재가 여신의 본모습에 닿지 못하게 만든다.",
  "레블롭틴": "작고 순한 성격으로 인기가 많은 드래곤. 별다른 힘이 없어보이지만 염동력을 이용해 적에게 큰 타격을 입힐 수 있다.",
  "레오벡터": "고대의 현자가 만들어낸 마공학 병기 매우 뛰어난 마공학 기술로 만들어낸 등의 포탑은 표적을 정밀 타격할 수 있다. 업그레이드된 뉴런 시스템은 매우 빠른 연산처리를 할수있어 빠르게 성장할 수 있다.",
  "레오파드": "도마뱀 왕국의 물자를 조달하며 끈질긴 생명력을 자랑한 드래곤이다. 다른 도마뱀 드래곤들과 비교해 생존력과 번식력이 매우 뛰어나다. 꼬리가 일부 잘리거나 날개에 상처를 입어도 충분한 음식을 먹으면 회복하는 경우가 대부분이다.",
  "레이디 드래곤": "특이하게도 암컷만 태어나는 드래곤.핑크빛의 색상이 특징이며 매우 온순하다.눈빛이 매력적이다. [ 획득가능: 바람의 신전 ]",
  "레이어스": "땅의 갑옷을 두른 드래곤. 기동력이 뛰어나 돌진 공격을 주로 사용한다. 등에 뻗어난 큰 뿔들은 방어와 더불어 공격에도 사용된다.",
  "레이징": "온몸에 무엇이든 녹이는 레이져가 둘러쌓인 난폭한 드래곤, 하지만 진심으로 아끼는 대상에겐 레이져가 따뜻하게 느껴진다. 레이징은 해치, 해츨링 단계에서는 레이져를 잘 다루지 못하므로 거울로 컨트롤 훈련을 해야한다. 레이징의 에너지의 근원은 태양열을 저장하여 사용하며 레이져가 닿으면 폭발하는 구체가 신체주변을 떠다닌다. | 원작자 : 현무*소환사 |",
  "레인보우": "무지개 동산에서만 태어나는 드래곤이다. 날개의 색상이 무지개와 같다.",
  "레인보우배트곤": "다양한 생명의 염원이 깃들어 태어난 마력형 드래곤.본래 이름 없는 약한 드래곤이었으나 다양한 생명의 호소를 듣고 새로 태어났다.",
  "레텐토르": "땅의 힘을 자유자재로 사용하는 특화형 드래곤. 한번의 움직임으로 다양한 지각변동을 일으킨다. 그 힘은 비행형 드래곤에게는 미미하나 무게가 나가는 대형 드래곤에게는 큰 위협이 된다. [ 획득가능: 미스터리 뽑기 ]",
  "렉몰": "거대한 덩치를 자랑하는 신비성 드래곤. 팔에 새겨진 신비한 무늬가 붉어져 그 빛을 발한 때, 무시무시한 힘으로 적을 제압할 수 있다. 강한 힘을 지녔지만, 세상과 떨어져 조용히 은거하는 드래곤으로 전해진다.",
  "렉몰 리버스": "렉몰과 똑같이 생겼지만 성장 방법과 성격은 완전히 다른 드래곤. 어디서 온건지 그 정체는 철저히 비밀로 하고 있다. 렉몰과 마주하자 서로 굉장히 '뻘쭘한 표정'을 지었다고 한다.",
  "렉스톤": "뿔과 강한 완력을 가진 드래곤. 겉보기와 달리 얌전한 성격을 지니고 있으나 화가 나면 산을 무너뜨리기도 한다. 포메쿨과 사이가 좋다.",
  "로루스": "축복의 힘을 지닌 환상형 드래곤. 과거 많은 음유시인에게 노래를 통해 그 이름이 전해진 드래곤이다. 워낙 신비한 생김새 덕분에 행운을 가져다준다는 미신이 붙기도 했다.",
  "로키": "환영과 위장에 능한 장난기 많은 고대 드래곤이다. 연기 같은 갈기로 덮인 긴 몸을 상당히 민첩하게 움ㅈ기이며, 예측할 수 없는 행동으로 상대를 교란한다. 레무리아 대륙의 봉인 당시, 발두르의 부탁으로 대륙이 발견되지 않게 숨겼다. 대륙봉인 이후, 외부에서 레무리아로 들어가려는 자들이 없는지 감시했다.",
  "로티스": "개울가나 연꽃이 핀 연못에서 주로 발견되며 온화하고 부드러운 성격을 가지고 있다. 인간에게 우호적인 태도를 보이며 자신이 맘에드는 상대를 발견하면 연못의 분홍색 연꽃을 꺽어주고 사랑하는 상대에게는 짙은 붉은색 연꽃을 준다. 때로는 장난끼가 많은 면모를 보이며 연못 주변에 장난을 쳐놓기도 한다.",
  "롱기누스": "창 한 자루에 몸을 맡긴 채 오랜 세월 동안 이차원의 전장을 누볐던 드래곤. 끝없는 대결을 통해 자신에게 부족한 점을 찾게 되었고, 진화를 거듭하여 거리에 상관없이 모든 목표를 공격할 수 있게 되었다. 모든 힘을 발휘할 때에는 전신의 회로가 개방되며 신비한 빛을 뿜어 낸다고 한다. [ 획득가능: 2021 빛의 축제 이벤트 ]",
  "루": "빛으로 된 날개를 가진 드래곤. 얇은 피막같은 날개같지만 만져보면 실체가 없다. 어떻게 그걸로 날라다니는지는 아무도 모른다. 굉장히 무뚝뚝한 성격이라 친한 테이머에게도 날개를 만지는 걸 허락하지 않기 때문이다. [ 획득가능: 지하성채 ]",
  "루가르 드래곤": "어둠의 수호자를 수호하던 삼무제의 일원. 강한힘과 무서운 외형, 주변을 떠도는 불꽃 악령을 다루는 사악한 드래곤이다. 삼무제 중 가장 성격이 난폭한 존재로, 마르바스 의견의 차이로 자주 다투었으나, 누구보다 어둠의 수호자에게 충성을 다했다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "루네라 드래곤": "보름달의 어둠에서 태어난 드래곤. 여신에게 선택받지 못했다는 이유로 아르테미스 드래곤을 극도로 미워한다. 하지만 그 빼어난 아름다움은 아르테미스 드래곤에게 뒤지지 않는다.",
  "루돌프 드래곤": "산타의 썰매를 끌었다고 알려진 환상형 드래곤. 크리마용과는 친한 친구사이로 같이 산타의 썰매를 끌며 세상에 선물을 전해줬다는 기록이 남아 있다.",
  "루드라": "천상의 문지기라 전해지는 폭풍 드래곤. 폭풍의 신이라 불릴 정도로 강력한 바람을 다룬다. 망자가 심판받기 위해 천상으로 올라오면 선악을 구분해 악을 멸한다.",
  "루드오어": "신의 광석 드래곤. 루드오어의 피부 조각을 가져가 물건을 만든다면 영원히 그 상태로 유지한다고 해서 피부 조각은 신의 광석이라 불리며 모든 유타칸의 대장장이들이 만나보고 싶어 한다. 피부 조각은 오로지 루드오어의 힘으로 변형이 가능한 형태로 바꿀 수 있어 몰래 떼어간다고 하더라도 원하는 모습으로는 만들 수 없다.",
  "루루": "환상의 진주가 있는곳을 알고 있는 인도자 드래곤이다. 가슴에 진주가 박힌 드래곤으로 바다와 하늘을 오가며 생활한다. 그만큼 바닷길과 하늘길에 능통하지만 길잡이를 자처하지 않는다. 길을 잃은 배를 보아도 돕지 않는다. 그럼에도 불구하고 뱃사람들 사이에서 인기가 좋은데, 환상의 진주가 있는 곳으로 안내한다는 소문 때문이다. 실제로 환상의 진주가 있는 곳을 알고 있으며 마음에 드는 자들을 종종 그곳으로 안내한다. 얇고 투명한 비늘은 매우 튼튼하여 거친 물살과 바람에도 찢어지는 법이 없다.",
  "루미네스": "운명을 조율하는 신, 다이즈의 수호 드래곤. 빛을 머금은 은빛 갑주와 온몸을 수놓은 푸른 빙결은 매우 아름답지만, 그 파괴력은 일격에 모든 것을 얼려버릴 만큼 무시무시하고 강력하다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "루민디스": "다양한 모습으로 왕을 수호하며 노빌리스의 기사들을 이끄는 기사 드래곤이다. 기사도에 어긋나는 일은 절대 금하며, 기사도와 반하는 행위를 발견 시 같은 동료라 해도 절대 용서치 않는다.",
  "루살카": "서로 의식을 공유하는 파수꾼 드래곤이다. 머리에 달린 큰 푸른 혹으로부터 먼 거리로 의식을 원거리로 주고받거나, 흰 뿔을 서로 갖다대어 생각을 전달하기도 한다. 말을 하기보다는 생각으로 전달하는 경향이 크다.",
  "루송": "떡을 너무나도 좋아하는 드래곤이다. 언제든지 떡을 쳐서 먹을 수 있게 몸통이 절구로 되어있다. 떡메는 매우 무거워서 루송만 들 수 있다. 가지런히 썬 떡 모양의 루송의 꼬리는 맛있어 보이지만, 루송이 배고플때마다 떼어먹는 귀중한 먹이이니 건드리지 말아야 한다.",
  "루시오": "기괴한 문양으로 환각을 선사하는 환각 드래곤이다. 빛과 어둠의 전쟁 이전, 다크닉스를 따르던 시크레타 중 한 드래곤이다. 루시오가 선사하는 환각 속에서는 어둠 드래곤들의 선함과 빛 드래곤들의 악함이 있으며 오직 어둠이 승리하는 미래를 꿈꾸도록 한다. 다크닉스는 루시오의 환각이 통하지 않는 드래곤이었으며 루시오는 자신의 환각이 통하지 않는 다크닉스의 강인한 집념에 감탄하며 다크닉스를 따르기로 결심하였다. 환영을 만드는 능력으로 상대의 시각을 교란시켜 모든 공격을 무용지물로 만든다.",
  "루시페르": "불의 산에서 살고 있는 난폭한 드래곤. 다크닉스의 심복으로 악의 세력에 반대하던 자들에게 무참한 죽음을 선사했다. 다크닉스조차 골치가 썩을 정도로 난폭하니 테이머는 끝없이 주의를 기울여야 할 것이다.",
  "루아셰아 드래곤": "가장 밝은 달이 뜬 날 나타나는 드래곤. 그리고 세상의 악몽을 수집하고 사라진다. 그 뒤 다시 볼 수 있는 건 다음 보름달이 뜰 때로, 아주 희귀하고 보기 힘든 드래곤이다.",
  "루크바트": "네뷸라의 인도 아래 외우주를 떠돌아다니는 드래곤들 중 하나. 활과 화살을 이용한 싸움에 능숙하다. 활을 날리는 궤적에는 은하수가 생겨난다.",
  "루틸루스": "생명의 불꽃을 지닌 자연형 드래곤. 고동치는 숲을 닮은 녹색의 발과 빛을 형상화한 금색의 날개를 지니고 있다. 만리를 하루 만에 날아간다고 전해져 바람 속성 드래곤으로 착각하지만, 자세히 보면 불 속성 드래곤의 특징을 간직하고 있다.",
  "루포": "미지의 땅. 아브게니아에서 찾아온 신비의 드래곤. 숱한 전투에서 살아남은 무시무시한 투사로 강한 전투력을 지니고 있다. 루포 드래곤의 냉철한 판단력은 테이머들에게 큰 도움을 줄 수 있을 것이다.",
  "루피아 드래곤": "바다의 생명의 목소리를 듣는 신비한 드래곤. 자신의 능력은 미약하나 자신의 친구들을 이용해 적을 농락하는 재주가 엄청나다고 알려졌다. 가끔 이 드래곤을 육성하여 물고기를 잡길 부탁하는 못된 드래곤 테이머도 존재하지만 자신의 친구들을 내버릴 친구가 세상에 과연 있을지부터 질문하는 게 순서일 것이라 여겨진다. [ 획득가능: 청록의 해저화산 ]",
  "룩소린": "베르나의 남동생. 누이의 죽음을 맞이할 당시 몸과 마음에 큰 상처를 입었다. 회복 불가의 깊은 상처는 그의 마음과 외형, 둘 모두를 뒤틀어놓았다. 남은 것은 누이를 그리는 끔찍한 복수귀였다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "리바이어던": "7대 죄악 중 '질투'를 담당하는 드래곤. 주로 바다에 서식하며 거대한 몸집을 가지고 있다.",
  "리베라": "수많은 역사에 기록된 전설의 풍마. 거대한 폭풍우 속에 항상 그 모습을 드러내 재앙의 존재로 기록되어왔다.갑옷 같은 피부와 전신에서 발산하는 신비한 푸른 빛은 수 세기가 지나도 많은 학자를 매료시키는 환상과 같았다.",
  "리베티": "성실하고 근면한 성격의 드래곤. 단점이라면 근면성실함을 너무 추구한 나머지 게으른 드래곤들과 사이가 영 좋지 못하다.",
  "리브로": "세상에 보이는 모든 것을 책에 기록하며 항상 의문을 가진다. 지금까지 보고 느낀 것들에 대해 상세히 기록을 남긴다. 겉으로 보기에 리브로가 지니고 있는 책은 한 권인데, 머리에 쓰고 있는 기록자의 모자는 신비한 기운을 담고 있어, 매우 작아보이지만 놀랍게도 속은 깊어 그 안에 책을 담아둔다. 리브로에게 친절히 부탁하면 보여줄지도 모른다. 특히 자연에 관심이 많다. 리브로는 대부분 기록하거나 책을 읽을 때 숲 속에 있는다. 작은 동물과 대화할 수 있는 능력도 있어 주변에는 새들이 모여있기도 하다.",
  "리치몬드": "금지된 암흑마법에 도전한 고대의 주술사 드래곤. 크리스탈에 강력한 암흑마력을 담을 수는 있었지만 그 대가로 육체를 빼앗기게 되었다. 암흑마력이 담긴 수정구에서 마력을 뽑아내어 강력한 브레스를 뿜어 적의 육체를 소멸시킨다. 육체가 소멸된 적의 영혼을 크리스탈로 흡수하고 암흑마력으로 변환시키는데 적을 무찌를수록 더욱 더 강력한 마력을 지니게 되는 무시무시한 드래곤이다.",
  "리쿠루드래곤": "특이한 성장 방식을 지닌 특이성 드래곤. 반드시 자신이 지나간 자리에 표시를 해두는 습관이 있다. 표시하는 행위는 일종의 스트레스 해소법으로 육성을 게을리했다면 빈도는 더 심해진다. [ 획득가능: 미스터리 뽑기 ]",
  "리티오": "풍성한 털과 거대한 날개를 가진 드래곤이다. 거대한 날개는 먼 거리를 거뜬하게 날아갈 힘을 가졌으며, 풍성한 털은 장시간의 비행에도 보온을 유지할 수 있게 돕는다. 리티오의 꼬리 끝은 성장에 따라 병의 치유를 돕는 능력을 갖춘다.",
  "리프 드래곤": "넓은 나뭇잎을 감싸고 있는 듯한 이 드래곤은 새끼 때는 자신의 피부조직인 나뭇잎을 감싸고 다닌다. 하지만 커가면서 거대한날개로 변한다. 날카롭고 정교하게 공격을 한다. [ 획득가능: 옛 성터 ]",
  "마가": "태초에 존재했던 신비의 성, 파라디수스를 지키던 최후의 수호 드래곤. 바람의 힘을 이용하며, 거센 돌풍 속에 몸을 맡겨 적을 공격하는 전법을 구사했다. [ 획득가능: 미스터리 뽑기 ]",
  "마그나스": "이계의 지배자 마룡왕의 자식으로 제1 왕위 계승권을 가졌다. 그러나 정복된 세계는 볼일 없다며 서번트 몇 마리와 함께 차원을 넘어 이노를 정복하러 왔다. 머리의 왕관은 차원을 넘을 때 아버지의 것을 몰래 가지고 왔다.",
  "마누스": "마계의 차원문을 지키는 문지기다. 허가받지 않은 존재가 차원문제 접근할 때 스태프를 소환하여 제압한다. 큰 귀로 먼 거리의 위협을 감지하며, 위협을 감지하면 즉시 차원문과 자신을 완벽하게 은폐시킨다. 마룡왕의 명을 받들어, 스태프의 구슬을 통해 과거 전투에 맞붙었던 자, 마그나스의 동태를 주기적으로 확인하고 있다.",
  "마니메칼라": "에스텔라의 맑고 푸른 바다에 사는 드래곤. 얕은 바다에서 하얗게 부서지는 파도의 기운을 모아 성장한다. 물을 조종할 수 있으며 어릴 때에는 미약하지만 완전히 성장하면 큰 파도도 부릴 수 있다고 전해진다. [ 획득가능: 드래곤빌리지 37권 ]",
  "마룡": "마계의 왕이란 별명을 지닌 드래곤. 그만큼 어마어마한 마력을 지니고 있다.평소에 들고다니는 구슬은 마력을 저장하고, 조절하는 역할을 맡는다고 한다.",
  "마르바스": "어둠의 수호자를 따르는 드래곤의 무리는 검은 파도와 같았다. 마르바스는 과거 어둠의 수호자를 호위하던 삼무제의 일원으로 무시무시한 힘과 전투력으로 어둠의 수호자를 지키는 삼무제의 매서운 검이라고 불렸다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "마리노 드래곤": "어릴 때는 수중에서 많은 생활을 하다가 성장함에 따라 지상으로 나와 성장을 마무리한다. 흡사 개구리 드래곤인 프로그 드래곤과 비슷하다는 평이 많지만 실상 알려진 바는 전혀 다른 형태의 변종 드래곤이라 정정하고 있다.",
  "마문드": "항상 눈을 감고 있어 잠이 많은 걸로 오해받고 있는 드래곤이다. 복슬복슬한 털 때문에 숙면을 취하고 있어 보이지만 눈을 감으면 상대의 마음을 꿰뚫어 볼 수 있다고 한다. 마문드가 눈을 뜨고 그 눈을 바라본 자는 기억의 저편에 갇혀 빈사 상태가 될 수 있으니 조심해야 한다.",
  "마브리카 드래곤": "검은 가면을 쓰고 있는 드래곤. 맨얼굴을 본 이는 아무도 없다. 사실 가면이 아니라 얼굴의 일부다, 너무 추하게 생겨서 벗지 않는거다라는 둥 여러 소문이 돌지만 진실은 모른다. [ 획득가능: 도전의 전장 ]",
  "마소티스": "꿈의 연못에 사는 요정 드래곤, 꿈의 연못은 현실에선 볼 수 없고 오직 꿈에서만 볼 수 있다고 한다. 꿈에서만 만날 수 있기 때문에 잠에서 깨어나면 기억에 남지 않는다고 한다. 항상 정령이 드래곤 주변을 맴돌며 드래곤을 수호한다. [ 획득가능: 프리미엄 뽑기 ]",
  "마스테마": "푸른 불꽃을 다루는 드래곤. 시리도록 차가운 색의 불꽃을 다루지만 그 힘이 너무나도 강력하여 원치 않는 곳에서도 방출되기 때문에 언제나 힘을 억누르며 살아간다.",
  "마카라": "니드호그를 따르는 사악한 우주 드래곤, 미트라의 라이벌이며 오만하고 호전적인 성격을 가지고있어 상대를 공포를 떨게하는 것을 재미로 느낀다. 약한드래곤을 멸시하며 강함들 추구한다.",
  "마카롱": "다양한 마카롱 정령들을 소환하여 주변 생명체들에게 도움의 손길을 내민다. 달콤한 맛의 노란 마카롱은 힘을 돋워주고, 고소한 맛의 초록 마카롱은 마음을 차분하게 해준다. 위협이 다가올 때 씁쓸한 맛의 파란 마카롱을 던지면, 폭탄처럼 터진다.",
  "말덱": "둘로 나뉜 순환의 서 중, 흡수의 서를 갖고 있는 악동 드래곤. 호기심이 많아 눈에 보이는 생명들을 책 안에 가두려고 한다. 덕분에 누나인 스트라가 골치를 앓는 편.",
  "말로단": "태초에 존재하던 초거대 드래곤.강대한 힘과 능력을 가졌지만 어디에서 왔는지, 그 목적이 무엇인지는 아무도 모른다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "말소자 드래곤": "모든 것을 태워 안녕으로 이끈다는 업보의 불길을 만들어 내는 드래곤. 외형으로 인해 흉악하고 무시무시한 드래곤으로 알려졌지만 실상 이승을 떠도는 혼령이나 잠들지 못한 존재를 안식시키는 등 소문과는 다르게 수호자의 성격을 띠고 있다. 여행 도중 말소자 드래곤을 만난다면 비명을 지르기 보다 한 발자국 다가가 호감 어린 눈빛을 보여줘도 나쁘지 않을 듯하다. [ 획득가능: 고요의 암석터 ]",
  "맘므니아": "좀처럼 물밖으로 나오지 않는 드래곤. 물속에선 민첩하게 움직일 수 있지만 뭍으로 올라오면 그렇지 못해 싫다고 한다. 물 밖 세상은 잘 모르지만 물 속에서는 누구보다도 많은 드래곤들과 친구라고 자랑한다. [획득조건: 도감점수 달성 ]",
  "매직스타 드래곤": "신비의 세계에서 왔다고 주장하는 드래곤. 진짜인지는 모르겠지만 뛰어난 언변이 사람같다는 느낌을 줄 때가 많다. 카드놀이와 도박을 좋아한다. 잘 하지는 못한다고 한다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "매직스타드래곤": "신비의 세계에서 왔다고 주장하는 드래곤. 진짜인지는 모르겠지만 뛰어난 언변이 사람같다는 느낌을 줄 때가 많다. 카드놀이와 도박을 좋아한다. 잘 하지는 못한다고 한다.",
  "맴도는 라이오스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 라이오스는 여섯 수호자 중 바람을 상징한다. 폭풍과 같은 능력으로 최선을 다해 여신 레오나를 지킨 수호 드래곤이다. [ 획득가능: 에스텔라 ]",
  "머드 드래곤": "스왐프 드래곤과 태생은 비슷하나 생활 방식은 다른 드래곤. 본래는 물속성의 드래곤이었으나, 생활방식으로 인해 속성이 변화된 특이한 종류의 드래곤으로 최근 많은 학자들에게 연구의 대상으로 손꼽히고 있다.",
  "머스타드해머": "턱근육이 굉장히 좋은 드래곤이다. 턱힘 하나로 바위도 으깰 수 있다. 성격은 온순하며, 다른 드래곤들을 잘 따른다.",
  "메갈로돈": "네시와 마찬 가지로 사람들에게 신비의 상징으로 알려진 드래곤. 용의 마력을 목격한 많은 이들이 청룡과 착각하여 숭상했지만 실제로는 청룡처럼 자비롭기보다 파괴와 악행을 일삼는 사악한 존재로 더 알려져 있다. [ 획득가능: 미스터리 뽑기 ]",
  "메라크": "강한 완력과 금빛 뿔로 우주의 모든 불멸자를 처벌한다. 미트라의 여섯 부하 중 하나로, 앙그라와의 전투에서 눈에 깊은 상처를 입은 뒤 끊임없이 자신을 단련해 강인한 육체를 완성했다. 상처로 뒤덮인 거친 몸과 거대한 근육질 팔은 오랜 노력과 축적된 힘을 증명한다. 금빛 장신구가 둘러진 팔에 힘을 모아 휘두를 때, 몯느 것은 한순간에 산산조각 난다. 자신보다 몇 배는 큰 물체도 거뜬히 들어 올려 무기로 삼는다. 전투 중 분노가 극에 달하면, 금빛 뿔에서 강렬한 빛이 발산된다. 이 빛은 불멸자들의 시야를 마비시키고, 그들의 발걸음을 완전히 봉쇄한다.",
  "메이플드래곤": "사람의 손이 닿지 않는 절벽 끝 단풍나무아래에서 태어나는 드래곤. 메이플이 날개짓을 하면 곡식이 풍성해진다. 숲의 수호자 엔트와 같이 자신의 숲을 지키는 드래곤으로써 숲을 사랑하고 지키는 드래곤이다.",
  "메탈 드래곤": "피부와 뼈가 모두 강철로 된 드래곤. 물은 매우 싫어하지만 불과 함께라면 힘이 배가 된다. [ 획득가능: 어둠 제단 ]",
  "메탈 마그넷 드래곤": "머리, 팔, 다리, 날개가 자석과 같은 성질로 이루어져 있다. 배에 있는 버튼을 건드리는 걸 무척 싫어한다.",
  "모리카 드래곤": "망자를 이끄는 길잡이 드래곤. 탁한 색으로 인해 암흑의 드래곤으로 오해하는 사람이 많지만 실제로는 망자를 저승으로 안내하거나 잡아가는 수호자의 성격을 지녔다. 꼬리에 달린 호롱 불은 악한 자와 망자에게 강력한 힘을 발휘한다.",
  "무닌": "흰 까마귀 영토를 지키는 고대 드래곤이다. 검은 몸을 가졌으며 장난스러운 성격과 반짝이는 것을 좋아하는 어린 모습을 보인다. 찾아온 테이머에게 강력한 마석 '카닐'의 유혹을 이겨낼 수 있는지 시험한다.",
  "문라이트": "빛이 저무는 고요한 밤에만 태어나는 이세계 드래곤. 밤하늘에 달이 떠 있을 경우 달의 힘을 받아 누구보다 빠르게 날 수 있다. 의외로 쉽게 토라지는 성격이니 신중히 육성하자.",
  "물결의 파프리온": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 파프리온은 여섯 수호자 중 물을 상징한다. 맹렬한 해일을 불러오는 힘을 지녔으며, 레오나를 안전한 곳으로 이동시켰다고 전해진다. [ 획득가능: 에스텔라 ]",
  "물의 레이디 드래곤": "특이하게도 암컷만 태어나는 드래곤. 핑크빛의 색상이 특징이며 매우 온순하다. 눈빛이 매력적이다.",
  "물의 레인보우": "무지개 동산에서만 태어나는 드래곤이다. 날개의 색상이 무지개와 같다.",
  "물의 메탈 드래곤": "피부와 뼈가 모두 강철로 된 드래곤. 물은 매우 싫어하지만 불과 함께라면 힘이 배가 된다.",
  "물의 크리마용": "겨울에만 발견된다고 알려진 신비로운 용. 이색적인 장식을 몸에 장식한 것이 특징이며 장식의 색상만큼 활발하고 장난기가 많은편. 들려오는 민담으로는 루돌프를 도와 썰매를 끌었다고 전해진다.",
  "뮤직 드래곤": "음악을 사랑하고 즐겨 부르는 드래곤 사실상 노래는 잘하지 못한다. 노래를 부를 때 나오는 초음파로 다른 드래곤들을 공격한다. 다른 용들은 귀가 아파 항복을 하기도 한다. [ 획득가능: 메마른 평원 ]",
  "므네이아": "세상에 떠도는 기억을 수집하는 서기 드래곤. 세상에 떠도는 기억과 시간을 수집하여 기록하는 드래곤으로 귀여운 생김새와 달리 매우 해박한 지식을 지니고 있다. 꼬리에 번뜩이는 푸른 불꽃은 악한 자의 기억을 소거 시키는 힘을 지녔다.",
  "미나스 드래곤": "신성한 달빛에서 태어난 드래곤. 어두운 밤에 가장 밝게 빛나는 존재로서 어둠 속의 모든 악을 찾아내 무찌른다는 사명감을 가지고 있다. 루네라 드래곤의 숙적. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "미니 드래곤": "작은 고추가 맵다.'라는 속담처럼작다고 무시하면 안 된다. 작은 성체로, 빠른 스피드를 낼 수 있다. [ 획득가능: 무지개 동산 ]",
  "미미르": "수백년간 잠들어 있던 드래곤, 끊임없는 만남을 추구해야 만날 수 있다. 오랜 기간 동안 공을 들여 만난다면 깨어나 지식의 샘물을 내어주어 테이머에게 지식을 알려준다고 한다.",
  "미스트드래곤": "으스스한 모습의 언데드 드래곤. 미스트 드래곤은 다른 사물에 숨어들어 사물을 조종하거나 지배할 수 있다. 단 이 기술의 단점은 정신력이 강한 존재에게는 전혀 통하지 않는다는 점이다. [ 획득가능: 미스터리 뽑기 ]",
  "미스틱아츠": "묵직한 주먹으로 무장한 투지 드래곤이다. 당근을 좋아하며 당근밭에서 주로 생활한다. 너무 작고 날쌔게 움직이는 바람에 당근밭 주인이 애를 먹는다. 당근밭에 자라는 당근들이 모두 자신의 것이라고 생각하며, 당근밭을 탐내는 자들에게 주먹을 휘두른다. 미스탁 아츠가 휘두르는 주먹은 너무 빨라 눈에 보이지 않는다.",
  "미스틱티니": "오래된 집에 서식하는 작고 귀여운 마력형 드래곤. 그 생김새가 쥐와 비슷하지만, 매우 작은 크기에도 불구하고 드래곤으로 분류된다.기묘한 형태의 랜턴을 흔들며 다양한 마법을 사용한다. 다만… 무작위로 엉터리 마법이 발동되는 탓에 가끔 큰 소동을 일으킨다.",
  "미스틸테인": "한 알에서 태어난 두마리의 드래곤. 한마리는 날개가 짧아 날 수 없었고, 한마리는 날개가 너무 커 걸을 수가 없었다. 궁리 끝에 이 둘은 서로의 날개와 발이 되어 함께 다니게 되었다.",
  "미스핏": "신비한 주술을 다루는 드래곤. 과학적으로 이해할 수 없는 힘을 사용하여 미래를 예측하거나 적에게 악몽을 선사한다고 알려져 있다. 유타칸의 많은 테이머들과 드래곤 전문가들이 그 힘을 분석해보려고 했었지만 되려 악몽에 가득 찬 밤만 보내게 되었다고 한다. [ 획득 가능: 패키지 ]",
  "미이라곤": "지하 던전 깊은 곳에 서식하는 드래곤. 몬스터 친구 가릴 것 없이 싸우는 것을 좋아해 상처가 마를 날이 없다. [ 획득가능: 어둠 제단 ]",
  "미트라": "아모르가 다른 차원에 창조한 드래곤. 아모르의 의지를 현실로 구현하는 능력을 가지고 있으며 앙그라를 봉인한 장본인이다. 최근 빛과 어둠의 전쟁으로 풀려난 앙그라를 찾느라 혈안이 되어있다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "미티어": "작은 별에서 태어난 드래곤으로 이마와 꼬리에 작은 별을 달고 있다. 매우 빠른 이동속도를 자랑하며 꼬리와 이마의 별은 빨라질수록 밝게 빛난다. 그것을 본 사람들이 별똥별로 착각하는 경우가 있다고 한다.",
  "밀라": "등갑에 큰 자연을 가지고 다니는 거대 드래곤. 다른세상에 큰 관심을 가지지 않으며 무심하게 하늘을 떠다닌다. 등에는 개체마다 다른 독자적인 생태계를 가지고있어서 탐험가들이 등에 올라타고 싶어한다.",
  "밀라타스": "빛의 수호자, 고대신룡의 권능 아래 7가지 선을 주관하는 라이트 세븐의 일원이다. 7가지 선 중 겸손을 주관하고 있다. 상대를 존중하고 서로의 다름을 받아들이는 관대함으로 라이트 세븐을 이끄는 리더이다. [ 획득가능: 2021 크리스마스 이벤트 ]",
  "바람의 샌드 드래곤": "불보다 뜨거운 사막에서 태어난 샌드 드래곤. 땅계열 같지만 그는 불계열이다. 불구덩이보다 뜨거운 모래로 상대를 잠재울 수 있다.",
  "바람의 흑룡": "사람들 눈에 잘 띄지 않는 곳에 서식하며, 길들이기 힘든 드래곤으로 알려져 있다. 탐험을 통해서 얻을 수 없는 스페셜 드래곤.",
  "바르그": "오래된 설화 속에 등장하는 드래곤. 검은 로브의 습격을 받아 큰 피해를 입고 도망쳐 더욱더 강력한 힘을 추구하게 되었지만, 형제와는 다른 운명을 선택해 검은 로브의 마수로부터 유타칸을 보호하기로 맹세했다. [ 획득가능: 길드 상점 ]",
  "바르라아": "빛의 속삭임에 기거하는 신비성 드래곤. 온몸에 수 놓인 신비의 빛의 흔적은 보는 이의 눈을 사로잡는다. 수많은 드래곤 테이머는 이 신비한 드래곤을 표현하길 '꿈을 형상화한 값진 보석과 같다' 라고 말하곤 했다.",
  "바리안": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 바리안은 여섯 수호자중 빛을 상징한다. 광명의 빛으로 최선을 다해 여신 레오나를 지킨 수호드래곤이며, 여섯 수호자의 우두머리이다. [ 획득가능: 에스텔라 ]",
  "바스카": "고대 드래곤의 후예이자 광활한 고지대 초원의 지배자이다. 토호우 대륙에 혼란이 빚어지던 시절이 있었다. 오래전 대륙에 존재했던 고대 드래곤들은 뜻을 하나로 모아 대륙을 통일했고 혼란을 잠재웠다. 고대 드래곤들의 후예로 탄생한 바스카는, 그들의 뜻과 염원을 이어받아 토호우 대륙의 초원을 지배해나갔다. 고대 드래곤들은 바스카가 태어난 순간부터 훗날 지배자가 되리라는 것을 예견했다. 초원의 기운을 품은 강인한 힘을 가졌기 때문이었다. 초원의 바람과 태양 빛은 항상 바스카의 기운을 따라 움직이며, 이 힘으로 오랜 시간 동안 초원의 먼 거리를 이동할 수 있다. 유목민들의 삶을 위하여 자신의 힘을 사용한다. 커다란 황금빛 발톱 끝으로 밤에 습격해오는 들짐승과 몬스터의 공격을 막아내며 바스카의 손아귀에 든 모든 생명체는, 앞에 무릎 꿇거나 영영 사라지거나, 둘 중 하나를 택해야 한다. 왼팔의 황금 장신구는 드넓은 초원의 지배자임을 상징한다.",
  "바알": "태초에 빛과 어둠이 대립하던 시기에 존재한 매우 강력한 고대 드래곤. 원인 모를 다크닉스의 폭주로 인해 세상의 균형이 깨지자 고대신룡을 도와 다크닉스를 봉인시켰다. 또 다른 이름은 어둠의 감시자라 알려졌다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "바위 드래곤": "바위와 같은 단단함을 가지고 있는용.외부로부터의 통증이나 감각을 잘 느끼지 못한다.머리도 단단하다. [ 획득가능: 희망의 숲 ]",
  "바이올렛 드래곤": "외형의 아름다운 색과 달리 성격이 사나우며 공격적이다. 더불어 호기심이 강하기 때문에 움직이는 것이나 처음 보는 사물을 무조건 공격해보는 습성을 지녔다. 기술인 파이브센스는 오색 빛의 공격으로 적을 공격하는 동시에 시야의 구분을 방해하여 판단을 흐리게 하고 위험에 빠트릴수 있다.",
  "박쥐곤": "어두운 동굴에서 살고 있는 드래곤. 실제 박쥐와 다르게 시력이 좋으며 어두운 곳도 잘 볼 수 있지만 밝은 곳은 눈이 부셔 별로 좋아하지 않는다. 하지만 테이머와 친해지게 된다면 밝은 태양 아래서도 용감히 싸울 수 있는 의리있는 드래곤이다.",
  "발라 드래곤": "태초의 빛과 어둠의 전쟁 당시, 빛의 수호자를 따르는 무리중 칸과 더불어 뛰어난 활약을 한 드래곤. 아름다운 갈기와 빛을 머금은 뿔은 오직 발라가 사랑하는 모든 존재를 지키기 위해서만 빛났다고 한다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "발라크": "어둠의 보물이라 불리는 칠흑빛의 드래곤. 밤하늘처럼 빛나는 검은 털은 달빛을 받을 때마다 검은 진주마냥 번뜩인다. 할리벨과 대칭을 이루는 존재로 선과 악의 유무 없이 강한 힘을 지닌 자를 자신의 테이머로 인정한다. 반대로 약한 자는 무슨 행동을 하더라도 자신의 테이머로 인정하지 않는다.",
  "발레포르": "혼돈의 힘으로 온 세상을 혼돈에 빠트리려고 한다. 혼돈의 틈새에서 제일 간사하고 악한 존재다. 보이지 않는 곳에서 은밀하게 목표를 바라보고 접근하여 달콤한 말을 내뱉은 뒤, 혼돈을 야기한다. 목표를 달성하면 자신은 유유히 모습을 감춰버린다. 가끔 자신의 달콤한 말에 속아 넘어가지 않는 이들도 있지만, 혼돈으로 물든 세상을 염원하고 있어 쉽게 포기하지 않는다.",
  "발로드": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 발로드는 여섯 수호자 중 어둠을 상징한다. 강력한 어둠의 힘을 조종했으며, 누구보다 레오나를 위했던 드래곤이었다고 전해진다. [ 획득가능: 에스텔라 ]",
  "발칸": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 발칸은 여섯 수호자 중 불을 상징한다. 과거 여신을 노리는 다크닉스에 맞서 타오르는 화염의 힘으로 대적한 용감한 드래곤이다. [ 획득가능: 에스텔라 ]",
  "배틀 드래곤": "또 다른 세계에서 건너온 이계의 드래곤. 잦은 전투에 특화되었으며 좀처럼 남을 신뢰하지 않는다. 물론 진심으로 마음을 연다면 그 호소에 응답할지도 모르는 일...",
  "백룡": "희망의 드래곤으로 알려진 백룡.탐험을 통해서 얻을 수 없는 스페셜 드래곤.",
  "백택곤": "사람의 말을 이해 및 구사 가능한 드래곤. 주로 사람들의 눈에 띄지않는 절벽에 서식하며 불의를 참지 못 하는 정의로운 드래곤이다.",
  "백호": "소리소문없이 재빠르게 달리면서 사악한 존재를 내쫓으며 서쪽을 관장한다고 전해지는 사신 드래곤이다. 모두에게 친근하고 악을 증오하는 성격으로 테이머나 드래곤을 가리지 않고 직접 나서서 보호해 주려고 한다.",
  "밴시": "무시무시한 힘을 지닌 언데드 드래곤. 끔찍한 소리와 소름이 끼치는 모습. 밴시를 상징하는 단어라 할수있다. 보는 자는 누구든 죽음으로 인도하기 때문에 발견 시 죽음을 각오해야 할지 모른다. [ 획득가능: 미스터리 뽑기 ]",
  "뱃도치 드래곤": "등에는 강력한 가시가, 꼬리에는 무시무시한 철퇴가, 이 드래곤을 상대하려면 엄청 곤욕을 치뤄야 할 각오를 해야 한다. [ 획득가능: 나무 던전 ]",
  "버블 드래곤": "입에서 강력한 거품을 뿜어 적을 공격하는 드래곤.꽤 난폭한 성격을 지니고 있어 쉽게 친해지기 어려운 드래곤이다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "버블드래곤": "입에서 강력한 거품을 뿜어 적을 공격하는 드래곤.꽤 난폭한 성격을 지니고 있어 쉽게 친해지기 어려운 드래곤이다.",
  "번개고룡": "고대에 존재하던 번개 드래곤. 번개와같은 속도로 날아다닌다고 전해진다.빠른 속도로 날아다닐 때에는 눈에보이지 않을 속도로 날아다닌다. 주로 밤에 행동하며 너무 빨라 그 모습을 본 사람이 별로 없다. [ 획득가능: 불의 산 ]",
  "번네스": "운명을 조율하는 신,다이즈의 수호 드래곤. 빛을 머금은 은빛 갑주와 온몸을 수놓은 붉은 화염은 끝없이 타오르며 적으로 간주하는 모든 것을 태워 없애는 초월적인 힘을 지녔다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "범": "꿀단지에서 태어나 꿀을 배출하는 드래곤, 꿀은 몸의 온도로 500도까지 가열된다. 꿀은 자신의 식량이자 최고의 무기이다.",
  "베가본드 드래곤": "항상 세상을 떠도는 드래곤. 여행을 통해 자신보다 강한 상대와 싸워 자신을 수련하는 것을 좋아한다. 오랜 전투를 한 베가본드의 전투 능력은 매우 뛰어나다.",
  "베네보렌티아": "빛의 수호자 고대신룡의 권능 아래 7가지 선을 주관하는 라이트 세븐의 일원이다. 7가지 선 중 친절을 주관하고 있다. 어떤 상대이든지 무장해제 시킬 만큼 다정다며 자신의 도움을 바라는 이에게 친절함을 베푼다. 무슨 일이 생기든 인자한 표정을 잃지 않으며 상대를 존중하고 배려한다.",
  "베네지": "베네지브램블드래곤. 통명은 베네지로 불린다. 머리한쪽에 눈이 없어 붕대를 감고 다닌다. 붕대 속 본래의 모습은 보기가 힘들며 꼬리의 큰 가시에 맞으면 치명적인 상처를 입게된다.",
  "베놈 드래곤": "마공학의 정수로 태어난 곤충형 드래곤. 괴짜 마공학자가 의문의 드래곤을 육성하여, 새로운 모습으로 변신시켰다. 타입은 곤충으로 분류되나, 기계의 성질을 지니고 있으며, 중앙의 핵을 기점으로 움직인다. 인공지능으로 자아를 가진 것인지, 아니면 과거의 드래곤의 기억이 남아있는지 그 누구도 알 수 없다.",
  "베라드래곤": "고대 악의 기운이 깃들여진 드래곤. 위협적이게 돋아난 흑색의 뿔은 마력을 잠재우는 힘을 지녔다. 만만히 보고 육성하다간 큰 화를 입으니 정신을 똑바로 차릴 것! [ 획득가능: 미스터리 뽑기 ]",
  "베르나": "반짝이는 날개를 가진 매혹적인 드래곤. 별명은 광휘의 여왕. 세상을 감싸안는 따뜻한 모성을 지녔다고 한다. 거대한 악을 물리치기 위해 목숨을 잃었다. 다들 그렇게 알고 있었다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "베른하르트": "어린 시절부터, 자신과 함께 성장하는 도끼를 휘두르며 성장했다. 투지를 불태울수록 몸에 숨겨진 표식에 빛이 나며, 도끼도 그에 동조해 빛이나기 시작한다. 바다를 가를 정도로 강력한 도끼질로 앞을 가로막는 모든 장애물을 분쇄한다. [ 획득가능: 크리스마스 이벤트 ]",
  "베리스": "야간에 움직이는 야행성 드래곤, 늦은 밤이나, 이른 새벽에 종종 보이기 때문에 많은 사람들에게 알려져 있지 않다. 희소성이 높은 드래곤을 원하는 테이머의 목표가 되기도 한다.",
  "베타라": "눈이 퇴화하여 시각은 거의 이용하지 못하나, 다른 감각들이 발달했다. 그중 청각이 가장 많이 발달했다. 생명체가 있는 행성만을 골라 공격하며 생명체들을 감염시킨다. 감염된 생명체의 기운은 베타라에게로 점점 흡수되며 기력을 다하면 깊은 잠에 빠진다.",
  "베팔": "괴상한 생김새로 인해 몬스터로 취급된 비운의 드래곤. 그 이유는 날개가 달릴 부분에 괴상하게도 팔이 달려있다는 것이었다. 하지만 학자들의 오랜 연구 끝에 드래곤이라는 것이 증명되었고, 지금은 오히려 [드래곤과 환경]이라는 보고서에 들어갈 만큼 주요 연구대상으로 인기가 많다.",
  "베히모스": "무시무시한 생김새를 지닌 괴력형 드래곤. 흑요석 원석 같은 거친 피부에 수놓은 신비한 푸른 무늬가 보는 이의 마음에 기묘한 두려움을 자아낸다. 압도적인 크기만큼 뛰어난 전투력을 지녀, 경험이 풍부한 테이머들이 앞다투어 육성하고 싶어 한다.",
  "벨레드": "부정한 기운이 모여 탄생한 드래곤, 좋지 않은 기운을 타고난 이 드래곤은 언제나 분노해 있고, 난폭하기 때문에 주변의 드래곤 혹은 테이머 등이 보이면 이유를 불문하고 공격한다.",
  "보레아스": "신비로운 바람의 성역 북쪽에서 태어난 드래곤, 바람의 성역의 북쪽 지형은 깎아지는 절벽과 돌풍이 불고 있기 때문에 어떠한 드래곤도 자유롭게 날지 못한다. 오직 보레아스만 성역의 돌풍사이를 자유롭게 날아다닐 수 있다 [ 획득가능: 프리미엄 뽑기 ]",
  "보상이용": "6주년을 맞이한 드래곤 빌리지에 찾아온 환상의 드래곤. 드래곤 빌리지를 아주 열심히 즐긴 테이머에게만 찾아온다고 한다. 자신만의 특별함을 뽐내고 싶은 테이머에게 걸맞는 드래곤.",
  "본샤스 드래곤": "날 수 있으리라고 생각하기 힘든 드래곤. 전체적으로 '뚱뚱'한 느낌이라 나는 걸 처음 본 사람은 누구나 깜짝 놀란다. 사실 날 수 있는 것에 의미가 있을 뿐, 그다지 빠르진 않다.",
  "본헤드": "황랑한 사막같이 생명체가 거의 없는 곳에서 서식하며, 장난끼가 많다. [ 획득가능: 고룡 무덤 ]",
  "볼바": "지혜의 샘을 지키며 시험을 내리는 고대 드래곤이다. 찾아온 테이머에게 진실을 가려내는 시험을 부여하며, 손끝으로 별자리를 그려 점을 치는 능력을 지녔다. 샘가에 앉아 별빛을 해석하며 대륙의 운명을 살핀다.",
  "볼케이노": "라바드래곤과는 또 다른 형태의 용암 드래곤. 붉은 피부만큼 불에 익숙하며, 잘 다룰 줄 안다. 튼튼한 근육과 꼬리는 그에 상응하는 전투력을 보장한다. [ 획득가능: 미스터리 뽑기 ]",
  "부두룡": "마녀의 저주인형이 환생한 드래곤. 저주인형일때의 기억을 잊지 못하고 다른 자들을 저주하고 다닌다. 즐겨먹는것은 자신이 저주한 자들의 영혼.",
  "불나래": "꼬리 끝은 언제나 불꽃이 타오르고 있다. 불꽃 크기는 스스로 조절할 수 있으며 악의를 품지 않는다면 그리 뜨겁게 느껴지지 않는다. 평소 화가 나면 모든 것을 태워버리기 때문에 온화한 상태를 유지하기 위해 노력한다.",
  "불씨의 발칸": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 발칸은 여섯 수호자 중 불을 상징한다. 과거 여신을 노리는 다크닉스에 맞서 타오르는 화염의 힘으로 대적한 용감한 드래곤이다. [ 획득가능: 에스텔라 ]",
  "불의 고대주니어": "고대신룡과 엔젤사이에서 태어난 아들이다. 고대신룡처럼 정의롭지만 나이가 어려서 철이 없고 암컷드래곤들을 매우 좋아 한다.",
  "불의 다크닉스": "빛과 어둠의 시대, 신의 대행자로서 어둠의 세상을 수호하던 어둠의 수호자.",
  "불의 스마트 드래곤": "태어나면서부터 IQ가 뛰어난 드래곤이다. 책을 항상 갖고 다니는 이 드래곤은 책을 읽지 못하면 화가 나서 공격을 해버릴 수 있다. 책을 주웠다면 돌려주자.",
  "불의 스파인": "뾰족한 가시를 두르고 있고 호기심이 많지만, 가시 때문에 홀로 다니는 경우가 많다. 가시 안에는 맹독이 들어 있어, 한번 찔리면 치료가 불가능하다.",
  "불의 슬라임 드래곤": "바다의 요정이라 불리는 드래곤.하반신을 자유자재로 변형할 수 있다.더우면 몸이 흐믈흐믈 해져서싫어한다.",
  "붐버 드래곤": "장난기가 매우 심한 악동 드래곤에 속한다. 생김새가 흡사 폭탄과 같아 많은 이들이 두려워하지만 실제로 머리에 불을 붙인다고 해도 터지지는 않는다. 하지만 폭발에 맞먹는 기술인 익스플로전은 일격필살의 무시무시한 위력을 지녔다. [ 획득가능: 불의 산 ]",
  "브리트라": "혼돈의 정수로 인해 타락한 긴나라 드래곤의 수장. 앙그라에게 패배한 후, 심해로 달아났다. 거친 바다와 앙그라를 향한 증오심에 그의 몸과 마음은 크게 뒤틀려버렸다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "블라드": "생명체의 기운을 흡수하여 관에 담는다. 가슴의 균열을 열어 생명을 가진 모든 것들로부터 기운을 흡수한다. 흡수한 기운들은 모두 커다란 관 안에 전달되며, 관에 담긴 기운들은 블라드의 힘을 끝없이 증폭시킨다. 단순히 기운을 빼앗아가는 것을 넘어, 생명체의 흔적을 영원히 지워버리기도 한다.",
  "블랙쇼커": "안개 낀 높은 산맥에서만 사는 드래곤. 호랑이와 같은 생김새가 특징이며 이마의 문양은 동족을 확인하는 증표이다.",
  "블랙아머 드래곤": "과묵하고 무서운 생김새의 기사 드래곤. 겉보기에는 사납고 난폭해 보이지만 위험으로 부터 주인을 지키기 위해서는 자신의 목숨마저 건다고 알려졌다.",
  "블랙찡또": "몬스터 빌리지라는 세계에서 찾아온 이름 난 드래곤. 충성심과 용맹함이 그 어떤 드래곤보다 뛰어나다. GM 용순이 특별히 아낀 드래곤이라고 한다.",
  "블랙코어": "환상의 금속 퀄라로 만들어낸 드래곤. 강한 생명력에 반응하여 그 힘을 증폭시키는 퀄라는, 블랙코어의 힘을 더욱 강력하게 만들어준다. 등의 날개 크기에 따라 힘을 미리 가늠할 수 있다.",
  "블랙퀸": "고대의 흑마법사가 만든 마력의 드래곤, 도도한 여왕과 같은 태도로 적을 압박하며 쓰러트린다. 얼음 같은 눈매는 고혹적이며 차가워보이지만 테이머에게는 누구보다 살갑게 구는 성격이기 때문에 고생끝에 낙이 온다는 태도로 육성하는 것도 나쁘지 않다.",
  "블랙티어 드래곤": "사그라지지 않는 파멸의 불꽃을 지닌 드래곤. 암흑 드래곤들 중에서도 손에 꼽힐 정도의 강한 전투력을 지니고 있다 특히 지맥을 타고 솟구치는 강력한 검푸른 불꽃은 적의 의지마저 무너트리는 무시무시한 힘을 지니고 있다.",
  "블랙혼": "매우 사나워 보이지만 의외로 겁이 많고 온순한 드래곤. 하지만 조금이라도 마음에 들지 않는 것이 있다면 눈에 띄는 모든걸 부숴버리기 때문에 다가가기 어려운 것이 사실이다.",
  "블러디네이트": "한번 싸움을 시작하면 움직이는 모든 것을 파괴하기 전까지 멈추지 않는 무시무시한 드래곤. 장기인 피의 재앙은 어떠한 것도 태워 없애는 엄청난 위력을 자랑한다.",
  "블러디터스크": "온 몸이 피로 물든 것처럼 붉은 드래곤. 날카로운 송곳니에 물린 적은 온 몸의 피를 흡수당한다고 한다 [ 획득가능: 아르하의 입구 ]",
  "블레이드 드래곤": "온몸이 칼날인 드래곤. 바위를 두부 썰 듯 자른다. 칼날의 예리함은 친구와 적을 구분하지 않으니 조심하자. [ 획득가능: 어둠 제단 ]",
  "블레이즈 드래곤": "불멸의 불꽃을 지닌 수수께끼의 드래곤으로 강력한 뿔을 이용해 육탄정에 강하다. 날카로운 뿔의 끝에서 나오는 불꽃의 기운으로 화산의 뜨거운 열기에 강하고, 갈기는 마치 용암처럼 강렬한 열기를 뿜어낸다.",
  "블루라이트닝": "번개를 자유자재로 다루는 전기드래곤. 사냥하는 먹잇감에 정확히전기를 맞춰 포획한다. 특히 꼬리 부분에 닿으면 정신을 잃을정도의 전격을 경험하게 된다. [ 획득가능: 미스터리 뽑기 ]",
  "블루벨": "꽃과 함께 태어나는 드래곤. 그때문인지 언제나 몸에서 좋은 향기가 난다. 사실 블루벨은 몸에서 자라는 꽃의 이름이다.",
  "블루썬더": "푸른 번개라 불린 돌풍 드래곤. 매서운 돌풍 속에서 모습을 드러내기 때문에 쉽게 발견되지 않는다. 장기인 일렉트릿의 힘은 매우 강력하다.",
  "블리자드": "만년설에만 산다고 알려진 신비의 드래곤. 매서운 얼굴과 달리 주인에게는 상당히 자상한 편이라고 한다. [ 획득가능: 아르하 레이드 ]",
  "비어디 드래곤": "도마뱀 왕국의 왕위를 잇는 유일한 혈통 드래곤이다. 도마뱀 왕국 최초의 왕이자 동시에 멸망까지 왕좌에 앉았던 드래곤으로 기록된다. 가슴에 박힌 보석은 도마뱀 왕국의 혈통을 상징한다.",
  "빙설룡": "사람의 발길이 닿지 않는 머나먼 빙하의 땅에 존재하는 신비한 드래곤. 푸른 갈기와 보석과 같은 얼음 뿔의 아름다움은 드래곤의 능력 이전에, 드래곤 애호가들에게 높은 인기를 끌고 있다. 하지만 사람을 심하게 경계하여 만나기가 쉽지 않다고 전해진다.",
  "빙하고룡": "혹한의 추위와 냉기를 간직하고 있는 드래곤.모든 것을 얼려버리는 숨결을내뿜는다.공격성이 강하니 주의가 필요하다. [ 획득가능: 난파선 ]",
  "빛나는 바리안": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 바리안은 여섯 수호자 중 빛을 상징한다. 광명의 빛으로 최선을 다해 여신 레오나를 지킨 수호드래곤이며, 여섯 수호자의 우두머리이다. [ 획득가능: 에스텔라 ]",
  "빛의 G네 드래곤": "다리가 많은 다족룡의 한 부류. 땅속에서 주로 거주한다. 스타일에 민감한 드래곤답게 자신의 화려함을 자랑으로 여긴다.",
  "빛의 가디언": "어느 왕국의 왕실의 상징으로 사람을 잘 따르며 보호 본능이 뛰어나다. 오른손에 생기는 문양은 힘을 더욱 강력하게 만든다.",
  "빛의 골든혼": "같은 종족중에서도 수십년에 한번씩 태어나는 황금으로 된 뿔과 날개를 가진 드래곤이다. 그 뿔과 날개는 종족 중에서도 우월함을 상징하며 강한 힘의 원천이 되기도 한다.",
  "빛의 금오드래곤": "삼족오라는 까마귀와 비슷해서 지어진 이름이다. 날개가 3개, 눈이 3개이다. 세 번째 눈은 어릴 때 감겨 있는데 성장하면서 세 번째 눈을 뜨면 엄청난 말썽꾸러기가 된다.",
  "빛의 다크닉스": "빛과 어둠의 시대, 신의 대행자로서 어둠의 세상을 수호하던 어둠의 수호자.",
  "빛의 다크프로스티": "고위도 추운지방에 분포, 추운지방에 서식해서 몸에 깃털이 둘러져 있다. 프로스티 드래곤과 달리 혼자 생활하는 습성이 있다.",
  "빛의 데몽과가고일": "몬스터 세계에서 온 데몽과 그의 드래곤. 종족은 다르지만 둘은 항상 붙어 다니며 드래곤은 언제나 데몽의 지시에 따른다.",
  "빛의 레드와이번": "새끼일때는 순하지만 성체가 되고부터는 막무가내로 포악해지는 드래곤이다. 뜨거운 불 구덩이 주변에서 자주 볼 수 있는 와이번 중 하나이다.",
  "빛의 레이디 드래곤": "특이하게도 암컷만 태어나는 드래곤. 핑크빛의 색상이 특징이며 매우 온순하다. 눈빛이 매력적이다.",
  "빛의 머스타드해머": "턱근육이 굉장히 좋은 드래곤이다. 턱힘 하나로 바위도 으깰 수 있다. 성격은 온순하며, 다른 드래곤들을 잘 따른다.",
  "빛의 메탈 드래곤": "피부와 뼈가 모두 강철로 된 드래곤. 물은 매우 싫어하지만 불과 함께라면 힘이 배가 된다.",
  "빛의 메탈 마그넷": "머리, 팔, 다리, 날개가 자석과 같은 성질로 이루어져 있다. 배에 있는 버튼을 건드리는 걸 무척 싫어한다.",
  "빛의 뮤직 드래곤": "음악을 사랑하고 즐겨 부르는 드래곤 사실상 노래는 잘하지 못한다. 노래를 부를 때 나오는 초음파로 다른 드래곤들을 공격한다. 다른 용들은 귀가 아파 항복을 하기도 한다.",
  "빛의 미니 드래곤": "작은 고추가 맵다. 라는 속담처럼 작다고 무시하면 안 된다. 작은 성체로, 빠른 스피드를 낼 수 있다.",
  "빛의 미이라곤": "지하 던전 깊은 곳에 서식하는 드래곤. 몬스터 친구 가릴 것 없이 싸우는 것을 좋아해 상처가 마를 날이 없다.",
  "빛의 뱃도치 드래곤": "등에는 강력한 가시가, 꼬리에는 무시무시한 철퇴가, 이 드래곤을 상대하려면 엄청 곤욕을 치뤄야 할 각오를 해야 한다.",
  "빛의 베네지": "베네지브램블드래곤. 통명은 베네지로 불린다. 머리한쪽에 눈이 없어 붕대를 감고 다닌다. 붕대 속 본래의 모습은 보기가 힘들며 꼬리의 큰 가시에 맞으면 치명적인 상처를 입게된다.",
  "빛의 본헤드": "황랑한 사막같이 생명체가 거의 없는 곳에서 서식하며, 장난끼가 많다.",
  "빛의 블레이드 드래곤": "온몸이 칼날인 드래곤. 바위를 두부 썰 듯 자른다. 칼날의 예리함은 친구와 적을 구분하지 않으니 조심하자.",
  "빛의 샌드 드래곤": "불보다 뜨거운 사막에서 태어난 샌드 드래곤. 땅계열 같지만 그는 불계열이다. 불구덩이보다 뜨거운 모래로 상대를 잠재울 수 있다.",
  "빛의 샤크곤": "상어의 모습을 띄며 물속에서 생활한다. 까칠하고 까다로운 성격 때문에 주위에서 건드리기를 꺼려하며 강력한 악력으로 사냥과 공격을 한다.",
  "빛의 서펀트 드래곤": "매우 강력한 독을 가진 드래곤. 겉 모습만 보고도 다들 숨어버릴 정도라 몰래 뒤로 접근해 놀래켜 주기를 좋아한다.",
  "빛의 스마트 드래곤": "태어나면서부터 IQ가 뛰어난 드래곤이다. 책을 항상 갖고 다니는 이 드래곤은 책을 읽지 못하면 화가 나서 공격을 해버릴 수 있다. 책을 주었다면 돌려주자.",
  "빛의 스켈레곤": "독특한 외모 때문에 처음에 다들 무서워하지만 부끄러움이 많고 친해지면 장난기가 넘친다.",
  "빛의 스콜피온 드래곤": "전갈의 특징을 지니고 있는 드래곤이다. 꼬리 끝에는 독샘이 있고 앞발은 집게로 되어있어 전투 시 까다로운 드래곤 중 하나이다.",
  "빛의 스파인": "뾰족한 가시를 두르고 있고 호기심이 많지만, 가시 때문에 홀로 다니는 경우가 많다. 가시 안에는 맹독이 들어 있어, 한번 찔리면 치료가 불가능하다.",
  "빛의 슬라임 드래곤": "바다의 요정이라 불리는 드래곤. 하반신을 자유자재로 변형할 수 있다. 더우면 몸이 흐믈흐믈 해져서 싫어한다.",
  "빛의 윙스 드래곤": "바람을 자유자재로 움직이게 할 수 있는 윙스! 성체는 작지만 거대한 날개는 다른 드래곤에게 위압감을 준다. 멀리서 보면 날개에서 눈이 보이는 신비한 드래곤.",
  "빛의 유니드래곤": "붕대가 몸을 깜싸고 있고 뚜렷한 형태가 없다. 성장하면서 붕대로 자신의 형태를 만들어간다.",
  "빛의 크레센트": "달의 뿔과 밤의 피부를 가지고 있다. 달이 뜨는 밤을 매우 좋아한다. 누군가를 해치는 것을 별로 좋아하지 않는다.",
  "빛의 타이거드래곤": "태어날때부터 호랑이의 무늬와 비슷한 무늬를 가져 타이거 드래곤이라 불렀다. 이는 모든 드래곤들중 순발력이 가장 빠르고 경계심이 강하다.",
  "빛의 타투": "짙은 갈색의 문양을 몸에 새기고 있으며 성장 되면서 문양이 커지며, 힘을 잃으면 사라진다.",
  "빛의 파이어 드래곤": "불을 먹고 산다고 전해지는 드래곤. 주로 뜨거운 지역에서 생활하며 불을 좋아한다. 호전적이며 불같은 성격을 지녔다.",
  "빛의 프로스티": "고위도 추운지방에 분포, 추운지방에 서식해서 몸에 깃털이 둘러져 있다. 거의 집단으로 생활한다.",
  "빛의 해태드래곤": "해태의 의지를 물려받은 동양의 사신 중 하나이다.",
  "빛의 현무 드래곤": "거북과 뱀의 몸을 가진 동양의 사신 중 하나이다.",
  "빛의 흑룡": "사람들 눈에 잘 띄지 않는 곳에 서식하며, 길들이기 힘든 드래곤으로 알려져 있다. 탐험을 통해서 얻을 수 없는 스페셜 드래곤.",
  "빛의 히에나곤": "하이에나의 모습과 흡사하며 등에 네개의 날개가 있다. 강력한 네 발로 빠르고 오래 뛰며 앞 발톱의 힘이 강하다.",
  "삐에로 드래곤": "먼 타국에서 태어났다는 다소 우스꽝스러운 드래곤. 사실 웃긴 분장은 상대방을 방심하게 하는 묘책이며, 실제로 적과의 대치 상황에서는 누구보다 악랄하게 약점을 파고드는 모습을 보인다. [ 획득가능: 미스터리 뽑기 ]",
  "사나래": "사족이 모두 응축된 바람의 힘이 잠든 폭풍형 드래곤. 사족에 닿는 모든 사물이 강력한 폭풍에 몰아치며 먼지가 되어 사라진다. 성격이 상당히 고약하기 때문에 훌륭한 솜씨의 드래곤 테이머가 아니라면 고생이 심하니 주의할 것!",
  "살라": "깊은 밤의 악몽을 불태우는 드래곤. 몸을 감싸고 있는 푸른 화염이 착한 아이의 꿈에 끼어든 어두움을 불태운다고 전해진다",
  "샌드 드래곤": "불보다 뜨거운 사막에서 태어난 샌드 드래곤. 땅계열 같지만 그는 불계열이다. 불구덩이보다 뜨거운 모래로 상대를 잠재울 수 있다. [ 획득가능: 불의 산 ]",
  "샤크곤": "상어의 모습을 띄며 물속에서생활한다. 까칠하고 까다로운 성격때문에 주위에서 건드리기를꺼려하며 강력한 악력으로 사냥과공격을 한다. [ 획득가능: 난파선 ]",
  "샤프테일 드래곤": "꼬리가 칼날같이 날카로운 드래곤. 전투할 때 강력한 무기로 사용한다. 성격이 굉장히 거칠고 사나워 함부로 다가가면 크게 다칠 수도 있다. 화이트썬더 드래곤과 '매우' 사이가 나쁘다.",
  "샤흐": "항상 테이머의 명령을 따르며 복종하는 드래곤. 다른 드래곤들 앞에서는 리더로서의 모습을 보여주나 앞장서서 행동하다 위험에 빠지는 경우가 많다.",
  "샬롯": "과일을 좋아하는 컵케이크 드래곤, 몸에 두르고 있는 과일은 매우 달콤한 향기가 나서 주변에 있는 사람들이 행복해진다고 한다. 쓴맛이 나는 것을 매우 싫어한다.",
  "샴 드래곤": "태생부터 두 개의 머리와 자아를 가진 희귀한 드래곤이다.두 개의 자아는 극적으로 다른 성향을 보이지만 적을 공격할 때에는 협동을 하여 공격한다.",
  "섀도우드래곤": "오래전 버려진 드래곤의 알에서 어둠의 정기를 머금고 태어난 드래곤. 태생이 어두운 만큼 사물에 대한 적개심도 높다. 내뿜는 어두운 숨결은 모든생명체에게 치명적이다. [ 획득가능: 미스터리 뽑기 ]",
  "서펀트 드래곤": "매우 강력한 독을 가진 드래곤. 겉 모습만 보고도 다들 숨어버릴 정도라 몰래 뒤로 접근해 놀래켜 주기를 좋아한다. [ 획득가능: 나무 던전 ]",
  "선셋 드래곤": "아름답다고 소문난 오색빛의 드래곤. 아름다운 생김새로 많은 테이머들이 목표가 된다고 알려졌다.하지만 워낙 의심이 많아 쉽게 친해지긴 어렵다.",
  "선인장 드래곤": "수많은 선인장의 염원이 담겨 태어나게 된 드래곤. 항상 바쁘게, 누구보다도 빠르게 살던 그들의 소원은 다름아닌 게으르게 지내는 것이었다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "설리반": "용의 보옥에서 태어나, 아름다운 깃털로 적을 현혹하는 드래곤. 자신 외의 모든 것이 아름답지 않다 생각하며 항상 눈을 감고 다닌다. 소문에 의하면, '현명함의 사도’를 만날 때만 눈을 뜬다고 한다.",
  "세에레": "테이머들의 꿈을 먹으며 살아가는 드래곤. 꿈을 먹는다고 해도 테이머에게 피해를 끼치지는 않으며 단순히 양분만을 얻어가며 살아간다. 다채로운 색상의 날개와 꼬리는 전날 밤에 흡수한 꿈을 표현한다고 전해진다. [ 획득가능: DVNew 이벤트 ]",
  "세찬 라이오스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 라이오스는 여섯 수호자 중 바람을 상징한다. 폭풍과 같은 능력으로 최선을 다해 여신 레오나를 지킨 수호 드래곤이다. [ 획득가능: 에스텔라 ]",
  "세크레타": "여명과 황혼의 주인인 아실리와 옵타툽을 지키는 세 마리의 수호자 드래곤 중 하나. 세크레타는 창과 같은 팔로 적을 백발백중으로 공격했다. 지혜롭고 어진 성격으로 누구보다 재앙의 밤인 크레바스에 맞서 꿈의 세계를 지키기 위해 애썼다. [ 획득가능: 왕궁방어전 ]",
  "센투라": "라테아를 지키는 드래곤들의 왕. 화염의 군단 아프리트들과 함께 오랜 세월 드래곤의 성역 라테아를 지켜왔다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "셀마사": "해가 떠오를 무렵에만 발견할 수 있는 드래곤. 아침 해를 받은 등이 반짝거리기 때문이라고 한다. 그 외 시간에는 그림자에 숨어 다닌다고 할 정도로 눈에 띄지 않는다. 상세한 정보가 많이 밝혀지지 않은 드래곤.",
  "소서러 드래곤": "신비로운 영적 주술을 다루는 드래곤. 광활한 대지를 모시는 신앙을 가지고 있으며 가끔 제사를 올리는 모습이 목격되었다. 그들이 다루는 '주술'이라는 힘은 아직 수수께끼가 많다.",
  "소울": "찬란한 푸른빛의 뿔을 지닌 마력형 드래곤. 신비의 푸른 뿔과 불타는 붉은 갈기는 기묘한 마력의 힘이 느껴진다. 뛰어난 테이머가 아니라면, 이 까다롭고 기품 있는 드래곤을 육성하는 꿈은 조금 뒤로 미루자.",
  "솔라": "영롱한 태양의 빛을 지닌 드래곤. 만물에게 빛을 전해주는 태양처럼 따스한 힘을 지녔으며 매우 온화하고 자비로운 성격이다.",
  "솔루카니스": "해와 달을 가지기 위해 유타칸을 찾은 수호 드래곤이다. 재앙을 거두는 힘이 있는 드래곤으로 자신의 몸을 희생하여 재앙을 막아낸다.",
  "수라 드래곤": "파괴의 힘을 지니고 있는 강력한 폭열성 드래곤. 영원히 불타오르는 염화의 힘을 지닌 존재로 만물을 조화롭게 조율하며 생명을 지키는 영겁의 수호자. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "수룡": "물속에서 살아가는 드래곤.호수나 바다에서 물고기를 먹으며 살아간다.온순한 성격에 다른 동물들과도 잘 어울릴 줄 안다. [ 획득가능: 난파선 ]",
  "순둥곤": "동글동글한 생김새가 웃긴 드래곤. 매사를 둥글둥글하게 취급하며 살아가기 때문에 전투하는 경우가 적다. 일부 특이한 용 애호가들 사이에서는 애완용으로 인기가 많다. [ 획득가능: 미스터리 뽑기 ]",
  "술래": "악몽의 기운이 가득한 둥근 호리병 속에서 태어나는 드래곤. 술래의 몸은 끈적한 액체로 이루어져 있어 상황에 따라 몸의 형태를 자유롭게 변화시켜 호리병 속으로 숨을 수 있다. 호리병 안은 한계를 알 수 없을 만큼 크다고 알려져 있다.",
  "쉐도우 드래곤": "오래전 버려진 드래곤의 알에서 어둠의 정기를 머금고 태어난 드래곤. 태생이 어두운 만큼 사물에 대한 적개심도 높다. 내뿜는 어두운 숨결은 모든생명체에게 치명적이다.",
  "쉔": "높은 고원지대, 차가운 극 지대에서만 서식하는 드래곤. 태어날 땐 밝은 푸른색을 띠며 나이가 들수록 짙은 색을 띤다고 한다. 그들은 몇몇을 제외하곤 꽤 친화적인 성격을 지녔다. 그들이 사는 지역은 맑은 날보다 우중충하고 어두운 날이 더 많다. 흰색 고리 무늬는 개체마다 모양이 조금씩 다르며 등과 다리에 존재하는 딱딱한 피부는 단단한 내구성을 자랑한다. 그들의 하얀 갈기는 마치 실크를 만지는 듯 부드러운 재질이다.",
  "쉴로시": "봉인의 열쇠로 흡수의 서와 방출의 서를 하나로 합쳐 순환의 서를 되찾고자 하는 사명을 지니고 있다. 순환의 서에 대한 정보를 일절 발설하지 않기 때문에 순환의 서에 대해서는 어떠한 것도 알려진 바가 없다.",
  "슈넬 드래곤": "저주받은 드래곤. 원래는 흰색의 아름답고 날렵한 드래곤이었다고 한다. 하지만 다크닉스에게 장난을 치다가 붙잡혀 그 누구도 얼굴을 볼 수 없는 저주를 받았다고 한다.",
  "슈팅스타": "신비한 고산에 머물며 자신의 가족을 부양하는 터잡이 드래곤. 한군데 서식지를 정하면 반드시 그 장소에 머물다 생을 마감하는 고집스러운 면이 돋보이는 드래곤이다. 전통을 중시하는 만큼 고리타분한 면도 다수 있다. [ 획득가능: 미스터리 뽑기 ]",
  "스노우볼": "자신의 몸통보다 더 큰 공을 굴리고 놀았지만, 몇번의 크리스마스가 지난 후에 스노우볼은 공보다 훨씬 커졌습니다. 하지만 어릴 때부터 가지고 놀던 공은 여전히 스노우볼이 가장 좋아하는 장난감입니다. [ 획득가능: 크리스마스 이벤트 ]",
  "스마트 드래곤": "태어나면서부터 IQ가 뛰어난드래곤이다. 책을 항상 갖고 다니는 이드래곤은 책을 읽지 못하면 화가 나서 공격을 해버릴 수 있다. 책을 주웠다면 돌려주자. [ 획득가능: 옛 성터 ]",
  "스왈로우": "사냥 능력이 매우 뛰어난 드래곤. 스왈로우는 뛰어난 사냥 실력을 지닌 드래곤으로 날개와 꼬리를 적극 활용하여 먹이를 포획한다. 실패라는 단어를 모르는 완벽한 사냥꾼이다.",
  "스왐프 드래곤": "물속에서 숨어있다가 먹이가 발견되면 재빨리 나와 잡아먹는다. 꼭 육군의 탱크처럼 생긴 스왐프 드래곤은 육지에서는 어느 드래곤보다 월등하다. 못생겼다고 놀리면 화를 낸다. [ 획득가능: 무지개 동산 ]",
  "스워드": "태양계를 수호하는 빛의 드래곤. 행성이 위험에 빠지면 위기에서 구해준다. 태양계을 수호하는 대가로 행성을 닮은 검을 사용할 수 있다고 한다.",
  "스윗클라우드": "마치 솜사탕 같이 생긴 불꽃에 휩싸인 드래곤. 보기만 해도 달콤해보이는 그 모습에 섣불리 다가서다 화상을 입은 자들도 많다. 몸이 굉장히 가벼워 바람을 타고 여행하는 방랑 드래곤.",
  "스카투스": "수련을 거듭할수록 강해지는 괴력 드래곤이다. 이마의 뿔과 꼬리 끝에서 뿜어져 나오는 보라색 불꽃에는 치유의 힘이 있다. 따라서 스스로 자신의 몸을 치유하면서 게속 공격을 퍼부어서 상대를 쓰러트린다. 대부분의 경우 스카투스는 악의 없이 자신의 힘을 시험하려고 싸우기 때문에 대결이 끝난 후에는 상대의 상처를 치유해 주기도 한다.",
  "스카트": "네뷸라의 인도 아래 외우주를 떠돌아다니는 드래곤들 중 하나. 깨지지 않는 긴 몸에 우주의 흐름을 담고 있다. 몸을 움직일 때마다 물이 찰랑거린느 것만 같은 별의 소리가 들린다.",
  "스칼렛": "종종 길을 잃어버린 아이 주변에서 목격된다. 숲과 어울리지 않는 붉은색을 띠고 있으나, 숨어 살기 때문에 목격이 힘들다. 주로 목격되는 경우는 숲에서 길을 잃은 아이 주변을 맴돌며, 아이를 위험에서 보호해 주는 모습을 보여주곤 한다.",
  "스케어": "겁이 많은 드래곤. 유령을 볼 수 있으며, 그 유령으로 적을 공격한다. 그리고 그 유령을 제일 무서워한다.",
  "스켈레곤": "독특한 외모 때문에 처음에 다들 무서워하지만 부끄러움이 많고 친해지면 장난기가 넘친다. [ 획득가능: 나무 던전 ]",
  "스콜피온 드래곤": "전갈의 특징을 지니고 있는 드래곤이다. 꼬리 끝에는 독샘이 있고 앞발은 집게로 되어있어 전투 시 까다로운 드래곤 중 하나이다.",
  "스쿠룸": "태초에 존재했던 신비의 성, 파라디수스를 지키던 최후의 수호 드래곤. 불의 힘을 사용했으며, 성난 불의 장벽은 그 어떤 악도 용서치 않았다고 전해진다. [ 획득가능: 미스터리 뽑기 ]",
  "스쿨드": "등 뒤의 날개 조각들은 평소엔 우아한 날개의 형상을 띠지만, 전투시에는 거대한 차크람의 형태가 되어 부정적인 존재를 베어넘긴다. 세계수의 뿌리가 오염되지 않도록 전당의 신성함을 유지시킨다.",
  "스킨크 드래곤": "모래 속에 숨어 상대의 약점을 노리는 도마뱀 드래곤이다. 다른 드래곤 및 생명체의 침입조차 허용하지 않았으며, 발견한 상대는 즉시 땅 깊은 곳으로 끌어내린다고 알려진다.",
  "스타에이스": "오랜 시간 동안 유타칸을 수호한 자에게 찾아오는 신비로운 드래곤. 별빛과도 같이 찬란히 빛나는 그 모습은 어떠한 어둠도 물리칠 수 있다. [ 획득가능: 300일 출석체크 ]",
  "스탑튠": "석상의 모습을 한 드래곤. 신이 내린 드래곤이라고 불리운다.",
  "스터드 드래곤": "패트 드래곤과 마찬가지로 가장 무겁다고 전해지는 수륙형 드래곤. 워낙 큰 덩치 덕에 껍질 속에 몸을 숨기고 있으면 하나의 작은 섬이라 보이는 경우가 많다. 하지만 등의 철갑은 특이한 온도를 지니고 있어 금세 깨닫고 줄행랑을 치는 행인이 더 많은 편.. 신기하게도 이 등껍질은 자신의 호감 있는 상대에게는 뜨겁게, 미워하는 자에게는 차갑게 온도가 변화된다고 알려졌다. [ 획득가능: 별빛 산호초 ]",
  "스테고드래곤": "매력적인 흑색 보석으로 몸이 이루어진 보옥형 드래곤. 이 신비한 보석은 상대방에게 두려움을 불러일으키는 힘을 지녔다. 단 자신보다 강한 상대에게는 아무런 효과가 없다. [ 획득가능: 미스터리 뽑기 ]",
  "스텔스": "기억을 흡수하고 조작할 수 있는 수호 드래곤이다. 빛과 어둠의 전쟁 당시, 수많은 드래곤들의기억을 조작하였다는 이유로 기억의 신에게서 퇴출당했다. 그림자 세계에서 그림자 여신에게 은신의 축복을 받았다.기억의 신과 그의 수호 드래곤들은 스텔스의 존재를 잊게 되었고, 스텔스는 그림자 세계뿐만 아니라 다른 지역에서도 모습을 유지할 수 있게 되었다.",
  "스트라": "둘로 나뉜 순환의 서 중, 방출의 서를 갖고 있는 드래곤. 동생이 가둔 생명들을 불쌍히 여겨 풀어주려한다. 문제는, 자기 마음대로 내보내는 것이 동생보다 더한 악동이라는 평이 있다.",
  "스트라이커": "섬광의 창이라는 이명으로 더 알려진 드래곤. 전신을 수놓은 강력한 번개의 힘은 그 어떤 적도 일격에 멸할 수 있다. 개체의 수가 한정적인 멸종 위기 드래곤으로 협회에서는 무분별한 드래곤 알 채취를 금지하고 있다.",
  "스틸윙": "강철의 날개를 지닌 강화 드래곤. 마공학의 비술로 강화된 다목적 드래곤으로, 수호 기사를 돕거나 다양한 특수한 임무를 수행하기 위해 육성되었다. 마법 금속으로 만들어진 강철 날개는 깃털처럼 가볍지만 그 어떤 물질보다 튼튼한 방어력을 제공한다.",
  "스파이시": "태초에 빛과 어둠이 대립하던 시기에존재한 매우 강력한 고대 드래곤.과거 빛과 어둠의 대전투에서고대신룡을 도와 다크닉스를봉인시켰다.또 다른 이름으로는 광명의지배자라고 알려졌다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "스파이크 드래곤": "온 몸에 뾰족한 피부 조직을 가지고 태어나는 스파이크 드래곤이다. 단단한 피부를 가지고 있어 어떠한 공격에서도 든든한 방어 형태가 형성된다. [ 획득가능: 메마른 평원 ]",
  "스파인": "뾰족한 가시를 두르고 있고 호기심이 많지만, 가시 때문에 홀로 다니는 경우가 많다. 가시 안에는 맹독이 들어 있어, 한번 찔리면 치료가 불가능하다. [ 획득가능: 무지개 동산 ]",
  "스플렌더 드래곤": "화려한 색을 지닌 용. 아름다운 깃털로 상대방을 방심하게 만든 뒤 무시무시한 공격을 퍼붓는다. 작은 체구의 용인 만큼 공격과 수비의 전환이 빠르다.",
  "슬라임 드래곤": "바다의 요정이라 불리는 드래곤.하반신을 자유자재로 변형할 수 있다.더우면 몸이 흐믈흐믈 해져서싫어한다. [ 획득가능: 난파선 ]",
  "슬레이어": "뛰어난 검술 실력을 지닌 기사 드래곤. 맹렬하게 타오르는 불꽃의 검술로 적을 물리친다. 다양한 전투 상황을 승리로 이끌 수 있다. 다만 비가 오는 날에는 큰 힘을 발휘하지 못한다.",
  "슬레이프니르": "세계수와 같은 생명력이 몸에서 깨어난다. 3쌍의 다리, 6개의 발굽이 닿는 자리마다 생명의 기운이 솟구쳐 메마른 땅도 풍요의 터전으로 바뀌며, 모든 동식물이 살기 좋은 땅이 된다. 생명력을 퍼뜨리는 것을 사명으로 생각하기 때문에 세계수의 힘이 닿지 않는 험지나 오염된 지역을 찾아서 그곳을 치유하고 회복시킨다.",
  "슬리즈 드래곤": "깊은 동굴 속에서 사는 드래곤. 눈이 작아진 대신 빛을 감지하는 능력이 굉장히 뛰어나다. 꼬리에는 맹독이 있어 이걸로 사냥감을 마비시킨 뒤 한입에 삼켜버린다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "시그마 드래곤": "심판자 또는 대자연의 생명이 주축인 에테르의 양면성의 존재. 시그마는 에테르의 어둠을 상징한다. 평소에는 에테르의 틈새에 머무르다,생명의 균형이 무너져 그 한계에 다다를 때, 강림한다고 전해진다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "시리스": "인드라 드래곤의 일원이자 아스티의 오랜 친구. 인드라문의 전통에 따라 추방당한 아스티를 감싸준 유일한 존재였다. 다만 친구를 감쌌을 뿐 인드라문의 전통을 저버린 것은 아니다.",
  "시소르": "녹색의 날개를 가지고 창공을 나는 드래곤. 바람을 타고 나는 것에 있어 그 누구보다 능하다고 일컬어지는 드래곤이다. 애교가 많고 귀여운 성격으로 친해진 테이머에게는 장난조차 치지 않고 헌신한다 [ 획득가능: 지하성채 ]",
  "시타엘": "금빛 투지를 내뿜는 강력한 신성 드래곤. 전투 시 다양한 병기로 적의 사각을 노리는 노련함이 특징이다.",
  "식스 레그 혼 드래곤": "다리가 6개인 매우 특이한 드래곤으로 온순한 성격으로 사람들에게 인기가 많다. 머리 위에 뿔이 특히 매력적이다. 나는 것보다 뛰는 것을 좋아한다. [ 획득가능: 바람의 신전 ]",
  "썬더레인 드래곤": "날개가 완전히 퇴화해 땅을 걸어다니는 드래곤. 하지만 온 몸에 두른 번개의 힘인지 엄청난 속도로 달릴 수 있다. 분노하면 마치 비가 쏟아지듯 하늘에서 번개를 흩뿌린다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "썬더버드": "번개를 조종할 수 있으며 스스로 번개를 생성하는 드래곤.태어날 때는 정전기 수준의 전력을 가지고 있지만 성체가 되면 주변을 잿더미로 만들 정도로 강력한 전기를 만들어낸다.코에 충전지 같은 역할을 하는 기관이 있어 위급할 때 여비 전력으로 사용할 수 있다.꼬리는 도마뱀처럼 위급할 때 끊어뜨릴 수 있지만 재생할 때는 다른색의 꼬리가 자라난다.",
  "아그나드": "고대 현자의 지혜와 뛰어난 기술자의 손으로 탄생하게 된 마공학 병기.드래곤을 닮은 기계라 착각하겠지만, 놀랍게도 감정을 가지고 있다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "아누라다": "마카라에 충성을 바치는 이 사악한 드래곤들은 여러 행성을 파괴하며 엘베스타 성계전역에 악명을 떨쳤다.",
  "아델라": "디트가 새로운 마공학 회로를 도입해 만든 병기. 안타깝게도 메모리가 부족해 언어 회로는 집어넣지 못했다고 한다. 비록 말은 못하지만 정의감만큼은 누구에게도 뒤지지 않는다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "아라카": "과거 빛과 어둠의 전쟁 당시 고대신룡을 수호한 기사 드래곤.막강한 힘과 바람의 투지는 고대신룡을 노리는 모든 존재에게 커다란 공포를 선사했다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "아르고 드래곤": "심판자 또는 대자연의 생명이 주축인 에테르의 양면성의 존재. 아르고는 에테르의 빛을 상징한다. 평소에는 에테르의 틈새에 머무르다, 생명의 균형이 무너져 그 한계에 다다를 때, 강림한다고 전해진다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "아르주나": "사악한 영혼을 정화하는 불을 지닌 드래곤. 카데스의 꿈을 엿보다가 뿔을 빼앗기는 바람에 그 힘의 대부분을 잃고 만다. 이를 가엾게 여긴 마이아 아오라는 창조신에게 기도하자, 새 뿔이 돋아났다.힘을 회복한 아르주나는 이제 카르나와 운명의 결전을 준비하고 있다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "아르켈론": "깊은 바닷속에 살다가 배를 전복시키는 괴력 드래곤이다. 항상 항해하는 이들을 괴롭히고자 하는 마음만 가득한 드래곤이다. 깊은 바닷속에 살아 발견하기 어렵지만 항해하는 이들에겐 종종 발견된다고 한다.",
  "아르테미스 드래곤": "달의 여신의 이름을 가진 드래곤. 여신이 내려준 달빛을 받아 태어났다는 전설이 있다. 원래는 발견하기 매우 힘들지만 일년 중 가장 달이 밝은 날에는 반드시 모습을 드러낸다. [ 획득가능: 챔피언 대전 ]",
  "아만타": "다른 차원에서 넘어온 이차원의 드래곤. 그쪽 차원에서는 '드래곤'이 아니라 다른 이름으로 불린다고 들었지만 기억이 나지 않는다. 인간 세계에 간섭하는 것을 경계하지만 인간의 힘으로 극복할 수 없는 위기가 닥쳐오면 모든 부정한 것들을 정화하는 기운을 내뿜으면서 세상을 수호한다.",
  "아말테아": "네뷸라의 인도 아래 외우주를 떠돌아다니는 드래곤 중 하나. 아말테아의 꼬리는 행성의 고리를 만들어내며, 아말테아의 뿔은 행성에 풍요로움을 불러와 풍요의 뿔로 불린다. 3개의 머리는 현명한 지혜를 가지고 있어 아말테아 앞에서는 거짓을 이야기할 수 없다고 한다.",
  "아바돈": "멸망을 부르는 시면의 왕으로 불리는 드래곤이다. 선과 악을 구분하지 않으며 마주하는 모든 것을 파괴하고자 한다. 세상을 멸망시킨 뒤 자신도 파멸하길 꿈꾼다.",
  "아브밸리": "미지의 힘을 지닌 마력형 드래곤. 하늘거리는 에메랄드빛 갈기와 타오르는 듯 흐르는 금색의 날개는 모두를 홀리는 신비한 힘을 지녔다. 흑색 뿔에 영생의 비밀이 있다고 전해지지만 그 진실은 누구도 알 수 없다.",
  "아비스": "나무와 공존하는 드래곤. 한겨울에 한자리에 앉아 쉬고 있으면 유타칸의 어린이들은 기념일에 장식을 달아준다. 아비스가 머물고간 자리는 아주 커다란 나무가 자라난다고 한다.",
  "아비온": "매우 거대한 날개를 가진 드래곤.바람을 타는 것을 좋아하며 매우 빨라서 바람과 비슷한 속력으로 이동할 수 있다. 테이머를 태우는 것을 좋아해 먼 거리를 이동하는 테이머들이 자주 키운다.",
  "아스타테": "세계수를 지키는 인드라 드래곤의 수장. 태초의 마귀 크로낙과 치열하게 싸우며 끝내 승리를 거머쥔다. 원래 질서와 전통을 지키는 일에 힘을 쏟았지만, 요즘은 과연 이 길이 맞는가 의심하고 있다.",
  "아스트라이나": "오로라에서 태어났다고 전해지는 드래곤. 그 말대로 오로라를 볼 수 있는 밤에만 알을 찾을 수 있다고 한다. 몸에 박힌 보석이 매우 귀해 많은 이들이 찾는다고 한다.",
  "아스티": "빛과 어둠의 전투 당시, 고대신룡을 존경하던 귀여운 생김새의 드래곤. 강한 힘을 지니지 않았으나, 따뜻한 마음씨로 많은 드래곤들의 사랑을 받았다. 어둠의 세력이 빛의 세력의 땅을 급습하던 당일, 어린 드래곤들을 지키기 위해 홀로 다크닉스에게 대적하다. 패배하고 빛이 되어 사라진다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "아실리": "꿈의 틈새에 살아간다고 전해지는 환상형 드래곤. 금과 백으로 빛나는 몸과 성스러운 뿔은 사악한 악을 반드시 멸한다. 꿈과 현실이 하나가 될 때 위기를 막고자 세상에 나타난다고 전해진다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "아이가스": "태초에 존재하던 타오르는 불꽃의 드래곤.세상을 구했다는 전설이 남아있지만 어째서 지금 깨어나게 되었는지는 아무도 모른다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "아이스 드레이크": "차가운 빙결의 틈새에서 서식하는 드래곤. 칼날처럼 돋아난 푸른 지느러미와 주변의 물줄기는 외부로의 접촉을 거부한다. 멋진 생김새와 달리 매우 난폭하니, 신중히 육성하는 것이 좋다.",
  "아이언 드래곤": "망각의 기록 저편에 존재했던 환상의 드래곤.홍옥의 마력과 피와 같은 피부에대조되는 칠흑의 갑피를 지녔다.불의 시초 또는 불의 화신으로 불렸으나 그 정보는 정확하지 않다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "아자크": "태초의 빛과 어둠의 전투 당시, 수많은 악의 종자에 대항하기 위해 창조된 수호자 드래곤. 운명의 신의 예지 아래에 만들어진 마공학 드래곤으로 빛의 첫 번째 자손을 숭상하며 악을 물리쳤다",
  "아카이아": "강한 날갯짓으로 들판의 풀을 통째로 뽑아낼 만큼 강력한 바람을 만들어내는 신성한 드래곤이다. 전신을 뒤덮은 부드러운 털은 신성한 기운을 품고 있어, 악한 기운이 담긴 공격을 자연스럽게 튕겨낸다.",
  "아쿠아 드래곤": "해마곤과 마찬가지로 깊은 바다에서 살아가는 심해 드래곤. 과거에는 육지에 살았으나, 아름다운 별빛 용 가죽을 노리는 많은 수렵꾼들에 의해 바다로 도망쳐 심해 생활에 적응하게 되었다 [ 획득가능: 미스터리 뽑기 ]",
  "아쿠아리움": "바다 깊은 곳에 사는 드래곤. 항상 물고기에 둘러싸여있다.바다의 어머니 같은 역할을 하며 바닷속 생물들을 돌봐준다고 한다.",
  "아쿠아펄": "진주조개 속에서 살아가는 드래곤.진주로 된 장신구를 노리는 사람으로 인해 진주조개 속에 들어가서 생활하게 되었다고 한다. ​들고 다니는 진주 속에는 파도를 다스릴 수 있는 강력한 마력이 있다.​ | 원작자 : PEPE♡ |",
  "아톤": "고대의 마법룬을 사용하는 드래곤. 마력으로 이루어진 날개와 몸에 돋아난 마법룬은 적들의 공격을 쉽게 방어하게 해준다",
  "아틀란티스": "머나먼 기억 속에 잠든 도시의 수호자. 긴 세월 동안 그 정체가 밝혀지지 않아 수수께끼에 감추어졌던 존재이다. 신비한 힘을 지닌 문양은 강한 물보라를 일으켜 수많은 적을 물리칠 수 있다. 선한 성격이지만, 자신의 영역에 침범하는 존재는 절대 용서치 않는다.",
  "아폴로누스": "강력한 화염을 무기로 사용하는 폭열성 드래곤. 잘 단련된 근육질의 몸매와 날렵한 움직임이 최고의 무기. 불 속성 드래곤 치고는 상당히 장난스러운 성격이다.",
  "아프로디테": "모든 것을 아름답게 바꿔준다. 아름다움이 메마른 생명체와 장소를 향해 수많은 화살을 쏜다. 아프로디테의 화살을 맞은 생명체는 겉뿐만 아니라 마음도 아름다워진다. 아프로디테가 선사한 아름다운 마음을 지니게 된 생명체는 모든 것을 꽃처럼 아름다운 것으로 본다. 땅에 화살이 꽂히면 꽃밭이 된다.",
  "아프리트": "성역 라테아의 불꽃 드래곤 군단. 모든 아프리트들은 서로 정신적으로 연결되어 있으며 센투라의 의지에 절대 복종한다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "알데바란": "네뷸라의 인도 아래 외우주를 떠돌아다니는 드래곤들 중 하나. 크고 거대하고 우람한 뿔과 광륜에서 뿜어져 나오는 빛에 자부심을 가지고 있다. 모든걸 이끌며 주목받고 싶어 하다 보니 레굴루스와는 항상 경쟁하는 사이가 되었다. [ 획득 가능: 프리미엄 뽑기 ]",
  "알레샤": "네뷸라의 인도 아래 외우주를 떠돌아다니는 드래곤들 중 하나. 화려하고 아름다운 프릴같은 꼬리는 별의 흐름을 보여준다.",
  "알리스 드래곤": "신체에 비해 매우 거대한 날개를 가진 드래곤. 날갯짓을 한번 할 때마다 주변에 돌풍이 몰아친다. 매우 소심한 성격이라 그때마다 주변에 잊지않고 사과한다. [ 획득가능: 미스터리 뽑기 ]",
  "알투스": "극한의 기온에서도 견디는 털과 지방을 가진 드래곤. 일년 내내 눈보라가 몰아치는 혹한의 설산에서 볼 수 있다.",
  "암두시아스": "은빛 일각를 가진 드래곤, 작곡가로써의 면모를 가지고 있으며 오케스트라 연주는 나무를 움직이는 신비로운힘을 가지고 있어 나뭇가지와 잎사귀가 음악에 맞춰 춤춘다고 한다.",
  "암흑의 발로드": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 발로드는 여섯 수호자 중 어둠을 상징한다. 강력한 어둠의 힘을 조종했으며, 누구보다 레오나를 위했던 드래곤이었다고 전해진다. [ 획득가능: 에스텔라 ]",
  "앙그라": "먼 과거에 존재하던 고대 드래곤들의 왕. 카데스와 맞서싸운 용감무쌍한 왕이었으나 그 오만한 성격으로 인해 신의 미움을 사 봉인당하고 만다. 빛과 어둠의 전쟁으로 봉인이 약해져 최근 눈을 뜨게 된다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "애니마라": "영혼의 날개를 가진 공포의 드래곤, 영혼의 날개에 스쳐지기만 해도 빠져나올 수 없는 영원의 악몽 속에서 헤어나올 수 없게 된다.",
  "애플칙": "깊은 숲에서만 모습을 보이는 요정 드래곤. 재빠르고 머리가 좋아 많은 사람들을 골탕 먹이지만 상당히 겁이 많아 자주 모습을 보이진 않는다. [ 획득가능: 토너먼트 루키 ]",
  "액스칼리버": "무수히 많은 검을 다루는 드래곤. 빛과 푸른 불꽃으로 이루어진 검으로 적을 베어버리며,원하는 형태의 빛의 검을 소환할 수 있다. 발과 등에서는 푸른 불꽃이 타오르는데 평소에는 근처의 것들이 타지 않지만 액스칼리버 자신이 태울 마음이 있는 자들에게만 불이 붙는다. 털은 찬란한 은빛으로 번쩍이며 갑옷은 매우 희귀하고 단단한 물질로 이루어져 있다고 전해진다.",
  "앳지버": "신비한 꼬리를 가진 드래곤. 성격은 장난스러우면서도 대단히 사납다. 꼬리에 달린 눈은 장식이 아닌 실제 눈이라 꼬리를 활용한 공격 명중률이 대단히 높다고 한다.",
  "앵커": "『생김새가 닻을 본뜬 이 드래곤은 어릴때부터 무게가 엄청 무겁다. 움직임이 느려 여기저기 다니면서 훈련하기가 힘들다. 앵커의 발톱은 길고 하나밖에 없으며 자신의 무게를 감당할 수 있도록 단단하지만 다시 자라나지 않는다. 대신 낡은 닻으로 새로운 발톱을 만든다. 발톱이 부러지면 다시 자라지 않기 때문인지 앵커를 키우는 테이머들은 부러진 발톱을 키운 증표로 보관하는일이 많다.』",
  "야누스": "빛과 어둠의 기사단을 이끌며 우주의 균형을 가져온다. 창조신 아모르와 파괴신 카데스, 두 신이 격돌하는 자리에서 빛과 어둠을 함께 지닌 채 탄생했다. 눈을 뜨자마자 붕괴되기 시작한 우주의 균형을 안정시켰다. 우주의 균형을 유지하는 모습을 본 드래곤들은 야누스를 따르기 시작했다.",
  "야즈니르": "오랜 세월 방황과 수련을 거쳐 욕망과 속박을 벗어난 초월적 드래곤. 황금빛 몸과 부유하는 구슬, 뒤로 펼쳐진 다수의 빛의 잔영으로 신성한 위용을 드러낸다. 과거엔 혼란의 근원이었으나, 지금은 인내와 희생 끝에 세상을 구원할 영웅으로 각성했다.",
  "어두운 발로드": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 발로드는 여섯 수호자 중 어둠을 상징한다. 강력한 어둠의 힘을 조종했으며, 누구보다 레오나를 위했던 드래곤이었다고 전해진다. [ 획득가능: 에스텔라 ]",
  "어둠의 가디언": "어느 왕국의 왕실의 상징으로 사람을 잘 따르며 보호 본능이 뛰어나다. 오른손에 생기는 문양은 힘을 더욱 강력하게 만든다.",
  "어둠의 고대 주니어": "고대신룡과 엔젤사이에서 태어난 아들이다. 고대신룡처럼 정의롭지만 나이가 어려서 철이 없고 암컷드래곤들을 매우 좋아 한다.",
  "어둠의 고대신룡": "태초의 비법을 통해 태어난 교배 드래곤. 본래는 선한 성격의 빛의 수호자였지만, 암흑의 힘이 더해져 사악하고 무시무시한 마신으로 돌변했다.",
  "어둠의 골드 드래곤": "피부와 뼈가 모두 금으로 된 드래곤. 빛의 광산 깊은 곳에서 서식한다. 수 많은 탐험가들이 찾으려 하지만 아직까지 전설로만 전해온다.",
  "어둠의 골든혼": "같은 종족중에서도 수십년에 한번씩 태어나는 황금으로 된 뿔과 날개를 가진 드래곤이다. 그 뿔과 날개는 종족 중에서도 우월함을 상징하며 강한 힘의 원천이 되기도 한다.",
  "어둠의 금오드래곤": "삼족오라는 까마귀와 비슷해서 지어진 이름이다. 날개가 3개, 눈이 3개이다. 세 번째 눈은 어릴 때 감겨 있는데 성장하면서 세 번째 눈을 뜨면 엄청난 말썽꾸러기가 된다.",
  "어둠의 나이트 드래곤": "중세시대로부터 전해 내려온 갑옷을 입고 있으며, 기사의 영혼을 담고있는 전설의 드래곤이다. 정의롭고 용감하며 패배를 모르는 드래곤이다.",
  "어둠의 라이곤": "호기심이 많고 매우 활발한 성격의 드래곤. 날개가 작아 자유롭게 하늘을 날아다니지는 못하지만 빠른 달리기와 저공 비행을 이용해 땅 위에서는 상대를 놓치는 적이 없다. 강력한 다리 힘으로 한번 휘두르면 공기를 가르는 파동이 생긴다.",
  "어둠의 레드와이번": "새끼일때는 순하지만 성체가 되고부터는 막무가내로 포악해지는 드래곤이다. 뜨거운 불 구덩이 주변에서 자주 볼 수 있는 와이번 중 하나이다.",
  "어둠의 레이디 드래곤": "특이하게도 암컷만 태어나는 드래곤. 핑크빛의 색상이 특징이며 매우 온순하다. 눈빛이 매력적이다.",
  "어둠의 레인보우": "무지개 동산에서만 태어나는 드래곤이다. 날개의 색상이 무지개와 같다.",
  "어둠의 머스타드해머": "턱근육이 굉장히 좋은 드래곤이다. 턱힘 하나로 바위도 으깰 수 있다. 성격은 온순하며, 다른 드래곤들을 잘 따른다.",
  "어둠의 메탈 마그넷": "머리, 팔, 다리, 날개가 자석과 같은 성질로 이루어져 있다. 배에 있는 버튼을 건드리는 걸 무척 싫어한다.",
  "어둠의 뮤직 드래곤": "음악을 사랑하고 즐겨 부르는 드래곤 사실상 노래는 잘하지 못한다. 노래를 부를 때 나오는 초음파로 다른 드래곤들을 공격한다. 다른 용들은 귀가 아파 항복을 하기도 한다.",
  "어둠의 백룡": "희망의 드래곤으로 알려진 백룡. 탐험을 통해서 얻을 수 없는 스페셜 드래곤.",
  "어둠의 본헤드": "황랑한 사막같이 생명체가 거의 없는 곳에서 서식하며, 장난끼가 많다.",
  "어둠의 샌드 드래곤": "불보다 뜨거운 사막에서 태어난 샌드 드래곤. 땅계열 같지만 그는 불계열이다. 불구덩이보다 뜨거운 모래로 상대를 잠재울 수 있다.",
  "어둠의 샤크곤": "상어의 모습을 띄며 물속에서 생활한다. 까칠하고 따로운 성격 때문에 주위에서 건드리기를 꺼려하며 강력한 악력으로 사냥과 공격을 한다.",
  "어둠의 샴 드래곤": "태생부터 두 개의 머리와 자아를 가진 희귀한 드래곤이다. 두 개의 자아는 극적으로 다른 성향을 보이지만 적을 공격할 때에는 협동을 하여 공격한다.",
  "어둠의 스마트 드래곤": "태어나면서부터 IQ가 뛰어난 드래곤이다. 책을 항상 갖고 다니는 이 드래곤은 책을 읽지 못하면 화가 나서 공격을 해버릴 수 있다. 책을 주었다면 돌려주자.",
  "어둠의 스콜피온 드래곤": "전갈의 특징을 지니고 있는 드래곤이다. 꼬리 끝에는 독샘이 있고 앞발은 집게로 되어있어 전투 시 까다로운 드래곤 중 하나이다.",
  "어둠의 스파인": "뾰족한 가시를 두르고 있고 호기심이 많지만, 가시 때문에 홀로 다니는 경우가 많다. 가시 안에는 맹독이 들어 있어, 한번 찔리면 치료가 불가능하다.",
  "어둠의 슬라임 드래곤": "바다의 요정이라 불리는 드래곤. 하반신을 자유자재로 변형할 수 있다. 더우면 몸이 흐믈흐믈 해져서 싫어한다.",
  "어둠의 에메랄드 드래곤": "빛의 수호자로 알려져 있던 드래곤. 빛과 암흑의 세상에서 신의 대리자로 세상의 균형을 유지해왔다.",
  "어둠의 윈드 드래곤": "바람 부는날을 무척 좋아하는 용으로 바람을 타고 날아오른다. 새끼 때는 부모의 보살핌을 받지만 성장하면 무리를 떠나 따로 생활한다. 바람이 불지 않는 날에는 밖으로 잘 나오지 않는다.",
  "어둠의 윙스 드래곤": "바람을 자유자재로 움직이게 할 수 있는 윙스! 성체는 작지만 거대한 날개는 다른 드래곤에게 위압감을 준다. 멀리서 보면 날개에서 눈이 보이는 신비한 드래곤.",
  "어둠의 치킨헤드 드래곤": "암컷만 존재하는 드래곤. 모성애가 매우 강하다. 익숙하게 생겼다고 무시하다간 강력한 부리로 머리를 쪼이고 혼쭐나게 된다. 온몸을 감싼 두꺼운 깃털이 적들의 공격으로부터 보호해준다.",
  "어둠의 카멜레용": "피부 색을 자유자재로 바꿀 수 있는 드래곤. 기분에 따라 색상이 바뀌기도 하니 붉은 색을 띠고 있다면 가까이 가지 않는 것이 좋다. 입 안에 혀를 돌돌 말고 있어 몸 길이의 10배까지 늘어난다고 한다.",
  "어둠의 캥거레빗 드래곤": "당근을 무척 좋아하는 드래곤. 마음먹고 점프하면 구름까지 뛰어오를 수 있다. 몸에 달린 주머니 속에 어떤 것들이 들어있는지는 아무도 모른다.",
  "어둠의 큐피트용": "사랑을 이어주는 드래곤이라고 알려져 있다. 이 드래곤의 화살에 맞으면 사랑에 빠진다고 하여 활을 훔치려는 이들이 끊임 없다. 하지만 화살로 사랑만 전해 줄 수 있는 건 아니다.",
  "어둠의 크리마용": "겨울에만 발견된다고 알려진 신비로운 용. 이색적인 장식을 몸에 장식한 것이 특징이며 장식의 색상만큼 활발하고 장난기가 많은편. 들려오는 민담으로는 루돌프를 도와 썰매를 끌었다고 전해진다.",
  "어둠의 타이거드래곤": "태어날때부터 호랑이의 무늬와 비슷한 무늬를 가져 타이거 드래곤이라 불렀다. 이는 모든 드래곤들중 순발력이 가장 빠르고 경계심이 강하다.",
  "어둠의 타투": "짙은 갈색의 문양을 몸에 새기고 있으며 성장 되면서 문양이 커지며, 힘을 잃으면 사라진다.",
  "어둠의 파이어 드래곤": "불을 먹고 산다고 전해지는 드래곤. 주로 뜨거운 지역에서 생활하며 불을 좋아한다. 호전적이며 불같은 성격을 지녔다.",
  "어둠의 프로스티": "고위도 추운지방에 분포, 추운지방에 서식해서 몸에 깃털이 둘러져 있다. 거의 집단으로 생활한다.",
  "어둠의 해태드래곤": "해태의 의지를 물려받은 동양의 사신 중 하나이다.",
  "어둠의 현무 드래곤": "거북과 뱀의 몸을 가진 동양의 사신 중 하나이다.",
  "어비스 엣지": "심해에서 살아가는 무시무시한 특화형 드래곤. 물 속성 드래곤임에도 불구하고 사나운 성격은 불 속성 드래곤과 견줄 정도이다. 매섭게 솟아오른 뿔은 심해의 칼날이라고 불릴 정도로 뛰어난 파괴력을 자랑한다.",
  "얼티밋 드래곤": "우주에서 왔다는 소문이 있는 드래곤. 말은 하지 못하지만 텔레파시를 통해 의사소통을 한다. 무슨 원리인지는 모르겠으나 가끔 배에 우주의 은하수가 보일 때가 있다.",
  "얼티밋드래곤": "우주에서 왔다는 소문이 있는 드래곤. 말은 하지 못하지만 텔레파시를 통해 의사소통을 한다. 무슨 원리인지는 모르겠으나 가끔 배에 우주의 은하수가 보일 때가 있다.",
  "에그 드래곤": "겁이 매우 많아 새끼때 알속에 숨어지낸다.알은 매우 단단하며 자라면서 날개와 합쳐진다.새끼때의 모습은 보기 힘들다. [ 획득가능: 희망의 숲 ]",
  "에그마용": "폭신폭신한 에그마요 털을 두른 소시지 드래곤. 빵 덮개에 덮여있을 때 가장 안정감을 느낀다. 그릴에 구운 것 같은 무늬가 몸에 있는게 특징.",
  "에닉스": "전설로 전해지는 심해 신전의여신 레오나의 여섯 수호 드래곤중 하나인 에닉스는 여섯 수호자중 땅을 상징한다. 숲과 대지를 다루는능력으로 레오나를 노리는 악에 맞서싸웠다고 전해진다. [ 획득가능: 에스텔라 ]",
  "에메랄드 드래곤": "빛의 수호자로 알려져 있던 드래곤. 빛과 암흑의 세상에서 신의 대리자로 세상의 균형을 유지해왔다. [ 획득가능: 하늘의 신전 ]",
  "애버네일": "수줍음이 많아 모두가 잠든 밤에 주로 밤의 숲 산책을 좋아하는 빛 드래곤이다. 숨결에 발광물질이 녹아있어 숨을 쉴때마다 주변이 밝게 빛나는데 이 덕분에 밤 산책이 용이하다. 어두운 숲을 밝히는 모습이 반딧불이를 닮았다 하여 반딧불이 드래곤으로도 불린다.",
  "에슈": "꿈의 세계에서 온 정령 오리시아와 함께 각종 보석을 훔치는 괴도 드래곤이다. 갖고 싶은 물건이라면 수단과 방법을 가리지 않고 훔치고 만다는 신조가 있다. 그만큼 물건에 대한 소유욕과 집착이 매우 강하며 특히 반짝이는 보석에는 눈이 뒤집힐 정도다.",
  "에오스": "샛별이 질때 쯤, 유타칸에 드리운 어둠이 걷힐 때에 목격되는 드래곤. 처음에는 정체가 밝혀지지 않은 드래곤이었기에 사람들은 이 드래곤을 볼 수있는 시간대와 우아한 외모에서 착안해 '에오스'라고 부르기로 하였고 그 이름은 지금까지도 전해져 내려오고 있다.",
  "에이라": "8년에 한 번씩 오는 혜성을 타고 나타나는 드래곤. 8년의 먼 여행을 떠나기 때문에 날개가 많다고 한다. 여행을 다니며 머나먼 지역의 별빛을 모아 장식에 담아둔다.",
  "에일리언 드래곤": "우주괴물처럼 생긴 용, 우주의 힘을 가지고 있는 용이라고 전해진다. 하늘과 가까이 있는 곳, 하늘보다 더 하늘인 곳에서 많이 출현한다. [ 획득가능: 바람의 신전 ]",
  "에트왈 드래곤": "화려함과 미를 추구하는 드래곤. 높은 산의 바람 쐬기를 좋아하며 여성 테이머에게 인기가 많다. 하지만 싸울 때 보이는 푸른 안광은 적을 꼼짝도 못하게 할 정도로 무시무시하다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "에피트": "어둠의 수호자 다크닉스의 권능 아래 7가지 악을 주관하는 다크 세븐의 일원이다. 7가지 악 중 욕망을 주관하고 있다. 상대로 하여금 쾌락에 대한 끝없는 욕망을 느끼게 한다.",
  "엔더 드래곤": "카데스의 여섯 날개 중 하나로 파멸의 힘을 부여받은 신의 화신. 지금까지 그 누구도 정체를 모르고 있던 드래곤으로 이유는 아주 간단하다. 그와 마주한 모든 이들의 운명은 파멸밖에 없었을 뿐이다. [ 획득가능: 증명의 탑 ]",
  "엔젤 드래곤": "고대신룡의 암컷이다. 빛을 좋아하며 매우 온화하다. 천사의 힘을 가지고 있다고 전해진다. [ 획득가능: 하늘의 신전 ]",
  "엔젤주니어": "고대신룡과 엔젤드래곤 사이에서 태어난 드래곤으로, 자존심이 세고 성미가 급한 고대주니어와 자주 다투는 편이다.",
  "엔젤캣": "테이머의 수호천사라 불리는 천사 드래곤이다. 신으로부터 부여받은 천사의 링을 통해 드래곤의 힘을 가질 수 있게 되었다. 테이머를 수호하고자 하는 마음이 강할수록 더욱 큰 힘을 발휘할 수 있는 드래곤이기도 하다.",
  "엔투라스": "자신의 힘을 초월한 드래곤. 자신이 곧 불이며, 악한 자를 벌하겠다는 말과 함께 라테아에서 내려왔다. 다른 드래곤과 다른 신체구조로, 팔 부분의 폭발적인 힘으로 적을 심판한다.",
  "엔틱 드래곤": "골동품 가게의 물건들은 가게가 망해도 계속 그 자리에 남게 되었다. 그때 세상을 떠돌던 생명의 기운이 망한 골동품 가게로 찾아들었고 엔틱 드래곤이 태어나게 되었다.",
  "엔퓨": "우주의 흐름의 힘으로 태어난 용이다.처음과 끝을 알리는 용으로 별의 죽음과 탄생 혹은 또다른 우주의 탄생과 죽음을 알려준다고 한다. 뿔에는 우주의 힘이 흐르고 있으며 그 뿔을 만진자는 이 세상 모든 지식을 알게 된다고 한다.",
  "엘더 드래곤": "많은 세월을 살아온 드래곤. 긴 세월을 살아왔기 때문에 해박한 지식을 지니고 있다. 종종 스마트드래곤이 찾아와 귀찮게 하는 것을 제일 싫어하는 편.",
  "엘리고스": "거대한 바다를 자유로이 이동하는 드래곤, 날렵하고 거대한 몸체가 바다를 자유로이 이동하는 모습은 감탄을 자아낸다고 한다. 성격은 온순하고 호기심이 많아, 배를 발견하면 주변을 맴돈다고 한다.",
  "엠파이어": "고대 제국을 지키던 수호 드래곤. 제국이 몰락할 때 인간에게 크게 실망하고 모습을 감췄다. 하지만 최근 유타칸 곳곳에서 일어나는 사건 때문에 평화가 위태로워지자, 다시금 평화를 수호하기 위해 모습을 드러냈다.",
  "열화의 발칸": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 발칸은 여섯 수호자 중 불을 상징한다. 과거 여신을 노리는 다크닉스에 맞서 타오르는 화염의 힘으로 대적한 용감한 드래곤이다. [ 획득가능: 에스텔라 ]",
  "염화룡": "다른 차원에서 넘어온 드래곤. 상상할 수 없을 만큼의 긴 세월동안 수행을 거듭해 ",
  "오딘": "왕의 운명을 타고난 환상의 드래곤. 머리 위에 지닌 왕의 표식은 성룡이 되었을 때, 완성되어 진정한 왕의 모습을 증명한다. 단 쉽게 마음을 열지 않기 때문에 상당한 노력이 필요하다.",
  "오렌지리프 드래곤": "좋은 향이 나는 신기한 드래곤. 은은한 오렌지 향내를 풍기기 때문에 애완용으로 인기가 많다. 최근 수렵꾼들의 포획이 심해져 인간의 손길을 피해 숲 깊은 곳으로 달아났다.",
  "오로": "자신이 선택한 정의로운 자에게 그 모습을 드러내는 신비로운 드래곤. 바람의 화신과도 같은 창공의 날개 능력으로 적을 제압할 수 있다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "오로라 드래곤": "신비한 문양으로 하늘을 수놓는 오로라 그 중심에 항상 머무는 신비한 드래곤. 매혹적인 오로라의 색만큼 이 드래곤의 생태는 특이한 편에 속한다. 사람들이 눈에 띄지 않는 밤하늘에만 나타나며 별빛을 주식으로 먹고산다. [ 획득가능: 미스터리 뽑기 ]",
  "오르도": "여명과 황혼의 주인인 아실리와 옵타툽을 지키는 세 마리의 수호자 드래곤 중 하나. 오르도는 강한 힘을 지닌 드래곤으로 그 용맹함과 투지는 따를 자가 없다 전해진다. 오랜 세월 재앙의 밤이라고 불리는 크레바스에 맞서 꿈의 세계를 지켜 왔다. [ 획득가능: 콜로세움 ]",
  "오르페우스": "유타칸에서 거구형 드래곤중 손가락 안에 드는 거대한 덩치의 갑피형 드래곤.철벽같은 뚝심으로 적의 공격을 방어하고 지축을 뒤흔드는 엄청난 공격능력으로 적을 농락하고 유린한다.",
  "오미야콘": "차가운 빙결의 틈새에서 서식하는 드래곤. 거대한 덩치와 철벽의 성과 같은 얼음 피부는 적의 공격을 효과적으로 막아내고 필살의 일격을 이끈다. 가슴의 푸른 불꽃이 맹렬히 타오를수록 더 강한 힘을 지니게 된다.",
  "오벡스": "오벡스가 만드는 공간의 경우 매우 폐쇄적이다. 적으로부터 자신의 몸을 지키는 용도로 가장 많이 활용되는데, 어떤 강력한 힘을 가진 드래곤이라도 오벡스가 만든 공간을 파괴하기란 쉽지 않다. 무리 지어 싸우기보단 한 드래곤을 공간에 가둔 채 죽음에 이르게 하는 경우가 많다.",
  "오쿠러스": "고귀한 영혼이 머무는 세계 프뉴마. 오쿠러스은 수많은 음유시인의 노래에 존재한 환상의 세계 프뉴마의 인도자이다. 이 신비의 땅의 인도자는 날렵한 움직임과 뛰어난 지성을 지니고 있다. 하지만 그저 환상의 존재라고 여길 뿐 실제로 이 인도자를 본 자는 그 누구도 존재하지 않는다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "옥타": "전체적으로 매끈매끈한 몸을 가졌으며, 머리의 촉수와 꼬리에는 접착력이 좋은 강력한 빨판이 달려있다. 등과 팔의 푸른 무늬는 불규칙적이다. 머리의 촉수를 길게 늘려 상대에게 빨판으로 붙어 도망치지 못하게 만든다. 목과 배 사이에는 보석처럼 보이는 눈동자가 달려있다.",
  "옴므니아": "오랜 시절 드래곤들을 관찰하고 보호하는 드래곤이다. 세상의 모든 드래곤을 사랑과 염려의 마음으로 지켜본다. 모든 드래곤과 테이머들에게 평화와 지혜가 깃들기를 바란다. [획득조건: 도감점수 달성 ]",
  "옵타툽": "꿈의 틈새에 살아간다고 전해지는 환상형 드래곤. 흑과 청으로 어우려진 불멸의 존재로 아실리와 힘을 합쳐 꿈의 세계를 지켜왔다. 꿈과 현실이 하나가 될 때 위기를 막고자 세상에 나타난다고 전해진다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "와일드 드래곤": "알려지지 않은 망각의 산 [발리온]의 비밀스러운 파수꾼. 낯선 자의 방문을 매우 싫어하며,전투가 거듭될수록 몸이 붉어지고 불타는 화염과 같은 색으로 몸이 변하면 더욱더 강한 힘을 얻을 수 있다.",
  "요르문간드": "레무리아의 세계수 위그드라실을 지키는 수호 드래곤이다. 대륙 전체를 감쌀정도로 거대한 몸체를 가졌으며, 마도사 발두르와 함께 오랜 세월 레무리아를 수호해왔다. 그러나 발두르의 마석 '카닐'을 악용한 제자들의 행위로 인해 폭주하였고, 결국 발두르의 손에 의해 대륙 깊숙이 봉인되었다.",
  "우파룸": "매사에 호기심이 많은 드래곤. 그래서 사고도 많고 다칠 때도 많다. 하지만 해치 시절의 그러한 경험들이 쌓이고 성체가 되면 굉장히 현명해지는 드래곤.",
  "울르": "어둠과 악으로부터 드래곤을 보호한다. 육각의 보옥은 방패와 같은 역할을 하여 자신과 상대를 어둠과 악으로부터 보호하는 데에 쓰인다.",
  "움브라": "보자기 인형같이 생긴 드래곤. 사실 인형은 위장이고, 아주 가까운 곳에서만 볼 수 있는 악령처럼 생긴 드래곤이다. 만약 그 모습이 보이는 곳까지 다가갔다면 모든 힘을 빼앗겨 먹잇감이 될 뿐이다.",
  "원더 드래곤": "신비한 세계에서 찾아온 의문의 드래곤. 강력한 근력을 무기로 적에게 무시무시한 악몽을 선사한다. 성격이 매우 난폭하니 육성 시 주의하도록 하자.",
  "웨일 드래곤": "거대한 체구를 자랑하는 수호자 드래곤. 웨일 드래곤은 깊은 바다에 서식하는 보기 드문 희귀 드래곤이다. 보는 것만으로 행운을 가져다준다 하여, 블루 럭이라는 큰 몸집에 비해 다소 귀여운 이명이 있다.",
  "위그드라실": "신성한 나무라고 알려진 위그라드실에 기원을 찾을 수 있는 드래곤. 팀버 드래곤과 같은 자연형 드래곤으로 위그드라실의 잎새에서 태어났을 것으로 학자들은 추측하고 있다. 등에 자라난 나무 잎새의 힘을 이용해 약하고 아픈 자를 치유하는 선한 드래곤으로 주로 사람들이 발길이 닿지 않는 험준한 계곡에 터전을 마련해 살아간다.",
  "위드미": "세상에 행복을 전해주기 위해 태어난 악동형 드래곤.의문의 마법사에게 수련을 받은 존재로 뛰어난 마법능력을 가졌으며 지나치게 명랑한 것이 단점. 모두를 기쁘게 해주고 싶어 하지만 오히려 사고를 일으키는 경우가 많다. 하지만 그저 환상의 존재라고 여길 뿐 실제로 이 파수꾼을 본 자는 그 누구도 존재하지 않는다.",
  "윈드 드래곤": "바람 부는날을 무척 좋아하는 용으로 바람을 타고 날아오른다. 새끼 때는 부모의 보살핌을 받지만 성장하면 무리를 떠나 따로 생활한다. 바람이 불지 않는 날에는 밖으로 잘 나오지 않는다. [ 획득가능: 바람의 신전 ]",
  "윗치 드래곤": "마녀가 자신의 마력을 나눠 태어난 드래곤. 마녀의 마력을 이어받아 주술력이 남다르며 신비한 힘의 지팡이를 지니고 있다. 지팡이의 마력은 드래곤의 힘과 동조 되어 상상을 초월한다. [ 획득가능: 미스터리 뽑기 ]",
  "윙스 드래곤": "바람을 자유자재로 움직이게 할 수 있는 윙스! 성체는 작지만 거대한 날개는 다른 드래곤에게 위압감을 준다. 멀리서 보면 날개에서 눈이 보이는 신비한 드래곤. [ 획득가능: 메마른 평원 ]",
  "유니드래곤": "붕대가 몸을 감싸고 있고 뚜렷한 형태가 없다. 성장하면서 붕대로 자신의 형태를 만들어간다.",
  "유니버스": "많은 비밀을 간직한 신비의 드래곤. 강력한 힘을 지니고 있어, 장신구를 통해 그 힘을 억제하고 있다. 저명한 학자들도 완벽히 이 드래곤을 분석하지 못해, 다양한 추측이 오고 가는 수수께끼의 드래곤이기도 하다.",
  "유르카": "여행을 좋아하는 야행성 드래곤. 몸에서 (포인트컬러) 빛을 발하기 때문에 밤에도 문제없이 활동할 수 있다. 대부분 밤에는 잠을 자기 때문에 친구가 없어 사회성이 떨어진다.",
  "유리온": "세상 가장 어두운 곳에서도 아름다운 빛을 뿜어내는 드래곤이다. 신비한 구체가 항상 몸 주변을 돌며 빛의 조각을 뿌려 테이머들에게 길을 인도한다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "이그나": "불꽃의 요정이라고 불리는 드래곤. 평소에는 모습을 잘 드러내지 않고 순수한 마음을 가진 사람 앞에만 나타난다고 전해진다. [ 획득가능: 아르하 레이드 ]",
  "이그니스": "특이한 성격과 인내심을 가져 불 속성 드래곤 중 보기 드물게 인지도가 높다. 그 특이한 성격은 바로 조용하고 과묵한 태도인데, 이러한 성격은 보통 땅 속성 외에는 그다지 보기 힘들다고 알려졌다.",
  "이모션": "이모션의 뜻은 감정이란 뜻입니다. 빨간색의 이름은 마나, 감정은 분노입니다. 노란색의 이름은 플램, 행복과 기쁨입니다. 파란색의 이름은 메이입니다, 감정은 슬픔입니다.",
  "이블 던": "진지하고 진중한 성격의 드래곤. 헬카이저의 교활한 계략에 신중함을 더하는 참모 역할을 맡고 있다. 말수도 없고 표정도 읽기 어렵지만, 그 속내에 감추고 있는 잔인함은 헬카이저 못지 않게 끔찍하다. [ 획득가능: 증명의 탑 ]",
  "이슬룡": "흐르는 물의 특성을 지닌 자연형 드래곤. 몸 대부분이 물로 이루어져 슬라임 드래곤과 자주 비교되곤 한다. 하지만 슬라임 드래곤 보다 더 활발한 성격으로 보아, 둘의 차이점은 조금씩 다를 것으로 파악된다.",
  "이지스": "신의 방패라 불리는 드래곤, 단단한 피부의 갑주는 성스러운 빛을 발산하며 사악한 공격을 방어하며 그 공격은 그대로 날개에 흡수되어 에너지가 된다.",
  "이클립스": "태양을 삼키는 드래곤, 일식이 일어날 떄 에만 볼 수 있다. 그 모습 때문에 일식의 주인이라고 불리며 일식이 일어날 때는 그 힘이 누구와도 견줄 수 없다고 한다. [ 획득가능: 프리미엄 뽑기 ]",
  "이터널": "서로 다른 세계를 넘나들면서 각 세계 간의 조화와 균형을 유지한다고 전해지는 드래곤. 태양처럼 영원과도 같은 삶을 살며, 강렬한 빛으로 세계의 왜곡과 불균형을 조정하는 힘을 가지고 있다. [ 획득가능: 드빌x드빌M 콜라보 축하 이벤트 ]",
  "익시아": "여명을 부르는 고요한 바람에 머무는 환상의 드래곤. 온몸을 수놓은 보랏빛의 무늬는 익시아의 감정에 따라 연해지거나 진해진다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "인베르소": "여신 샌즈의 감정을 어지럽히는 존재를 감지하면, 중력과 현실을 왜곡시켜 여신의 감정을 보호한다. 스스로의 중력을 조절해 누구도 예상할 수 없는 방식으로 비행할 수 있고, 어떠한 공격에도 감정을 통제하여 평온을 유지한다.",
  "인섹트 드래곤": "꽃에 들어있는 꿀을 먹고 사는 드래곤. 하지만 심술이 고약하고 독침이 나올 땐 피하는 것이 좋다. 불로 만들어진 독침은 한번 맞으면 독이 온몸에 퍼져 움직이지 못한다. [ 획득가능: 메마른 평원 ]",
  "인스트리아": "빛의 수호자 고대신룡의 권능 아래 7가지 선을 주관하는 라이트 세븐의 일원이다. 7가지 선 중 근면을 주관하고 있다. 세상에 일어나는 모든 일들을 기록하며, 이 기록을 바탕으로 계획을 세우거나 미래를 예측한다. 기억의 돌로 자신이 기록한 기록들을 쉽게 찾아 볼 수 있다. 날아다니는 쥐 '플루스'는 항상 인스트리아 주변을 날아다니며 인스트리아를 돕니다. 인스트리아가 가장 아끼는 물건은 이 세상 누구도 본 적이 없는 일기장이다.",
  "일란": "우아하고 기품이 넘치는 드래곤. 특히나 날아가는 모습이 우아한 것으로 유명하다. 엘프를 매우 좋아하여, 엘프 인형을 항상 가지고 다닌다고 한다.",
  "일레마": "미지의 불꽃을 사용하는 영험한 드래곤. 붉게 빛나는 눈은 많은 미신과 소문을 만들어냈다. 대표적으로 일레마의 붉은 눈을 보면 혼백이 빠져나간다는 엉터리 괴담이 있다.",
  "일로스": "뱀장어처럼 미끌거리는 드래곤. 순하고 착한 성격을 가져 누구와도 친하게 지낼 수 있다. 하지만 늘 진흙이 묻어있어 일로스를 좋아해주는 사람은 몇 없다. [ 획득가능: 옛 성터 ]",
  "일리오스": "시간의 여신 기누의 수호 드래곤.일리오스는 시간의 이루는 두 축 중아침을 상징하며 시간의 여신 기누의 명에 따라 초월적인 힘을 지닌 성제의 분노를 사용하여 사악한 카데스의 마물들을 물리쳤다고 전해진다.",
  "일리오스O": "시간의 여신 기누의 수호 드래곤.일리오스는 시간의 이루는 두 축 중아침을 상징하며 시간의 여신 기누의 명에 따라 초월적인 힘을 지닌 성제의 분노를 사용하여 사악한 카데스의 마물들을 물리쳤다고 전해진다.",
  "자간": "자간은 드래곤이 환경에 따라 변화하는 것을 증명하는 보기 드문 드래곤이다. 드래곤과 거리가 먼... 어쩌면 몬스터와 비슷한 생김새에도 불구하고 이 드래곤은 분류상 드래곤으로 구분된다. 실제로 자간을 육성하는 드래곤 테이머도 있는 만큼 생긴것으로 판단하는 건 자간에게 큰 실례가 될 것이다.",
  "자룡": "일기당천으로 악을 물리쳐 쓰러트린 맹장의 혼이 깃든 드래곤. 먼 동방에서 홀연히 나타난 의문의 존재로 투신과 같은 강인함으로 많은 이들에게 선망의 대상으로 알려져 있다.",
  "자루카": "빛과 어둠의 시대, 사악한 어둠에 맞선 재빠른 속도와 뛰어난 지능을 지닌 수호 드래곤.기억의 신이 내린 명령을 이행하고자 세상에 나타났으며, 날렵한 움직임과 뛰어난 재치로 적을 물리쳤다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "작은빛의 바리안": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 바리안은 여섯 수호자 중 빛을 상징한다. 광명의 빛으로 최선을 다해 여신 레오나를 지킨 수호드래곤이며, 여섯 수호자의 우두머리이다. [ 획득가능: 에스텔라 ]",
  "잔잔한 파프리온": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 파프리온은 여섯 수호자 중 물을 상징한다. 맹렬한 해일을 불러오는 힘을 지녔으며, 레오나를 안전한 곳으로 이동시켰다고 전해진다. [ 획득가능: 에스텔라 ]",
  "잠식된 요르문간드": "레무리아의 세계수 위그드라실을 지키는 수호 드래곤이다. 대륙 전체를 감쌀정도로 거대한 몸체를 가졌으며, 마도사 발두르와 함께 오랜 세월 레무리아를 수호해왔다. 그러나 발두르의 마석 '카닐'을 악용한 제자들의 행위로 인해 폭주하였고, 카닐의 마력에 의해 잠식되었다.",
  "장고": "세상을  혼란스럽게 하는 이들을 혼쭐내어 자신의 가치를 증명하고자 한다. 정의감으로 약자를 보호하는 보안관이다. 재빠른 몸놀림과 전투 실력으로 혼란을 가져오는 이들을 물러가게 한다. 자신의 생명의 은인으로 여기는 거북이, 프랭크와 함께 자신의 오랜 숙적인 에슈를 뒤쫓고 있다.",
  "장벽의 에닉스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 에닉스는 여섯 수호자 중 땅을 상징한다. 숲과 대지를 다루는 능력으로 레오나를 노리는 악에 맞서 싸웠다고 전해진다. [ 획득가능: 에스텔라 ]",
  "적마룡": "'정화'라고 불리는 불꽃으로 사악한 것을 정화하고, 새로운 생명이 돋아나게 하여 자연을 순환시킨다. 붉은 평원뿐 아니라, 토호으 대륙 전체를 달리며 정화의 불꽃을 피운다. 성체가 된 적마룡의 불꽃은 평범한 생명에는 영향을 주지 않고, 오염된 것이나 사악한 것들에게만 영향을 끼친다.",
  "적오드래곤": "신비로운 해에만 그 모습을 드러낸다는 마력형 드래곤.온몸을 수놓은 불타는 털은 마치 붉은색 마수를 떠오르게 한다.선한 마음을 지닌 자에게 그 마음을 허락하여 악한 마음을 지닌 자는 만날 수 없다.",
  "점프 드래곤": "이세계에서 유타칸으로 찾아온 신비한 드래곤. 점프 드래곤의 고향은 또 다른 검은 로브의 추종자들과 사악한 바라카의 음모가 도사리고 있다. 점프 드래곤은 유타칸에서 자신의 고향을 구할 방법을 모색하고 있다.",
  "제트 드래곤": "매끈하고 거대한 날개와 몸에 비례하여 큰 발을 지닌 드래곤. 푸른색에 가까운 몸체는 청명함을 보이기도 하지만 한편으로는 으스스한 분위기 또한 자아낸다. 고속으로 이동할 때 특이한 소리 덕분에 제트 드래곤이라는 이름이 붙여졌다.",
  "제피로스": "창공 너머 사람들의 손길이 닿지 않는 곳에 서식하는 희귀한 드래곤. 추운 것을 싫어하기 때문에 겨울에는 그 모습을 찾아보기가 어렵다.",
  "젤리피쉬": "온 몸이 말랑말랑하고 귀여운 드래곤. 촉수를 이용해 상대의 공격을 막거나 공격하는데 공격하는 순간에는 촉수가 단단해져서 더욱 강력해진다.",
  "조화룡": "형제가 환생했다는 전설의 쌍두 드래곤이다. 형은 죽음을 동생은 삶을 관장한다 전해진다. 생전 자신을 희생해 동생을 지켰던 동생의 우애로 탄생했다 알려져 있다.",
  "좀비드래곤": "불운한 실험을 통해 탄생한 언데드 드래곤. 드래곤 뿐만 아니라 다양한 종류의 생명을 혼합하여 만들었다고 추측된다. 낮에는 거의 활동하지 않으며, 해가 지는 밤에만 움직여 과거에는 언데드가 아닌 야행성 드래곤으로 분류했었다.",
  "주작": "힘차게 타오르는 불을 몰면서 남쪽을 관장한다고 전해지는 사신 드래곤이다. 모습을 잘 드러내지 않기 때문에, 주작을 발견한 자는 반드시 길조가 있을 것이라 전해진다.",
  "즈믄": "모든 테이머의 친구이자 누리의 숙적. 항상 누리와 티격태격 거리지만 사실은 제일 친한 친구라고 생각한다. 자신이 가진 최고의 매력 포인트는 알껍질이라고 여기는 중.",
  "지마": "빛과 어둠의 전투 당시, 어둠의 수호자 다크닉스를 수호한 삼무제의 일원. 중형 드래곤임에도 불구하고, 작고 호리호리한 체구는 덩치가 큰 드래곤들이 업신여길 단점이었다. 하지만 그런 단점을 무색하게 만드는 무시무시한 지략은 지마의 강력한 무기였고, 실제로 이 지략은 어둠의 드래곤 세력에 수많은 승리를 안겨 주었다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "지바타르": "뇌전과 폭풍의 기운을 자신의 수족처럼 다루는 드래곤. 조금이라도 자신을 언짢게 만드는 존재를 만나면 일단 벼락부터 뿜어내는 폭급한 성정을 지니고 있어 다른 생명체들과의 교류가 매우 드물다고 한다. [ 획득가능: 레이드 ]",
  "지진": "대지의 울림 속에서 태어난 드래곤. 그 때문인지 땅 위에서는 이길 드래곤이 없다고도 한다. 땅에게 여러가지 영향을 줄 수 있는 힘을 지니고 있다.",
  "지타쿨라": "얼어붙은 대지의 파수꾼. 앙그라의 침공으로 고통받은 그는 그후 외부의 드래곤들을 혐오하고 적대시하게 되었다.",
  "지하땅굴 드래곤": "땅속에서 살아가는 드래곤. 눈은 어두운 곳에 적응되어밝은 곳에 오래 있지 못한다. 땅굴을 파서 이동함.주로 땅속에서 먹이를 찾아 먹거나밤에 땅 위로 나온다. [ 획득가능: 희망의 숲 ]",
  "직소 드래곤": "퍼즐 세계에서 탄생한 드래곤. 혼자서 지내기엔 너무 쓸쓸해진 나머지 친구를 찾아 유타칸에 오게 되었다.",
  "진": "니벨룬 대륙의 푸른 숲에서 정령들의 숨결을 받아 태어난 자연의 수호자이다. 항상 숲과 교감하며, 존재만으로도 숲속 생명들에게 평온과 안식을 선사한다. 고대 마귀 크로낙이 사악한 힘으로 세상을 어지럽히던 시절에도, 진은 자연의 힘으로 맞서 싸워 크로낙을 물리쳤다.",
  "차차웅": "악한 영혼들에게 물들어 있던 스스로 엮은 부적과 금줄에 담긴 무형의 힘으로 좋지 않은 기운을 흡수하고 악을 벌하는 신성한 성룡으로 성장했다. 몸에 감긴 금줄에는 액운을 막아주는 부적이 붙어 있어 차차웅의 악한 마음을 끊임없이 정화하여, 성스러운 드래곤으로 성장할 수 있게 도와주었다.",
  "차콜플레임": "세상의 불씨를 가져가는 드래곤. 차콜플레임이 지나가는 곳의 불씨는 그의 등의 불로 빨려 들어간다. 빨려간 불씨는 더욱 붉고 화려하게 타오른다고 한다.",
  "찬란한 바리안": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 바리안은 여섯 수호자 중 빛을 상징한다. 광명의 빛으로 최선을 다해 여신 레오나를 지킨 수호드래곤이며, 여섯 수호자의 우두머리이다. [ 획득가능: 에스텔라 ]",
  "철벽의 에닉스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 에닉스는 여섯 수호자 중 땅을 상징한다. 숲과 대지를 다루는 능력으로 레오나를 노리는 악에 맞서 싸웠다고 전해진다. [ 획득가능: 에스텔라 ]",
  "청룡": "동양의 신화에 구름과 비를 몰고 다닌다고 전해지는 드래곤이다.이무기가 여의주를 얻어 청룡이 되었다고 전해진다.주로 날씨에 관련된 마법을 부릴 줄 안다. [ 획득가능: 바람의 신전 ]",
  "청마룡": "매번 청마의 해에만 나타난다고 전해지는 신비의 드래곤. 온몸에 수놓은 푸른 기운과 돌풍과 같은 기동력에서 나오는 전투력은 다른 모든 이들의 탄성을 자아낸다. 성격이 다소 드센 경향이 있으니 신중하게 육성할 것!",
  "청양 드래곤": "푸른색을 지닌 환상의 드래곤램곤과 같은 꿈의 안내자 드래곤으로,잠든 모든이를 고통스러운 악몽으로 이끈다.",
  "청화풍": "푸른 화염의 힘을 다루는 드래곤. 날개로 대기를 휘저어 강력한 푸른색 불꽃 태풍을 불러일으킨다. 온 몸이 푸른색 화염에 휩싸여 있지만 놀랍게도 물 속에서 수영도 할 수 있다고 한다.",
  "초림": "숲에서 서식하는 드래곤이다. 앵무새를 닮은 모습으로 나무 위에 앉아 있는 모습을 종종 발견할 수 있다. 온순하고 친화력이 높은 성격으로 테이머와의 교감을 좋아한다. 테이머와 친밀도를 쌓게 되면 테이머의 말을 따라 하기 시작한다.",
  "치킨헤드 드래곤": "암컷만 존재하는 드래곤. 모성애가 매우 강하다. 익숙하게 생겼다고 무시하다간 강력한 부리로 머리를 쪼이고 혼쭐나게 된다. 온몸을 감싼 두꺼운 깃털이 적들의 공격으로부터 보호해준다. [ 획득가능: 하늘의 신전 ]",
  "칠흑의 발로드": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 발로드는 여섯 수호자 중 어둠을 상징한다. 강력한 어둠의 힘을 조종했으며, 누구보다 레오나를 위했던 드래곤이었다고 전해진다. [ 획득가능: 에스텔라 ]",
  "카라선": "날개의 힘을 이용해 여러 차원을 유랑하는 드래곤. 그림자의 세계를 오랫동안 여행 도중, 아이들의 순수함에 이끌려 유타칸에 나타났다.",
  "카루라": "태초의 전쟁에서 활약한 드래곤. 앙그라의 부하이자 유일한 그의 이해자. 주인의 불같은 성미와 달리 매우 신중하고 조용한 성격을 가지고 있다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "카르나": "아르주나의 뿔에서 태어난 드래곤. 카데스에 의해 타락하게 되었다. 뿔에 담긴 아르주나의 힘을 온전히 소유하고 있다. 자신을 버린 아르주나를 극도로 혐오하고있다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "카멜레용": "피부 색을 자유자재로 바꿀 수 있는 드래곤. 기분에 따라 색상이 바뀌기도 하니 붉은 색을 띠고 있다면 가까이 가지 않는 것이 좋다. 입 안에 혀를 돌돌 말고 있어 몸 길이의 10배까지 늘어난다고 한다. [ 획득가능: 하늘의 신전 ]",
  "카모플라쥬": "담쟁이 덩굴을 몸에 두른 장난기 있는 드래곤, 성격이 활달하고 장난을 치기 좋아하는 성격을 가지고 있다. 주로 치는 장난은 숲에 숨어 있다가, 사람이 지나갈 때 소리를 내거나 숲속에서 갑자기 튀어나오곤 한다.",
  "카스룩스": "네뷸라의 인도 아래 외우주를 떠돌아다니는 드래곤들 중 하나. 서로의 생각이 공유되는 것처럼 움직인다. 각 드래곤들의 풀 네임은 카스토르와 폴룩스.",
  "카스티타스": "빛의 수호자, 고대신룡의 권능 아래 7가지 선을 주관하는 라이트 세븐의 일원이다. 7가지 선 중 순결을 주관하고 있다. 정직하고 친절한 성품으로 상대를 회유한다. 라이트 세븐 중 가장 진실하고 순수하며 거짓을 무척 싫어한다.",
  "카오스": "빛과 암흑을 조율하고자 태어난 드래곤. 저물지 않은 낮과 잠들지 않는 밤의 흐름에서 나타나는 신비한 존재로, 무수한 위험 속에서 많은 생명을 지키고자 노력했다. 원작자 : 氷菓",
  "카이저번": "죽은 이의 영혼을 관장하던 유타칸의 고대 드래곤. 하지만 카데스에 의해 타락하여 원래 모습을 잃어버린 지금은 그저 산 자의 영혼을 갈구하는 괴물일 뿐이다. [ 획득가능: 아르하의 입구 ]",
  "칸": "빛의 수호자를 따르는 드래곤 중 칸은 뛰어난 충성심으로 유명했다. 이 드래곤의 전투력은 삼무제로 유명한 마르바스와 호각을 다투었으며, 전투가 격해질수록 찬란히 타오르는 빛은 아군에게는 구원이자 적에게는 공포로 각인되었다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "칸타카": "얼어붙은 땅에 사는 바르라키 드래곤들의 우두머리. 모든 드래곤의 왕이라 불리던 앙그라조차 그만은 굴복시키지 못했다.",
  "칼라빈카": "카데스에게 혼돈의 정수를 받아 타락한 긴나라 드래곤 최후의 전사. 고대의 전쟁에서 쿠베라의 검에 치명상을 입고, 죽음의 문턱에서 살아돌아온 후로 카데스의 통제에서 벗어났다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "칼리시": "빛의 수호자 고대신룡의 권능 아래 7가지 선을 주관하는 라이트 세븐의 일원이다. 7가지 선 중 자선을 주관하고 있다. 연민의 마음과 고고한 자태로 정의를 실현한다. 편견이나 선입견 없이 생명을 존중하고 공평하게 대하는 인자한 드래곤이다. [ 획득가능: 2021 한가위 이벤트 ]",
  "캣츠곤": "장난기가 매우 뛰어난 동물형 드래곤. 생태와 행동이 흡사 고양이와 비슷하다 알려져 캣츠곤이라 이름 붙였다. 호기심이 뛰어나고 쉽게 사람과 친해져 안 좋은 소문보다 좋은 평가가 수식어로 따라붙는 편...",
  "캥거레빗 드래곤": "당근을 무척 좋아하는 드래곤. 마음먹고 점프하면 구름까지 뛰어오를 수 있다. 몸에 달린 주머니 속에 어떤 것들이 들어있는지는 아무도 모른다. [ 획득가능: 하늘의 신전 ]",
  "커스리퍼": "죽음의 냄새가 감도는 곳에 푸른 불꽃을 그리며 나타난다. 팔에 달린 뿔로 죽음의 냄새를 풍기는 생명체의 영혼을 즉시 저승으로 데려간다. 도망치려는 자에게는 날개를 펼쳐 저주를 내리며, 저주를 받은 자는 끝없는 공포에 빠진다.",
  "케이나인": "스워드 뒤편의 어둠을 통해 이동하는 드래곤. 태양에 의해 생긴 그림자에 숨어들어온 적을 처치한다. 그의 날카로운 칼날은 적을 만났을 때에만 푸른색을 띤다",
  "케찰코아틀": "고대부터 인류에게 숭배받던 드래곤이다. 거만하고 고고한 성격으로 아름다운것을 몹시 좋아한다. 화려한 치장으로 자신의 존재감을 드러내며 반짝이는 비늘로 테이머를 홀리기도 한다. 태양과 달의 돌을 이용하여 악한 기운을 잠재우며 세상에 평화를 가져오기도 한다.",
  "코너투스": "바다 깊은 곳에서 살아가는 조용한 드래곤. 독특한 생김새로 인해 많은 드래곤 테이머들에게 묘한 인기를 얻고 있다. 물론 인기의 원인은 호기심이라는 요인이 더 클 것이다.",
  "코랄": "빠른 이동 속도를 자랑하는 수륙형 드래곤. 뛰어난 수영 실력을 지녀 자유자재로 물속을 헤엄친다. 머리에 산호 뿔이 색에 따라 자신의 감정을 표현할 수 있다.",
  "코르투스": "도마뱀 왕국 왕족 혈통이며 최전성기 시절 도마뱀 군단을 이끌며 도마뱀 왕국의 번영을 이루었던 도마뱀 드래곤이다. 거대한 풍채와 단단한 갑옷으로 보는것만으로도 위용이 어마무시하다.",
  "코멧": "태양계 밖, 외우주를 날아다니며 별의 씨앗을 뿌리는 드래곤. 모습에 비해 힘이 좋아 자신의 몸만한 크기의 씨앗을 가지고 다니지만 전혀 힘겨워하지 않는다. 별의 씨앗을 뿌리면 그곳에서 머물다가 다른 우주를 찾아나서는데 운이 좋으면 이때 코멧을 볼 수 있을 것이다. [ 획득가능: 9주년 이벤트 ]",
  "코므니아": "다른 드래곤들이 위기에 빠졌을 때 나타나는 수호자 드래곤. 항상 드래곤들간의 다툼을 정리하는데 앞장선다. 다만 이게 탁월한 리더쉽 때문인지 귀여움 때문인지는 조금 의문이다. [획득조건: 도감점수 달성 ]",
  "코브라곤": "서펀트 드래곤 중 강한 독성을 가진 일부가 변이하여 태어난 드래곤. 매서운 눈매와 더불어 날름거리는 혓바닥은 자신의 사냥감을 집요하게 따라잡는 비밀의 무기. 한번 정한 사냥감은 자신이 죽기 전까지 포기하지 않는 지독함 덕에 이 드래곤을 육성하려다가 포기하려는 겁 많은 드래곤 테이머가 꽤나 많다고 한다. [ 획득가능: 고요의 암석터 ]",
  "코스모": "여행하며 우주를 관찰하고 기록하는 요정 드래곤, 큰 수정구를 타고 다니며 관찰한 것은 수정구에 담아기록한다. 경험 많은 드래곤은 수정구에 더 깊은 우주를 담고 있다고 한다.",
  "코즈메키온": "어느 은하의 중심에서 태어났다고 전해지는 신비한 드래곤. 전설 속에서는 유성우가 내릴 때 나타났다고 전해진다. 날개에는 이미 사라져버린 별들과 은하의 흔적이 남아있어, 수많은 마도학자들이 찾아 헤매는 대상이다.",
  "콘라드": "치명적인 위력을 자랑하는 드래곤. 다른 드래곤과 달리 비행 능력은 모자라지만 강력한 육체 능력을 무기로 활약한다. 10초마다 자신이 생각하는 것을 잊어버리는 심각한 단점이 존재한다. [ 획득가능: 미스터리 뽑기 ]",
  "콜로서스": "무지막지하게 강한 힘을 가진 거대 드래곤. 큰 몸체에 비해 날개가 작아 먼 거리를 날지는 못한다. 무거운 무게를 실은 육탄 공격은 그 어떤 적도 물리칠 수 있다.",
  "쿠로이 드래곤": "숲의 요정이라 불렸던 드래곤. 과거에는 아름다운 생김새와 귀여운 외모로 요정이라 불렸으나, 고약한 질투심과 심한 장난으로 사람에게 미움을 받게 되었다.",
  "쿠베라": "야크샤 드래곤의 일원으로서 역사의 이면에서 악의 무리를 처단해 온, 어둠의 심판자. 일말의 자비심도 없는 것으로 알려진 그는 과거 악에 물들어있던 칼라빈카를 직접 베어버린 바 있다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "쿠알레": "심해의 밝은 빛이 되는 드래곤, 빛이없는 곳을 찾아다니며 어두운 심해를 밝혀준다. 호기심이 굉장히 많아 이곳 저곳을 건드려 말썽을 부린다. [ 획득가능: 미스터리 뽑기 ]",
  "쿠즈마라": "탈릿사의 절친한 친구. 원래 겁쟁이란 이유로 동족에게 멸시와 괴롭힘을 당하다 탈릿사의 도움으로 친구가 되었다. 그때의 은혜를 갚기 위해 용기를 내어 니드호그의 뱃속으로 뛰어들었다.",
  "큐아네드": "테이머 대신 드래곤을 키워주는 드래곤이다. 등의 부화 장치로 드래곤의 알을 품을 수 있다. 주로 버려진 드래곤이나 테이머에게 부탁받은 알을 돌보며 여러 쌍의 날개는 따뜻한 체온을 유지하고 부화장치를 보호 한다.",
  "큐피트용": "사랑을 이어주는 드래곤이라고 알려져 있다. 이 드래곤의 화살에 맞으면 사랑에 빠진다고 하여 활을 훔치려는 이들이 끊임 없다. 하지만 화살로 사랑만 전해 줄 수 있는 건 아니다. [ 획득가능: 메마른 평원 ]",
  "크레바스": "꿈의 여신 샌즈를 수호하며 잠에 들게 하는 능력을 가진 드래곤 중 하나. 그러나 악의 힘에 빠져 적대적으로 변하게 된다. 타락한 크레바스는 파괴의 힘을 얻은 대신 수면 능력을 잃었다.",
  "크레센트": "달의 뿔과 밤의 피부를 가지고 있다. 달이 뜨는 밤을 매우 좋아한다. 누군가를 해치는 것을 별로 좋아하지 않는다.",
  "크레스티드 드래곤": "도마뱀 왕국을 위해서는 자신의 꼬리 손상도 마다하지 않는 드래곤이다. 크레스티드 드래곤은 다른 도마뱀 드래곤들과는 달리 잘려 나간 꼬리는 다시 자라나지 않는다. 이 때문에 드래곤들 사이에선 잘린 꼬리는 영광의 상처로 불리기도 한다.",
  "크로마 뇌신": "큰 구름을 몰고 다니며 날씨와 벌개를 자유자재로 부리는 드래곤. 평소에는 날씨를 조종하여 사람들을 윤택하게 해주지만 악에 빠진 자들에게는 거대한 번개로 천벌을 내린다.",
  "크로마 레굴루스": "네뷸라의 인도 아래 외우주를 떠돌아다니는 드래곤들 중 하나. 성장하면 성장할수록, 강렬해지는 빛으로 자신의 존재감을 뽐내기에 유타칸의 밤하늘에서도 레굴루스가 어디를 향하고 있는지 쉽게 확인할 수 있다고 한다.",
  "크로마 레긴레이프": "비프로스트의 안개를 가르고 대륙의 경계를 침범하는 위협으로부터 세계수의 뿌리를 지키는 드래곤이다. 고산 지대의 험준한 바위 절벽과 끊어진 다리가 맞닿은 비프로스트에서 살고 있다. 브륀힐드의 기운 중 '단절'의 의지를 물려받아 탄생했으며, 검의 형상을 띤 날렵한 팔을 휘둘러 안개 속에서 숨은 위험을 베어낸다. 레건레이프의 힘이 고조되면 신체에 새겨진 룬 문자가 찬란하게 빛나는데, 이때 응집된 마력을 폭발시켜 지형의 흐름을 방해하는 불순한 요소들을 정교하게 도려낸다. 평소에는 짙은 무지갯빛 안개 속을 소리 없이 기동하며, 외부의 간섭이 세계수의 뿌리에 닿지 않도록 경계를 늦추지 않는다.",
  "크로마 루루": "환상의 진주가 있는곳을 알고 있는 인도자 드래곤이다. 가슴에 진주가 박힌 드래곤으로 바다와 하늘을 오가며 생활한다. 그만큼 바닷길과 하늘길에 능통하지만 길잡이를 자처하지 않는다. 길을 잃은 배를 보아도 돕지 않는다. 그럼에도 불구하고 뱃사람들 사이에서 인기가 좋은데, 환상의 진주가 있는 곳으로 안내한다는 소문 때문이다. 실제로 환상의 진주가 있는 곳을 알고 있으며 마음에 드는 자들을 종종 그곳으로 안내한다. 얇고 투명한 비늘은 매우 튼튼하여 거친 물살과 바람에도 찢어지는 법이 없다.",
  "크로마 리치몬드": "금지된 암흑마법에 도전한 고대의 주술사 드래곤. 크리스탈에 강력한 암흑마력을 담을 수는 있었지만 그 대가로 육체를 빼앗기게 되었다. 암흑마력이 담긴 수정구에서 마력을 뽑아내어 강력한 브레스를 뿜어 적의 육체를 소멸시킨다. 육체가 소멸된 적의 영혼을 크리스탈로 흡수하고 암흑마력으로 변환시키는데 적을 무찌를수록 더욱 더 강력한 마력을 지니게 되는 무시무시한 드래곤이다.",
  "크로마 리티오": "풍성한 털과 거대한 날개를 가진 드래곤이다. 거대한 날개는 먼 거리를 거뜬하게 날아갈 힘을 가졌으며, 풍성한 털은 장시간의 비행에도 보온을 유지할 수 있게 돕는다. 리티오의 꼬리 끝은 성장에 따라 병의 치유를 돕는 능력을 갖춘다.",
  "크로마 밀라타스": "빛의 수호자, 고대신룡의 권능 아래 7가지 선을 주관하는 라이트 세븐의 일원이다. 7가지 선 중 겸손을 주관하고 있다. 상대를 존중하고 서로의 다름을 받아들이는 관대함으로 라이트 세븐을 이끄는 리더이다. [ 획득가능: 2021 크리스마스 이벤트 ]",
  "크로마 발레포르": "혼돈의 힘으로 온 세상을 혼돈에 빠트리려고 한다. 혼돈의 틈새에서 제일 간사하고 악한 존재다. 보이지 않는 곳에서 은밀하게 목표를 바라보고 접근하여 달콤한 말을 내뱉은 뒤, 혼돈을 야기한다. 목표를 달성하면 자신은 유유히 모습을 감춰버린다. 가끔 자신의 달콤한 말에 속아 넘어가지 않는 이들도 있지만, 혼돈으로 물든 세상을 염원하고 있어 쉽게 포기하지 않는다.",
  "크로마 베네보렌티아": "빛의 수호자 고대신룡의 권능 아래 7가지 선을 주관하는 라이트 세븐의 일원이다. 7가지 선 중 친절을 주관하고 있다. 어떤 상대이든지 무장해제 시킬 만큼 다정ㄷ감하며 자신의 도움을 바라는 이에게 친절함을 베푼다. 무슨 일이 생기든 인자한 표정을 잃지 않으며 상대를 존중하고 배려한다.",
  "크로마 베타라": "눈이 퇴화하여 시각은 거의 이용하지 못하나, 다른 감각들이 발달했다. 그중 청각이 가장 많이 발달했다. 생명체가 있는 행성만을 골라 공격하며 생명체들을 감염시킨다. 감염된 생명체의 기운은 베타라에게로 점점 흡수되며 기력을 다하면 깊은 잠에 빠진다.",
  "크로마 벨레드": "부정한 기운이 모여 탄생한 드래곤, 좋지 않은 기운을 타고난 이 드래곤은 언제나 분노해 있고, 난폭하기 때문에 주변의 드래곤 혹은 테이머 등이 보이면 이유를 불문하고 공격한다.",
  "크로마 불나래": "꼬리 끝은 언제나 불꽃이 타오르고 있다. 불꽃 크기는 스스로 조절할 수 있으며 악의를 품지 않는다면 그리 뜨겁게 느껴지지 않는다. 평소 화가 나면 모든 것을 태워버리기 때문에 온화한 상태를 유지하기 위해 노력한다.",
  "크로마 블루썬더": "푸른 번개라 불린 돌풍 드래곤. 매서운 돌풍 속에서 모습을 드러내기 때문에 쉽게 발견되지 않는다. 장기인 일렉트릿의 힘은 매우 강력하다.",
  "크로마 스카투스": "수련을 거듭할수록 강해지는 괴력 드래곤이다. 이마의 뿔과 꼬리 끝에서 뿜어져 나오는 보라색 불꽃에는 치유의 힘이 있다. 따라서 스스로 자신의 몸을 치유하면서 게속 공격을 퍼부어서 상대를 쓰러트린다. 대부분의 경우 스카투스는 악의 없이 자신의 힘을 시험하려고 싸우기 때문에 대결이 끝난 후에는 상대의 상처를 치유해 주기도 한다.",
  "크로마 아카이아": "강한 날갯짓으로 들판의 풀을 통째로 뽑아낼 만큼 강력한 바람을 만들어내는 신성한 드래곤이다. 전신을 뒤덮은 부드러운 털은 신성한 기운을 품고 있어, 악한 기운이 담긴 공격을 자연스럽게 튕겨낸다.",
  "크로마 알레샤": "네뷸라의 인도 아래 외우주를 떠돌아다니는 드래곤들 중 하나. 화려하고 아름다운 프릴같은 꼬리는 별의 흐름을 보여준다.",
  "크로마 옥타": "전체적으로 매끈매끈한 몸을 가졌으며, 머리의 촉수와 꼬리에는 접착력이 좋은 강력한 빨판이 달려있다. 등과 팔의 푸른 무늬는 불규칙적이다. 머리의 촉수를 길게 늘려 상대에게 빨판으로 붙어 도망치지 못하게 만든다. 목과 배 사이에는 보석처럼 보이는 눈동자가 달려있다.",
  "크로마 인스트리아": "빛의 수호자 고대신룡의 권능 아래 7가지 선을 주관하는 라이트 세븐의 일원이다. 7가지 선 중 근면을 주관하고 있다. 세상에 일어나는 모든 일들을 기록하며, 이 기록을 바탕으로 계획을 세우거나 미래를 예측한다. 기억의 돌로 자신이 기록한 기록들을 쉽게 찾아 볼 수 있다. 날아다니는 쥐 '플루스'는 항상 인스트리아 주변을 날아다니며 인스트리아를 돕니다. 인스트리아가 가장 아끼는 물건은 이 세상 누구도 본 적이 없는 일기장이다.",
  "크로마 칼리시": "빛의 수호자 고대신룡의 권능 아래 7가지 선을 주관하는 라이트 세븐의 일원이다. 7가지 선 중 자선을 주관하고 있다. 연민의 마음과 고고한 자태로 정의를 실현한다. 편견이나 선입견 없이 생명을 존중하고 공평하게 대하는 인자한 드래곤이다. [ 획득가능: 2021 한가위 이벤트 ]",
  "크로마 크툴루": "상대의 생각을 완벽하게 조종한다. 상대가 눈을 피할 수 없도록 촉수로 상대의 몸을 휘감는다. 이제 촉수의 길이뿐만 아니라 개수까지 조종 가능하여 한 번에 수십, 수백 명의 몸을 묶을 수 있다. 촉수에 묶인 자들은 눈을 마주치지 않고도 생각을 조종할 수 있다. 촉수를 빠져나가려는 얄팍한 수부터 심해를 차지하려는 계획까지, 바꾸지 못하는 생각이 없다. 그들의 생각을 완전히 흔들어 그들을 미치게 만들 수도 있다.",
  "크로마 파이거": "이글거리는 화염의 갈기를 가진 드래곤이다. 파이거는 펄펄 끓는 용암 속을 들어가도 멀쩡할 정도로 열에 내성이 강하다. 몸의 열기는 쉽게 사그라지지 않아 추운 지역에서도 종종 발견된다. 거대한 체구를 이용한 육탄전과 자라면서 길어지는 뿔을 이용한 공격을 한다.",
  "크로마 프로텍트 드래곤": "강력한 방어력을 가진 드래곤으로 빛 속성 드래곤 답지 않게 무거운 몸과 강력한 방어 능력을 가지고 있어 우직한 뚝심과 한 방으로 적을 궁지로 몰아넣는다.",
  "크룩커스": "사람의 악몽에서 자주 등장하는 환상형 드래곤. 불운한 존재로 전해지나 사실 길몽의 상징이기도 하다. 실제로 크룩커스의 꿈을 꾼 테이머들은 트리플 맥스가 자주 뜬다는 소문이 들린다고. [ 획득가능: 미스터리 뽑기 ]",
  "크리마용": "겨울에만 발견된다고 알려진 신비로운 용. 이색적인 장식을 몸에 장식한 것이 특징이며 장식의 색상만큼 활발하고 장난기가 많은편. 들려오는 민담으로는 루돌프를 도와 썰매를 끌었다고 전해진다.",
  "크툴루": "상대의 생각을 완벽하게 조종한다. 상대가 눈을 피할 수 없도록 촉수로 상대의 몸을 휘감는다. 이제 촉수의 길이뿐만 아니라 개수까지 조종 가능하여 한 번에 수십, 수백 명의 몸을 묶을 수 있다. 촉수에 묶인 자들은 눈을 마주치지 않고도 생각을 조종할 수 있다. 촉수를 빠져나가려는 얄팍한 수부터 심해를 차지하려는 계획까지, 바꾸지 못하는 생각이 없다. 그들의 생각을 완전히 흔들어 그들을 미치게 만들 수도 있다.",
  "클라우드 드래곤": "비를 불러온다고 알려진 무형 드래곤. 거대한 크기로 사람들에게 위압감을 주나 실상 구름의 모습이기 때문에 바람이 불면 사라지고 비가 오면 보이질 않는다. 호기심이 많고 장난스러운 성격 탓에 자주 인근 마을에 내려와 사람들에게 장난을 치는 편인데 도가 지나친 장난에 다른 드래곤 테이머에게 혼쭐이 나는 경우가 빈번하다.",
  "키갈": "신속의 날개를 가진 드래곤. 날지 못한다는 이유로 해치 때 무리에서 쫓겨났다. 하지만 성장과 함께 날개가 점점 커지고 누구보다 빠른 드래곤이 된다. 아스티와는 각별한 친구 사이다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "키리온": "어느 괴짜 발명가에 의해 태어난 드래곤.키리온은 인간의 편리,안전을 위해 존재한다.사람의 감정을 이해할수 있고, 그들도 감정이 있다고하는 연구가 알려져있다. 다소 공격적인 성격은 아니지만, 주인을 방어해야할 경우 공격력을 최대치로 끌어올린다.",
  "킨더 드래곤": "작고 귀여운 드래곤. 크기가 너무 작다보니 다 큰 성체의 모습을 해치와 착각할 때가 많다. 심지어 하는 행동까지 장난이 심하고 어리숙한 면이 많아 더더욱 착각하는 사람이 많다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "타나토스": "우리가 알지 못하는 다른 세계에서 온 드래곤. 살해당한 동생의 복수를 위해, 그리고 동생을 되찾기 위해 여러 차원과 세계를 넘나들고 있다. 모든 드래곤을 자신에게 복종시킬 수 있는 강력한 마력을 가졌다고 한다. [ 획득가능: 2021 한가위 이벤트 ]",
  "타라": "수없이 많은 초를 켜놓은 곳에서 기도를 올리던 빛의 사제들은 어느 날 놀라운 생명체와 만나게 된다. 기도를 올리던 초가 날개를 펼치고 움직이게 된 순간을 마주한 것이다. 그 드래곤은 기도를 모두 들었다는 눈빛을 하며 머리의 불같은 뿔을 태웠다.",
  "타로스": "강철과 같은 턱과 용암보다 뜨거운 손톱을 가진 드래곤. 전투에서 뜨거운 성격과 유연한 몸놀림을 고루 갖춘 베테랑의 면모를 보여준다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "타르타로스": "망자의 불꽃을 머금은 수호자 드래곤중 하나로 타로 심연의 옥좌를 지키는 수문장이다. 태어난 방법과 시기에 대해서는 그 누구도 알지 못하지만 망자가 이승에 머물며 악행을 저지를 경우 나타나 심판을 내리는 심판자로 전해진다. [ 획득가능: 미스터리 뽑기 ]",
  "타아비레": "일격에 적을 쓰러트리는 강력한 빛의 힘을 지닌 드래곤. 만에 하나 호기심에 타아비레의 빛의 날개를 만졌다간 몸이 타들어 가는 끔찍한 고통을 체험할 것이다. 이 빛은 오로지 선한 자만이 만질 수 있으며, 악한 자가 빛에 홀려 만진다면 치명적인 상처를 입을 것이다.",
  "타오르는 발칸": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 발칸은 여섯 수호자 중 불을 상징한다. 과거 여신을 노리는 다크닉스에 맞서 타오르는 화염의 힘으로 대적한 용감한 드래곤이다. [ 획득가능: 에스텔라 ]",
  "타이거드래곤": "태어날때부터 호랑이의 무늬와 비슷한 무늬를 가져 타이거 드래곤이라 불렀다. 이는 모든 드래곤들중 순발력이 가장 빠르고 경계심이 강하다.",
  "타이게타": "미트라의 힘을 나누어받은 여섯 드래곤 중 하나. 그중 미트라에 대한 신뢰와 충성심이 제일 드높은 드래곤이다. 앙그라의 감옥을 지키는 것이 주 업무였다. 그래서 앙그라의 탈옥에 대해 죄책감과 분노를 동시에 느끼고 있다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "타이푼 드래곤": "세차게 불어오는 돌풍이 주변에 머물고 있다면 분명 타이푼 드래곤이 머물고 있을 것이다. 이 드래곤은 무시무시한 돌풍부터 고요한 산들바람까지 놀라운 동작으로 바람을 만들어내 상대를 농락하며 그 바람의 속도를 높여 고압의 번개를 선사하는 차징썬더라는 장기 또한 지니고 있다. 성격이 다소 까다로운 편이니 육성시 상당한 주의가 필요하다. [ 획득가능: 청록의 해저화산 ]",
  "타일런트": "물가의 폭군이라고 불리는 괴력형 수중 드래곤. 강한 근육에서 나오는 뛰어난 괴력으로 닥치는 대로 사냥하여 자신의 먹이로 삼는다. 충분히 맞서 싸울 자신이 없다면 이 드래곤을 피하는 것이 가장 효과적인 방법일수도 있다. [ 획득가능: 별빛 산호초 ]",
  "타임머신": "신기한 특이성 드래곤. 타임머신드래곤은 시간을 조종하는 힘을 지녔다. 하지만 이 힘은 단순히 마력을 이용한 마법의 한 종류일 뿐, 시간의 여신 기누의 힘과는 전혀 관련이 없다는 것으로 드러났다. | 원작자: 하늬바람과 민들레",
  "타크샤카": "브리트라를 따라 심해로 달아난 긴나라 드래곤의 일원들. 오랜 심해 생활로 인한 신체변이 속에서도 자신들의 주인을 향한 충성심만은 변함이 없다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "타투": "짙은 갈색의 문양을 몸에 새기고 있으며 성장 되면서 문양이 커지며, 힘을 잃으면 사라진다. [ 획득가능: 무지개 동산 ]",
  "탈릿사": "니드호그에게 고향별과 함께 삼켜진 우주고룡. 다행히 쿠즈마라의 도움으로 살아돌아왔고 이후 니드호그에게 복수할 기회를 엿보고 있다.",
  "태엽 드래곤": "괴상한 외형의 드래곤. 등에 태엽을 감으면 움직임이 3배 빨라진다는 소문이 있으나 엉터리 상인들의 이야기니 신용하지 말것. 몸에 기름칠을 해주는 것을 상당히 좋아한다.",
  "터들톰톰": "성체와 해츨링의 차이가 거의 없기로 유명한 드래곤이다. 친화력이 매우 높아 테이머 뿐만 아니라 다른 드래곤들도 호감을 드러낸다. 특유의 똘망똘망한 눈과 귀여운 걸음걸이는 싸울 의지를 사라지게 만든다. 몇몇 학자들은 싸우지도 않고 강력하지도 않은 드래곤이 어떻게 살아남았는지 연구하고 있다. [ 획득가능: 이벤트, 프리미엄 뽑기 ]",
  "테디 드래곤": "봉제 인형을 닮은 드래곤.푹신푹신하지만 의외로 까칠한 성격을 가지고 있어 가끔 테이머를 당황하게 한다.",
  "테일 드래곤": "7개의 꼬리를 가진 드래곤.늪지에 주로 서식하며,물고기를 주식으로 살아간다.성체가 되면 꼬리를 이용해 공격해먹이를 잡는다. [ 획득가능: 난파선 ]",
  "템페스트": "폭풍을 동반한 드래곤, 뇌운이 동반한 폭풍이 불어올 때, 종종 목격된다고 한다. 언제나 뇌운과 함께 등장하기 때문에 폭풍룡이라는 별명을 가지고 있다. 등장할 때마다 주변을 파괴하기 때문에 사람들은 '재앙'으로 인식하고 있다.",
  "템피오스": "베네토리 대륙의 신성한 사원을 수호한다. 문명을 지키고자 했던 고대 원주민들의 염원이 하나로 모여 형체를 이뤘다. 온몸에 새겨진 문신의 힘으로 공중에 창을 소환한다. 사원을 모독하거나 침입하려는 자를 창으로 처단한다.",
  "토네스": "과거 카데스의 뜻에 따라 세상을 파괴하던 검은 사도들에 대항하여 빛의 사제를 만들어낸 운명을 조율하는 신, 다이즈의 수호 드래곤이다. 밝은 발끝에서 터져나오는 전기로 토네스의 발에 닿으면 섬뜩한 섬광이 폭발한다. 루미네스와 번네스 사이의 중재자 역할을 맡고 있다.",
  "토르": "전사의 낙원을 지키며 시험을 내리는 고대 드래곤이다. 낙원을 찾아온 테이머에게 감각을 깨우는 혹독한 시험을 내리며, 전장에서 스러진 영혼들의 소리를 통해 진정한 자격을 가린다. 낙원에 남겨진 수많은 영혼과 무기들의 주인이다.",
  "토템 드래곤": "이국의 땅에서 소원을 빌어 만들어 냈다고 전해지는 드래곤. 온몸의 문신과 신비스러운 힘으로 토템을 소환하는 능력을 보는 이에게 경외심과 공포를 일으키기 충분하다. 이미 이 드래곤과 전투 상황에 놓인다면 하나의 드래곤이 아닌 드래곤 뒤에 수많은 선조들을 상대할 각오를 해야만 할 것이다. [ 획득가능: 고요의 암석터 ]",
  "토트": "지혜를 기록하는 드래곤이다. 지혜가 담긴 마법석을 가지고 다니며, 이 마법석에 지혜를 기록하거나 꺼내어 사용하기도 한다. 전투에선 항상 중재자 역할을 하지만 패배하는  쪽을 일방적으로 편드는 경향이 강하다. 의지가 강한 자에게 마법을 가르치기도 한다.",
  "톡시닉": "인간의 전쟁터에서 오래 노출되어, 체내에서 자신에게조차 치명적인 생화학 가스를 뿜어낸며 성장할수록 가스 활용도가 높아진다. 전쟁 난민과 함께 떠돌다 유타칸에 도착했다. 테이머에게 방독면은 필수다.",
  "톤톤": "모험을 좋아하는 활기찬 드래곤. 세상에 존재하는 온갖 진귀한 것들, 그 중에서도 보석을 찾는 일에 힘을 쏟고 있다.",
  "투탕카": "파라오 드래곤과 같은 타입에 속하는 왕가의 드래곤. 위엄이 넘치는 왕과 같은 모습을 하고 있어 성스로운 느낌마저 감돈다. 몸에 깊숙이 각인된 왕의 문장은 악한 자를 물리치는 강력한 마력이 숨겨져 있다고 전해진다.",
  "툰드라 드래곤": "극한의 빙설의 계곡에서 살고 있는 드래곤. 한 번만 숨을 내쉬어도 근처의 물체들이 산 채로 얼려지는 무시무시한 광경을 볼 수 있다. 하지만 능력과 반대로 성격은 상당히 나긋한 편이라 알려졌기 때문에 위험성은 적다.",
  "트로페우스": "빛조차 찾을 수 없는 심해에 사는 드래곤. 성장할 수록 더욱 더 깊은 바다 속으로 들어가 어둠의 힘을 흡수해 악과 맞서 싸웠다고 전해진다. [ 획득가능: 토너먼트 마스터 ]",
  "트리페어윙": "세 쌍의 날개가 붙어있는 드래곤. 날개가 많아서 그런지 엄청난 비행속도를 자랑하며 적들을 공격한다.",
  "트와일라잇": "밤이 시작되는 시간에 나타나는 드래곤. 별명은 '저녁 몰이꾼'. 목에 있는 고리는 어떤 생명체든 잠들게 하는 힘이 있다.",
  "티라노 드래곤": "또 다른 이름은 '폭군 드래곤'. 성질이 굉장히 사납고 포악하다.혜성의 충돌 이후 멸종된 것으로 확인 되었으나 최근 학자들이 연구를 통해 알을 복원 하는 것에 성공했다.타고난 사냥꾼으로 거대한 몸에서 폭발적인 스피드를 낼 수 있으며, 날카로운 이빨로 깨무는 턱 힘은 드래곤 중에서 제일 강력하다.",
  "티르": "알이 부화되기도 전부터, 무언가로부터 계시를 받아 단 한번의 싸움을 준비해온 드래곤. 티르는 알 일때부터 매서운 돌풍을 쐬었고 그 결과로 오른팔에 바람의 기운을 담는데 성공하였다. 평소에는 왼팔만을 사용하지만 생사대적과의 전투가 시작되면 오른팔을 휘둘러 적을 찢어발긴다. [ 획득가능: 프리미엄 뽑기 ]",
  "티아매트": "몸과 마음이 모두 뒤틀려버린 삼두 드래곤이다. 각자 다른 자아를 지닌 세 개의 머리를 갖고있다. 온 몸에 페르시온 결정과 산호가 박혀있다. 페르시온 결정의 강한 힘을 본능적으로 알아보고서 간절한 마음에 결정을 마구잡이로 섭취한 뒤 결국엔 페르시온 결정의 힘의에 중독되어버리고 말았다.",
  "티키톡": "쉬지 않고 여신 샌즈의 기억을 기록하며, 기록이 마무리되면, 기억을 도서관 깊은 곳에 숨겨둔다. 기억을 봉인하여 여신이 특정 기억으로 인해 고통받는 것을 막거나, 시간의 흐름을 멈추고 되돌려 위협으로부터 여신의 기억을 보호한다.",
  "틸키": "그림자 세계의 모래별에서 찾아온 드래곤. 부상 중이던 카라선을 도와주고 열쇠를 하나 선물받는다. 그리고 카라선이 말했던 유타칸에 대한 꿈을 꾸던 어느날, 열쇠가 밝게 빛나기 시작한다.",
  "팀버 드래곤": "오래된 물건에 생명이 깃들듯 오래된 고목에 드래곤이 영령이 잠들어 변화된 드래곤. 숲의 수호자 엔트와 같이 자신의 숲을 지키는 드래곤으로써 숲을 파괴하지 않는다면 온화한 미소로 여행자들을 바라보고만 있을 것이다. 물론 실수라고 해도 꽃을 밟거나 나무를 부러트린다면 그 온화한 눈빛은 매서운 증오로 변해갈 테지만...",
  "파고스 드래곤": "물과 냉기의 힘을 다루는 드래곤. 굉장히 쌀쌀맞고 차가운 성격을 지니고 있다. 흔치않게 웃는 모습을 보일 때도 있는데 한번 보면 두번다시 잊을 수 없는 미소라고 한다.",
  "파라오곤": "동방의 마법사들이 신비로운 주술로 부활시킨 왕의 드래곤. 신적인 마법능력을 지니고 있으며 악한 이들이 사악한 목적으로 부활시켰지만, 선한 왕의 선한 영혼이 깃들어 악한 일에 쓰이지 않았다. 내면적인 공격에서 강력한 능력을 자랑한다. [ 획득가능: 미스터리 뽑기 ]",
  "파루파루": "씨앗을 통해 가족과 하나 되고자 하는 꿈을 이루고자 한다. 따뜻한 환경에서 자라난 가족과는 달리, 얼음별에서 태어나 가족과 다른 모습을 지닌 채 탄생했다. 가족들과 같은 모습을 갖기 위해 따뜻한 날에만 피어난다는 씨앗을 돌본다. 씨앗을 발아시키려고 추운 바람과 눈보라 속에서도 씨앗을 품으며, 따뜻한 온기를 불어넣는다. 얼음별 곳곳을 다니며 적합한 장소를 찾거나, 주변을 따뜻하게 만들기 위해 열심히 노력한다. 그 어느 때에도 포기하지 않으며, 가족과 하나 될 날을 상상하면서 씨앗을 정성스럽게 돌본다.",
  "파베르": "얼굴쪽에 입같은것이 있지만 사실 입은 아니다. 먹이를 먹을 때 음식을 고정시켜주는 역할을 하며 독이 나온다. 가슴쪽에 있는 구멍에서는 환각을 보게하는 빛이 나오며 파괴광선도 나올 수 있다고 한다. 성격이 매우 괴팍하다.",
  "파브레가스": "진공의 힘을 지닌 사나운 마력 드래곤. 매서운 마력의 힘은 그 어떠한 적도 용서치 않는다. 한번 날아간 마력의 힘은 적을 끝까지 추격하는 무서운 능력을 지녔다. [ 획득가능: 미스터리 뽑기 ]",
  "파워 드래곤": "드래곤 중 가장 센 힘을 가진 드래곤. 앞발이 엄청 발달해 있다. 성격은 온순한 편. 태어나면서부터 엄청난 힘을 가지고 태어난다. [ 획득가능: 희망의 숲 ]",
  "파이거": "이글거리는 화염의 갈기를 가진 드래곤이다. 파이거는 펄펄 끓는 용암 속을 들어가도 멀쩡할 정도로 열에 내성이 강하다. 몸의 열기는 쉽게 사그라지지 않아 추운 지역에서도 종종 발견된다. 거대한 체구를 이용한 육탄전과 자라면서 길어지는 뿔을 이용한 공격을 한다.",
  "파이썬": "암각의 시린 가장 어두운 곳을 추구하는 환상의 드래곤. 대지의 시초 또는 대지의 사자라고 불리웠다. 혜성의 충돌 이후 사람들에게 목격된 적이 없었다고 전해진다. [ 획득가능: 카드코드, 프리미엄 뽑기 ]",
  "파이어 드래곤": "불을 먹고 산다고 전해지는 드래곤.주로 뜨거운 지역에서 생활하며 불을 좋아한다.호전적이며 불같은 성격을 지녔다. [ 획득가능: 불의 산 ]",
  "파이어리 블랜드": "폭열의 불꽃을 지닌 마력형 드래곤. 성장하면서 붉은 뿔의 크기가 점차 커지는 것이 특징이다. 적을 향해 브레스를 쏘기보다 힘껏 내달려 강력한 박치기 일격을 가하는 것을 좋아한다.",
  "파이어퓨리": "맹렬히 타오는 화염의 힘을 지닌 폭열성 드래곤. 아무리 불타는 화염 속에서도 평정심을 유지한 체 전투할 수 있다. 다만 물이나 추운 곳에서는 힘이 급격히 약해진다. [ 획득가능: 미스터리 뽑기 ]",
  "파키": "멸종된 박치기 공룡을 닮은 드래곤이다. 이름도 그 공룡에서 따왔다. 이마에 난 뿔은 크고 단단해 암석을 깰 수도 있다.",
  "파티 드래곤": "경사스러운 날에 자주 보이는 귀여운 생김새의 드래곤. 과거부터 다양한 축제에 이용된 만큼 타인을 즐겁게 만드는 재주가 뛰어나다. 성격이 명랑하여 각종 복지기관에서 환자를 돌보거나 격려하는 프렌드 드래곤으로 맹활약하고 있다.",
  "파프니르": "저주받은 보물에 홀려 타락한 고대 드래곤이다. 한때는 보물을 모으는 것을 즐기는 온순한 성격이었으나, 저주받은 유물을 손에 넣은 뒤 탐욕과 분노에 잠식되었다. 레무리아 봉인의 시기, 발두르의 부탁드로 '카닐'을영원한 저주의 불꽃으로 감쌌으며, 이후 외부로부터의 침입자가 없도록 감시했다.",
  "파프닐": "오랫동안 동굴의 소중한 보물을 지켜온 저주의 용. 파프닐이 있는 동굴에 보물을 찾으러 간 사람들은 영영 볼 수 없다고 전해진다. 장시간 한자리에 머물렀기에 시력과 비행능력이 저하되었으나 파괴력은 상상 이상이다.",
  "파프리온": "전설로 전해지는 심해 신전의여신 레오나의 여섯 수호 드래곤중 하나 파프리온은 여섯 수호자 중 물을 상징한다. 맹렬한해일을 불러오는 힘을 지녔으며,레오나를 안전한 곳으로이동시켰다고 전해진다. [ 획득가능: 에스텔라 ]",
  "판므니아": "절망에 빠진이들을 관찰하여 절망의 순간에 나타나 희망의 씨앗을 주는 드래곤 특유의 희망찬 목소리 때문에 듣기만해도 기쁘다.",
  "팡팡": "몸이 매우 가벼워 태풍이 불면 날아가는 경우도 있다. 바람에 휩쓸리며 상처를 입어 몸이 줄어드는 경우 또한 존재한다. 얇고 투명한 비늘은 상처가 잘 나지만 공기가 있다면 바로 회복할 수있다. 대부분 팡팡은 아이들의 웃음에 기쁨을 느낀다. 등에 아이들을 태우고 하늘을 나는 경우가 많으며 행사가 있는 곳에 종종 나타나기도 한다. 풍선으로 행사장을 꾸미거나 아이들에게 선물을 주고 사라지는 경우가 종종 목격된다.",
  "패트 드래곤": "새끼때는 겁이 많아서 숨어 지내지만 점점 어른이 되면서 몸이 커진다. 매우온순하고 약해 보이지만 먹이를 뺏기면 포악해져서 무서워지는 드래곤 [ 획득가능: 희망의 숲 ]",
  "퍼플립스 드래곤": "신비로운 색상의 드래곤.이마에 위치한 보석의 아름다움은많은 사람의 탐욕을 불러일으킨다.이 때문에 수렵의 목적이 되는 경우가 많다. 인적이 뜸한 지역이나 험한 지형에 서식지를 정한다. [ 획득가능: 미스터리 뽑기 ]",
  "페로스": "차원문을 열 수 있는 문지기 드래곤. 빛과 어둠의 전쟁 당시 포르타, 디아누와 함께 차원문을 열고 닫으며 수많은 드래곤들을 지켜냈다. 페로스는 차원문의 열쇠로 페로스의 차원의 열쇠는 차원을 넘어 마음먹은 곳으로 이동할 수 있다.",
  "페르마타": "악령이 깃든 방울에서 태어난 드래곤. 악령의 영향인지 굉장히 끔찍하고 난폭한 장난을 좋아한다. 소름끼치는 방울소리와 더불어 가까이 하기 꺼려지는 드래곤. 제일 좋아하는 것은 자신을 두려워하지 않는 자로 그 사람을 위해서는 뭐든지 한다.",
  "페어리 드래곤": "요정이라 불리는 드래곤이다.아름다운 날개가 특징이며 매우 화려한 색을 가지고 있다. [ 획득가능: 옛 성터 ]",
  "페이렉스": "요정의 땅을 지키는 요정 드래곤이다. 나무, 꽃과 같은 식물과 자연의 힘을 흡수하여 가슴의 주황색 보석에 저장했다가. 요정의 기운이 필요한 순간 가지고 있던 요정 꽃으로 그 힘을 방출한다.",
  "페이몬": "빛나는 왕관을 쓴 군주 드래곤, 외모와 목소리가 아름다워 명성이 높다고 한다. 비발과 아발람이라는 심복을 데리고 있으며 수많은 군단이 따르고 있다.",
  "페이퍼 드래곤": "종이로만 만들어진 기묘한 드래곤. 알록달록한 색상과 신기한 생김새로 아이들에게 인기가 많다. 다소 사나운 구석이 있으니 조금 육성에 신경 쓰는 것이 좋다.",
  "페트라드래곤": "사악한 것을 태우는 업화 드래곤. 말소자와 마찬가지로 악을 물리치는 숭고한 임무를 행하는 존재. 차분하고 냉철한 성격을 지녀 수준 높은 실력을 지닌 테이머들에게 큰 사랑을 받는다.",
  "페트로아": "화염의 힘을 자유자재로 다루는 드래곤. 부화되기 이전부터 자신을 지켜주고 도와주는 에메랄드 스네이크와 함께 유타칸을 탐험한다고 한다. 다 자라도 자신을 해치로만 생각하는지, 먼저 나서는 에메랄드 스네이크에게 약간 불만도 있다고 한다. [ 획득가능: 2021 빛의 축제 이벤트 ]",
  "펜리르": "날카로운 발톱과 이마의 뿔로 자기 마음에 들지 않는 것들을 부숴버리는 포악한 드래곤. 처음에는 착하고 부드러운 성격이었지만 무엇인가를 계기로 모든 것을 적대하게 되었고 누군가와의 전투에서 강탈한 망치를 자유자재로 다루게 되면서 한층 더 강력해졌다.",
  "평탄한 에닉스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 에닉스는 여섯 수호자 중 땅을 상징한다. 숲과 대지를 다루는 능력으로 레오나를 노리는 악에 맞서 싸웠다고 전해진다. [ 획득가능: 에스텔라 ]",
  "포레스트 드래곤": "숲을 지킨다고 전해지는 숲의 드래곤. 머무는 자리에는 항상 맛좋은 열매와 숲의 우거졌다고 전해진다. 숲을 보호하는 성격이 지나쳐 숲을 파괴하는 사람에게 난폭한 모습을 보이는 경우도 많다.",
  "포르타": "차원문을 만들고 차원을 경계하는 파수꾼 드래곤. 빛과 어둠의 전쟁 당시 페로스, 디아누와 함께 차원을 열고 닫으며 수많은 드래곤을 지켜냈다. 포르타의 차원문은 차원의 시작과 끝에 만들어지며 자신이만든 차원문들을 통해 이동할 수있다.",
  "포말하우트": "하늘의 별 중 가장 밝은 일등성과 같은 빛나는 개성을 가진 드래곤, 이 드래곤의 꼬리와 눈동자는 은하수 처럼 반짝거리며, 자신들의 꼬리를 매우 소중히 여기고 있다.",
  "포메쿨": "거대한 어금니로 적을 물어뜯는 드래곤. 날렵한 움직임으로 먹잇감을 농락하는 모습은 하얀 번개와도 같다. 렉스톤을 별로 좋아하지 않는다.",
  "포이즌리버": "단 한방울의 피로 강물을 독으로 물들여버리는 드래곤. 만지기는 커녕 함부로 다가가는 것조차 위험하다. 체액은 물론 그 숨결에도 강력한 독성분이 포함되어 있기 때문이다. [ 획득가능: 아르하의 입구 ]",
  "포포모": "벚꽃이 피는 근처에 서식하는 요정 드래곤. 귀여운 외모로 인기가 많지만 워낙 자유분방한 성격이라 말썽을 자주 피운다. [ 획득가능: 일반 레이드 ]",
  "포폰": "강력한 힘을 지닌 괴력형 드래곤. 거대한 덩치와는 다르게 상당히 소심한 성격. 작은 변화에도 놀라 야단법석을 떠는 경우가 많다.",
  "폭염의 발칸": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나인 발칸은 여섯 수호자 중 불을 상징한다. 과거 여신을 노리는 다크닉스에 맞서 타오르는 화염의 힘으로 대적한 용감한 드래곤이다. [ 획득가능: 에스텔라 ]",
  "폭포의 파프리온": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 파프리온은 여섯 수호자 중 물을 상징한다. 맹렬한 해일을 불러오는 힘을 지녔으며, 레오나를 안전한 곳으로 이동시켰다고 전해진다. [ 획득가능: 에스텔라 ]",
  "폭풍의 라이오스": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 라이오스는 여섯 수호자 중 바람을 상징한다. 폭풍과 같은 능력으로 최선을 다해 여신 레오나를 지킨 수호 드래곤이다. [ 획득가능: 에스텔라 ]",
  "폴투누스": "깊고 어두운 바닷속 해저에 서식한다고 알려진 드래곤. 폴투누스는 자라면 자랄수록 더 깊은 바닷속으로 들어가기에 깊은 바다의 수압도 견딜 수 있는 단단한 껍질을 지니게 된다고 한다. 물의 기운을 자유자재로 부려 이동이나 사냥에 사용한다. [ 획득가능: DVX 이벤트 ]",
  "푸딩곤": "굉장히 맛있어보이는... 드래곤. 하지만 그 말랑한 외양과 다르게 정의롭고 용감한 드래곤이다.",
  "푸투룸": "여명과 황혼의 주인인 아실리와 옵타툽을 지키는 세 마리의 수호자 드래곤 중 하나. 푸투룸은 강력한 근력을 이용해 적을 물리쳤다. 과묵하고 표현은 적었지만, 누구보다 꿈의 세계를 걱정하던 드래곤으로 항상 재앙의 밤인 크레바스를 물리치기 위해 노력했다. [ 획득가능: 도전의 전장 ]",
  "퓨미스": "마력의 붉은 보석을 지닌 신비한 보옥형 드래곤. 지성이 뛰어난 드래곤으로 멋진 생김새에 걸맞게 많은 테이머에게 인기를 독차지하고 있다. 최근에는 유명세 덕에 퓨미스의 알의 가치가 높아져 일부 테이머는 큰 불만을 표출하고 있다.",
  "프라이드": "어둠의 수호자 다크닉스의 권능 아래 7가지 악을 주관하는 다크 세븐의 일원이다. 다크 세븐의 리더이며 7가지 악 중 오만을 주관하고 있다. 다크닉스의 앞에서조차 허리를 굽히지 않을 정도로 거만하며 상대의 욕망을 이용해 스스로 자멸하도록 만든다. 오직 자신만이 우월하다고 믿는 악의 귀공자다.",
  "프랑켄슈타곤": "불온한 실험 때문에 태어난 드래곤. 무서운 외모와는 달리 많은 상처와 아픔을 겪은 만큼 마음이 여리다. 작은 호의에도 크게 반응한다는 점이 더 가슴을 아프게 한다. [ 획득가능: 미스터리 뽑기 ]",
  "프레데터": "잠들었을 때 적이 다가오더라도 붉게 빛나는 안광으로 단번에 잡아내기 때문에 '잠들지 않는 눈'이라는 이명이 붙었다.",
  "프레이야": "자신만의 행성을 만들어 내고 보살피는 드래곤이다. 다양한 종족이 살아가는 큰 행성이 아닌 스타시드가 발아한 작은 행성을 지니고 있다. 행성은 항상 밝게 빛나며 두 마리의 정령이 그것을 수호한다. 우주 공간을 떠돌며 스타시드의 힘이 줄어든 행성으로 내려가서 힘을 채워주기도 한다.",
  "프로그 드래곤": "주로 물속에서 알을 낳기 때문에 알을 보기란 힘들다. 화가나면 볼주머니가 커진다. 볼주머니가 커지면 피하는 것이 상책! [ 획득가능: 난파선 ]",
  "프로딘": "고대부터 사람들이 사는 곳으로 내려와 재앙을 내리는 용. 사람들은 재앙을 피하기 위해 소년들의 꿈을 바치고 제사를 지냈다. 꿈을 바친 소년들은 달이 뜨지 않는 날 악몽에 시달린다",
  "프로스티": "고위도 추운지방에 분포, 추운지방에 서식해서 몸에 깃털이 둘러져 있다. 거의 집단으로 생활한다.",
  "프로즌": "아름다운 자태의 서리 드래곤. 프로즌의 날갯짓소리는 얼음 때문인지 매우 맑은 소리가 난다고한다.",
  "프로텍트 드래곤": "강력한 방어력을 가진 드래곤으로 빛 속성 드래곤 답지 않게 무거운 몸과 강력한 방어 능력을 가지고 있어 우직한 뚝심과 한 방으로 적을 궁지로 몰아넣는다.",
  "프리러너": "대지의 축복을 받은 고속이동 드래곤. 바람의 가호와 땅의 축복을 받아 빛처럼 대지를 질주할 수 있다. 프리러너는 전력으로 질주 할 경우 날아가는 윙스드래곤 조차 프리러너를 붙잡지 못한다.",
  "플라워 드래곤": "숲의 정령인 오움들과 같은 공간에서 서식하는 신비한 드래곤. 봄날의 가장 화창한 아침과 가을의 석양의 잠드는 숲 속에서만 잠시 등장한다고 전해져 이 드래곤을 얻고자 하는 극성팬 드래곤 테이머가 많은 편… 하지만 플라워 드래곤을 한번 만이라도 보게 된다면 자연스레 그 극성팬 무리에 합류하고 말 것이다. [ 획득가능: 별빛 산호초 ]",
  "플래그너": "전기의 힘을 다루는 드래곤. 벼락이 떨어지거나 전기가 흐르는 곳에 주로 서식한다. 꼬리에 있는 코드로 에너지를 흡수해 항상 꼬리에는 강력한 전류가 흐르고 있다. 생각보다 온순한 성격을 가지고 있다.",
  "플레임 드래곤": "폭열성 드래곤 플레임 브레스는 뜨거운 불 속에서 집단 생활하는무리 드래곤의 일종. 파이어 드래곤과 비슷하다는 부류로 인식되나 실상 그 성격이 판이하게 다르기 때문에 같은 부류로 정하는 것은 큰 오류라 판명된다. 불드래곤 치고 조용한 편이며 자신의 이득이 되지 않는 행동은 절대 하지 않는 합리적인 성격의 존재들이다.",
  "플로레": "고목을 닮은 모습이며 운명을 예지하는 운명 드래곤이다. 빛과 어둠의 전쟁 이전, 다크닉슬르 따르던 시크레타 중 한 드래곤이다. 수많은 운명을 예지하였으며, 세상에 공허를 일으키려는 논을 물리쳐야 하는 자신의 운명도 예지하였다. 플로레가 운명을 볼 때면 세 번째 눈이 빛나곤 하는데, 이때 펼쳐진 운명은 필연으로 이어진다. 생명의 탄생, 죽음, 사고 등 어떠한 기준점이 있는 것은 아니기에 플로레의 세 번째 눈이 빛난 경우에 대해서는 현재까진 밝혀진 바 없다.",
  "플로리안": "공존과 화합이 이루어지는 이상적인 세계에서만 서식하는 드래곤. 숲의 생명을 돌보는 수호자 역할을 맡고 있으며 지나가는 곳에 행복을 전하는 꽃이 핀다고 한다.",
  "피닉스": "불에서 태어나 죽으면 다시 알로 태어난다고 전해진다.죽으면 알로 다시 태어나기에 불사조라고 불린다.온몸에 불을 휘감고 있다. [ 획득가능: 불의 산 ]",
  "피데스": "다크닉스를 따르며 불가능에 가까운 명령을 따라온 이 드래곤은 온몸에 벼락과 같은 흉터를 지니고 있다. 내려오는 명령은 항상 옳다고 믿기 때문에 다크닉스를 향한 충성심이 어마어마하다. 벼락을 내리치는 날개로 날아다니는 속도는 어느 드래곤과 비교해도 월등하게 빠르다.",
  "피미루": "오랫동안 버려져있던 피아노에 지나가던 악몽이 영혼을 불어넣어 생겨난 용. 성장하며 미쳐가고 잔인해져간다. 이 용을 키울 때는 생을 마칠 각오를 하고 키워야 한다. 그리고 테이머에겐 매일 밤마다 악몽을 불어넣는다. 의외로 잘 보살펴 준다면 악몽을 거둬가거나 아름다운 연주를 들려줄지도... | 원작자 : YB |",
  "피스 드래곤": "평화를 사랑하는 과학자가 의문의 조합법으로 탄생시킨 드래곤. 성격이 온순하고 사람들과 쉽게 친해져 순둥곤과 더불어 많은 사람들의 인기를 받고 있다. 주로 복지시설에 투입되는 만큼 이름 값어치를 증명하는 듯하다.",
  "피싱테일 드래곤": "강을 오염시키는 자들을 처단한다. 잡은 물고기를 통해 얻은 정보로, 강의 생태를 위협하는 자들에게 긴 꼬리로 만든 회오리를 보낸다. 손끝에는 물에 사는 생물들의 상처를 치유하는 능력이 있어서 바늘 때문에 생긴 상처도 곧바로 치료한다.",
  "피타야": "과일 용과를 닮은 화려한 드래곤이다. 피타야의 몸에 나는 꽃의 향기는 멀리서까지 향기로운 향을 느낄 수 있다고 한다. 피타야의 향은 바람을 타고 나아가 환각을 일으키게 만들기도 한다. 피타야의 꽃을 허락 없이 따면 바로 시들어버리기 때문에 피타야 모르게 꽃을 얻을 수는 없다.",
  "픽셀 드래곤": "네모난 세상에서 찾아온 드래곤. 각진 외형과 달리 친절하고 밝은 성격의 소유자. 어쩐지 보고 있으면 과거의 향수가 떠오른다.",
  "핑크벨 드래곤": "숲의 요정이라 불렸던 드래곤. 과거에는 아름다운 생김새와 귀여운 외모로 요정이라 불렸으나, 고약한 질투심과 심한 장난으로 사람에게 미움을 받게 되었다.",
  "하데스": "깊고 깊은 저승의 심연에서 태어난 드래곤. 붉게 빛나는 눈에는 지상의 살아있는 모든 것에 대한 분노가 깃들어 있다",
  "하레스": "지옥의 파수꾼을 맡은 드래곤. 죽은 이를 지옥까지 인도하는 역할을 맡고있다. 들고 있는 낫은 한때 지옥에서 난동을 부린 지옥새로 만든 것이다.",
  "하리카": "틸키의 절친인 드래곤. 갑자기 여행을 떠난 틸키를 찾아 유타칸을 찾아왔다. 삭막한 모래별에서 살아서 그런지 외로움을 많이 탄다.",
  "하이페리곤": "별의 힘을 지닌 별빛의 드래곤.밤하늘을 수놓는 아름다운 별 무리 중무언가 움직인다면 필시 이 드래곤일가능성이 높다. 하이페리곤은자유자재로 별의 힘을 사용하며,별빛이 많은 밤에는 더욱 큰 힘을발휘할 수 있다.",
  "하트샤": "강력한 브레스로 수많은 행성을 혼란에 몰아넣고 파괴한다. 과거 미트라의 여섯부하중 하나로, 행성의 질서를 수호하는 사명을 지닌 존재였다. 그러나 현재는 질서를 지키려는 의지에 반기를 들고서 자신의 브레스로 행성을 완전히 파괴하고 곳곳에 혼란을 퍼뜨리는 길을 선택했다. 깊은 분노와 배신감을 느끼며 파괴를 일삼을수록 하트샤의 가슴은 점점 까맣게 물들어간다.",
  "할로우": "강력한 힘을 지닌 혼령 이식 드래곤. 과거 숱한 전투를 승리로 이끈 용사의 혼을 빌어 만든 존재. 붉게 타오르는 눈은 적에 대한 무한한 증오와 과거의 애틋한 기억을 추억하고 있다. [ 획득가능: 미스터리 뽑기 ]",
  "할루시": "환각을 보여주며 장난치는 걸 좋아하는 드래곤. 목걸이에 달린 보석의 힘으로 환각을 일으킨다고 한다. 그 외에도 많은 보석을 모으고 있으며 남이 자신의 수집품을 만지는걸 극도로 싫어한다.",
  "할리벨": "빛의 보물이라 불리는 새하얀 드래곤. 하늘거리는 백색의 털은 빛을 받을 때마다 보석과 같이 반짝인다. 신기하게도 악한 자에게는 이 드래곤이 보이지 않는다고 하니… 욕심이 많은 드래곤 테이머는 영영 만날 수 없을지 모른다.",
  "합라": "신비한 보석을 이용해 적을 공격하는 드래곤.정체를 알 수 없는 보석이 빛을 발할 때마다 합라는 강력한 힘을 발휘한다. [ 획득가능: 챔피언 대전 ]",
  "해마곤": "물의 여신 레오나의 여섯 수호자의 보호 아래에 살아가던 바다 드래곤. 겁이 많고 다소 소극적인 성격을 지녔으나 그러한 성격을 무색하게 만드는 무시무시하고 세찬 파도를 만들어내는 힘은 보는 이를 절로 감탄하게 하는 마력을 지녔다. 물론 이러한 능력을 사용하면 쉽게 지치는 탓에 상대방에게 맞서기 보다 도망치는 것이 더 많은 편. [ 획득가능: 별빛 산호초 ]",
  "해일의 파프리온": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 파프리온은 여섯 수호자 중 물을 상징한다. 맹렬한 해일을 불러오는 힘을 지녔으며, 레오나를 안전한 곳으로 이동시켰다고 전해진다. [ 획득가능: 에스텔라 ]",
  "해태드래곤": "해태의 의지를 물려받은 동양의 사신 중 하나이다.",
  "허리케인": "돌풍을 먹고 사는 드래곤. 머문 자리에 돌풍으로 인한 피해가 생겨 악귀로 여겨지지만, 실제로는 돌풍을 먹어 없애는 착한 드래곤이다.",
  "헝그리 드래곤": "먹성이라면 패트 드래곤과 라이벌이라고 해도 무색한 거대 비만 드래곤.항상 손에 먹을 것을 들고 다니지 않으면 성격이 180도로 변해 난폭해지는 단점이 있으니 반드시 참고해 둘 것! [ 획득가능: 미스터리 뽑기 ]",
  "헤네스": "그림자 여신을 받드는 사도 중 현명함을 추구하는 드래곤. 행운과 지혜를 모두 갖춘 자만이 그녀를 만날 수 있다. 지성과 기민함이 함께하는 그대에게 빛이 있으라.",
  "헤라클레스곤": "환상 속에 존재한다는 숲, 에메르에서 온 의문의 드래곤. 두꺼운 갑피와 거대한 뿔은 흡사 곤충의 제왕 헤라클레스를 연상시키며, 무시무시한 생김새와 이름처럼 강력하고 뛰어난 전투력을 자랑한다.유별난 점이라면, 특이 식성으로 젤리라는 음식을 즐겨 찾는다고 전해진다.",
  "헤이즈": "신비한 외모로 유명한 비행형 드래곤. 헤이즈의 기묘한 생김새는 많은 테이머의 호기심을 자극한다. 고지식한 학자들 일부는 이 수수께끼의 드래곤을 색안경을 쓰고 비판하지만 테이머들 사이에서는 귀여운 외모와 높은 전투능력으로 날이 갈수록 인기가 높아지고 있다.",
  "헤임달": "과거를 꿰뚫어 보며 비프로스트를 지키는 고대 드래곤이다. 찾아온 테이머에게 공포를 이겨내고 나아갈 수 있는지를 시험하기 위해, 환영을 펼친다. 미미르와 볼바에 버금갈 정도로 깊은 지혜를 지녔으며, 전투에 걸맞게 단련된 몸을 가지고 있다. 비프로스트 너머로 통하는 길을 지킨다.",
  "헤카테": "달의 사제 드래곤, 달과 대지와 지하의 영향을 미치는 드래곤으로 죽은자들을 인도 한다고 한다. 죽은자들의 정화와 속죄를 도와준다. ",
  "헬 드래곤": "지옥의 불길을 머금은 드래곤. 매우 포악하며 부수는 것을 좋아한다. 헬 드래곤을 만나면 도망치는것이 좋겠다. [ 획득가능: 불의 산 ]",
  "헬가스트": "지옥의 새라고 불리는 드래곤. 이름의 유래는 정확하지 않지만, 무시무시한 전투력과 사나운 성질에 의해 붙여졌을 가능성이 높다.",
  "헬스페로우": "지옥의 불꽃을 사용하는 드래곤. 지옥의 칼인 헬소드에서 무시무시한 불꽃이 뿜어져 나온다. 드래곤이 성장함에 따라 헬소드도 함께 성장한다.",
  "헬카이저": "카데스의 명령으로 아르하를 지배중인 드래곤. 뛰어난 지능을 바탕으로 교활하고 잔인한 전략을 구사한다. 그와 동시에 아르하의 모든 수호룡을 쓰러뜨릴 정도의 강력한 힘을 가진 무시무시한 존재. [ 획득가능: 증명의 탑 ]",
  "현무 드래곤": "거북과 뱀의 몸을 가진 동양의 사신 중 하나이다.",
  "호드": "서리 해안에 사는 얼음 드래곤들의 수장이다. 어깨에 붙은 사슬 모양의 빙하로 짙은 얼음 안개를 만들어 은신하는 능력이 뛰어나다. 세계수를 위협하는 니드호그 무리가 나타나자, 그들의 편으로 들어가서 정보를 빼오는 스파이 역할을 자처한다. 내막을 모르는 대부분의 드래곤들이 호드를 배신자로 여기지만, 호드는 묵묵히 자신의 임무를 수행한다.",
  "호저리": "한 땀 한 땀, 열심히 기워 만든 알록달록한 양말이 아이들의 소원을 가득 담아 드래곤이 되었다. 원하는 선물이 들어있기를 바라며 양말을 만졌더니, 만져지는 건 드래곤이었다! 부들부들한 양말의 촉감이 기분 좋아지는 드래곤이다.",
  "호크아이": "뿔을 활로 사용하는 특이한 드래곤. 원래는 단단한 뿔이지만 성장함에 따라 탄력을 가지게 된다. 꼬리가 아닌 5번째 다리를 이용해 활을 당기며 화살은 자신의 날카로운 깃털을 사용한다.",
  "혼": "전쟁이 일어나면 죽은 드래곤의 혼을 모아가는 드래곤. 영혼을 다루는 힘을 가지고 있으며 높은 산에만 서식한다고 한다. 혼을 많이 모을수록 더 강한 힘을 발휘한다.",
  "화귀 드래곤": "사방을 불태우는 화염 드래곤. 무엇인가 강렬한 의지를 담은 물체에 담겨있다. 어떤 사건이 단초가 되면, 큰 화염을 일으키며 나타난다. 화귀가 일으키는 화염은 마음 속의 기운이기 때문에 어떤 마음가짐을 가지느냐에 따라 다른 힘을 가진다고 한다.",
  "화랑": "강력한 힘을 지닌 폭열성 드래곤. 겉모습과 비슷한 호쾌한 성격을 지녀, 갓 여행을 시작한 초보 드래곤 테이머에게는 힘겨운 육성 상대로 알려졌다. 하지만 그 노력에 상응하는 막강한 전력을 보장할 수 있을 것이다.",
  "화이트 디스트로이어": "한때 빛의 기사였으나 타락하였다. 여전히 빛의 갑옷을 두루고 그 힘을 이용하고 있지만 속은 검게 타오르고 있다.",
  "화이트스톰": "추운 설산에서만 태어나는 드래곤. 그때문인지 차갑고 냉정한 성격을 지니고 있다. 하지만 자신의 테이머에겐 따뜻하다.",
  "화이트썬더 드래곤": "이름 그대로 번개를 다루는 새하얀 드래곤이다. 굉장히 아름다운 모습과 색을 가지고 있지만 사실은 사납고 거칠기 짝이 없는 드래곤. 거스트 드래곤을 '진짜로' 미워한다.",
  "화주사": "특정한 지역에서 수호사자라 불리는 드래곤. 한 지역에 재앙이 닥쳐오는 것을 막아준다. 목에 있는 호박구슬은 목숨과도 같다.",
  "후긴": "흰 까마귀 영토를 지키는 고대 드래곤이다. 흰 몸을 가졌으며 장난스러운 성격과 반짝이는 것을 좋아하는 어린 모습을 보인다. 찾아온 테이머에게 강력한 마석 '카닐'의 유혹을 이겨낼 수 있는지 시험한다.",
  "흐레스벨그": "어린 드래곤이 악의 세력에게 빠지지 않게 가르친다. 흐레스벨그의 능력으로 부화된 드래곤은 흐레스벨그를 믿고 따른다. 흐레스벨그는 어린 드래곤이 악의 세력에게 넘어가는 것을 막기 위해 세상의 이치와 옳고 그름을 가르치고, 다른 생명과 조화롭게 살아가는 법에 대해서도 알려준다. 한 번에 많은 드래곤을 돌보는 것이 아니라, 한 마리가 때가 되어 곁을 떠나면 다시 새로운 드래곤을 찾아 돌본다.",
  "흐르는 파프리온": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 파프리온은 여섯 수호자 중 물을 상징한다. 맹렬한 해일을 불러오는 힘을 지녔으며, 레오나를 안전한 곳으로 이동시켰다고 전해진다. [ 획득가능: 에스텔라 ]",
  "흐므니아": "드래곤이 신기한 드래곤. 어떤 드래곤이라도 발견만 하면 사랑스러운 표정을 지으며 다가간다. 자기가 가장 귀여운 줄은 모르는 것 같다 [획득조건: 도감점수 달성 ]",
  "흑룡": "사람들 눈에 잘 띄지 않는 곳에 서식하며, 길들이기 힘든 드래곤으로 알려져 있다. 탐험을 통해서 얻을 수 없는 스페셜 드래곤.",
  "희미한 바리안": "전설로 전해지는 심해 신전의 여신 레오나의 여섯 수호 드래곤 중 하나 바리안은 여섯 수호자 중 빛을 상징한다. 광명의 빛으로 최선을 다해 여신 레오나를 지킨 수호드래곤이며, 여섯 수호자의 우두머리이다. [ 획득가능: 에스텔라 ]",
  "히드라곤": "머리가 3개인 드래곤.3개의 머리가 각각 다른 이성을 가지고 있다.각각의 머리가 서로 싸우는 일이 많다. [ 획득가능: 희망의 숲 ]",
  "히에나곤": "하이에나의 모습과 흡사하며 등에 네개의 날개가 있다. 강력한 네 발로 빠르고 오래 뛰며 앞 발톱의 힘이 강하다.",
  "운디네": "환상으로 꿈을 갖게 만든다. 현실을 살아갈 목적을 잃은 사람들 앞에 나타난다. 그들의 지친 어깨를 쓰다듬으며, 숨겨져 있는 그들의 꿈을 끄집어낸다. 물결을 닮은 머리칼과 날개로 그들의 꿈이 실현되었을 때의 모습을 보여준다. 운디네의 환상을 체험한 자들은 꿈을 되찾고, 다시 꿈을 향해 나아간다. 운디네는 꿈을 갖고 있는 자 앞에는 나타나지 않기 때문에 고마움을 전하기는 어렵다.",
  "크로마 운디네": "환상으로 꿈을 갖게 만든다. 현실을 살아갈 목적을 잃은 사람들 앞에 나타난다. 그들의 지친 어깨를 쓰다듬으며, 숨겨져 있는 그들의 꿈을 끄집어낸다. 물결을 닮은 머리칼과 날개로 그들의 꿈이 실현되었을 때의 모습을 보여준다. 운디네의 환상을 체험한 자들은 꿈을 되찾고, 다시 꿈을 향해 나아간다. 운디네는 꿈을 갖고 있는 자 앞에는 나타나지 않기 때문에 고마움을 전하기는 어렵다.",
  "세라핌": "세상의 모든 이치를 꿰뚫고 있는 대천사 드래곤이다. 어느 곳에서 무슨 일을 하고 있는지 알 수 없는, 베일에 싸여있는 드래곤이다. 오직 카일룸 네 마리 드래곤을 통해서만 세상과 소통한다. 이는 세상의 모든 이치를 파악했기 때문이다. 알고 싶은 것도, 알아야 하는 것도 없다. 물론 자신에 대해서도 모르는 것이 없다. 자신의 행동이 세상에 어떤 변화를 일으킬지도 잘 알고 있다. 아주 넓은 지역, 먼 미래에 일어날 변화까지 보기 때문에 되도록 세상일에 개입하지 않으려고 한다.",
  "누베스텔라": "소원을 현상화하여 깨달음을 준다. 소원을 가진 자에게 빛을 내뿜는다. 누베스텔라의 찬란한 빛을 맞으면 환상을 보게 된다. 환상 속에서는 소원을 이룬 자신의 모습을 볼 수 있다. 누베스텔라는 소원을 이룬 상대의 모습을 보여줄 뿐, 이루어주지는 않는다.",
};